```cpp
// p: pattern string used to build the failure table.
vector<int> buildFail(const string& p) {
    int m = p.size();
    vector<int> fail(m, 0);  // fail[0] = 0 always
    for (int i = 1; i < m; i++) {
        int j = fail[i - 1];
        while (j > 0 && p[i] != p[j]) {
            j = fail[j - 1];  // Fall back
        }
        if (p[i] == p[j]) {
            j++;
        }
        fail[i] = j;
    }
    return fail;
}
```

建構過程的不變量：`fail[i]` 代表 `p[0..i]` 最長真前後綴長度，每次用 `fail[j-1]` 跳回是因為 `p[0..j-1]` 的最長真前後綴已知。

```cpp
// text: input string.
// pattern: input string.
vector<int> kmpSearch(const string& text, const string& pattern) {
    string s = pattern + '#' + text;  // '#' must not appear in either string
    auto fail = buildFail(s);
    int m = pattern.size();
    vector<int> matches;
    for (int i = m + 1; i < (int)s.size(); i++) {
        if (fail[i] == m) {
            matches.push_back(i - 2 * m);  // Found at text[i-2m]
        }
    }
    return matches;
}
```

**另一種視角**：把 `pattern + '#' + text` 拼接後計算整個字串的 fail 陣列；在 text 部分，凡 `fail[i] == m` 的位置就是一個匹配點。分隔符 `'#'` 保證 fail 值不會跨越兩段。

```cpp
// s: input string.
vector<int> zFunction(const string& s) {
    int n = s.size();
    vector<int> z(n, 0);
    z[0] = n;  // Convention: whole string matches itself
    int l = 0, r = 0;
    for (int i = 1; i < n; i++) {
        if (i < r) {
            z[i] = min(r - i, z[i - l]);  // Use Z-box
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            z[i]++;  // Extend
        }
        if (i + z[i] > r) {
            l = i;
            r = i + z[i];
        }  // Update Z-box
    }
    return z;
}

// Pattern matching: find all positions of pattern in text
// text: input string.
// pattern: input string.
vector<int> zSearch(const string& text, const string& pattern) {
    string s = pattern + '#' + text;
    auto z = zFunction(s);
    int m = pattern.size();
    vector<int> result;
    for (int i = m + 1; i < (int)s.size(); i++) {
        if (z[i] == m) {
            result.push_back(i - m - 1);
        }
    }
    return result;
}
