const long long kMod1 = 1e9 + 7, kMod2 = 1e9 + 9;
const long long kBase1 = 131, kBase2 = 137;

struct StringHash {
    int n;
    vector<long long> h1, h2, pw1, pw2;
    // s: input string.
    StringHash(const string& s)
        : n(s.size()), h1(n + 1, 0), h2(n + 1, 0), pw1(n + 1, 1), pw2(n + 1, 1) {
        for (int i = 0; i < n; i++) {
            h1[i + 1] = (h1[i] * kBase1 + s[i]) % kMod1;
            h2[i + 1] = (h2[i] * kBase2 + s[i]) % kMod2;
            pw1[i + 1] = pw1[i] * kBase1 % kMod1;
            pw2[i + 1] = pw2[i] * kBase2 % kMod2;
        }
    }
    // Get hash of s[l..r] (0-indexed, inclusive)
    // l: left boundary or endpoint.
    // r: right boundary, row, or endpoint.
    pair<long long, long long> get(int l, int r) {
        long long v1 = (h1[r + 1] - h1[l] * pw1[r - l + 1] % kMod1 + kMod1 * 2) % kMod1;
        long long v2 = (h2[r + 1] - h2[l] * pw2[r - l + 1] % kMod2 + kMod2 * 2) % kMod2;
        return {v1, v2};
    }
    // l1: left index of the first interval/string segment.
    // r1: right index of the first interval/string segment.
    // l2: left index of the second interval/string segment.
    // r2: right index of the second interval/string segment.
    bool equal(int l1, int r1, int l2, int r2) {
        return get(l1, r1) == get(l2, r2);
    }
};
```

兩個字串的最長公共前綴（LCP）：二分長度 k，用哈希 O(1) 比較前 k 個字元是否相等。總複雜度 O(log n)。

```cpp
// LCP of s[l1..] and s[l2..] using StringHash
// h: input string.
// l1: left index of the first interval/string segment.
// n1: remaining length of the first string segment.
// l2: left index of the second interval/string segment.
// n2: remaining length of the second string segment.
int lcp(StringHash& h, int l1, int n1, int l2, int n2) {
    int lo = 0, hi = min(n1, n2);
    while (lo < hi) {
        int mid = (lo + hi + 1) / 2;
        if (h.equal(l1, l1 + mid - 1, l2, l2 + mid - 1)) {
            lo = mid;
        }
        else {
            hi = mid - 1;
        }
    }
    return lo;
}
```

