const int kMaxN = 500005;  // Total characters
int trie[kMaxN][26], cnt[kMaxN], tot = 1;

// s: input string.
void insert(const string& s) {
    int cur = 0;
    for (char c : s) {
        int idx = c - 'a';
        if (!trie[cur][idx]) {
            trie[cur][idx] = tot++;
        }
        cur = trie[cur][idx];
        cnt[cur]++;  // Count strings passing through this node
    }
}

// prefix: input string.
int countPrefix(const string& prefix) {
    int cur = 0;
    for (char c : prefix) {
        int idx = c - 'a';
        if (!trie[cur][idx]) {
            return 0;
        }
        cur = trie[cur][idx];
    }
    return cnt[cur];
}
