const int kBits = 30;
int trie01[kMaxN * kBits][2], tot01 = 1;

// x: value or node being processed.
void insert01(int x) {
    int cur = 0;
    for (int i = kBits - 1; i >= 0; i--) {  // High bit first
        int bit = (x >> i) & 1;
        if (!trie01[cur][bit]) {
            trie01[cur][bit] = tot01++;
        }
        cur = trie01[cur][bit];
    }
}

// x: value, node, or output coefficient used by the function.
int maxXor(int x) {
    int cur = 0, result = 0;
    for (int i = kBits - 1; i >= 0; i--) {
        int want = 1 - ((x >> i) & 1);  // Greedy: prefer opposite bit
        if (trie01[cur][want]) {
            result |= (1 << i);
            cur = trie01[cur][want];
        } else {
            cur = trie01[cur][1 - want];
        }
    }
    return result;
}
