```cpp
// s: input string.
vector<int> buildSA(const string& s) {
    int n = s.size();
    vector<int> sa(n), rk(n), tmp(n);
    iota(sa.begin(), sa.end(), 0);
    for (int i = 0; i < n; i++) {
        rk[i] = s[i];  // Initial rank = ASCII value
    }

    for (int gap = 1; gap < n; gap <<= 1) {
        // Sort by (rk[i], rk[i+gap])
        auto cmp = [&rk, gap, n](int a, int b) {
            if (rk[a] != rk[b]) {
                return rk[a] < rk[b];
            }
            int ra = a + gap < n ? rk[a + gap] : -1;
            int rb = b + gap < n ? rk[b + gap] : -1;
            return ra < rb;
        };
        sort(sa.begin(), sa.end(), cmp);
        tmp[sa[0]] = 0;
        for (int i = 1; i < n; i++) {
            tmp[sa[i]] = tmp[sa[i - 1]] + (cmp(sa[i - 1], sa[i]) ? 1 : 0);
        }
        rk = tmp;
        if (rk[sa[n - 1]] == n - 1) {
            break;  // All ranks distinct, done early
        }
    }
    return sa;
}
```

```cpp
// s: input string.
// sa: input or working vector used by the algorithm.
vector<int> buildLCP(const string& s, const vector<int>& sa) {
    int n = s.size();
    vector<int> rank_(n), lcp(n, 0);
    for (int i = 0; i < n; i++) {
        rank_[sa[i]] = i;
    }
    int h = 0;
    for (int i = 0; i < n; i++) {
        if (rank_[i] > 0) {
            int j = sa[rank_[i] - 1];  // Previous suffix in sorted order
            while (i + h < n && j + h < n && s[i + h] == s[j + h]) {
                h++;
            }
            lcp[rank_[i]] = h;
            if (h > 0) {
                h--;  // Key: h decreases by at most 1 each step
            }
        }
    }
    return lcp;
}
```

**Kasai 的關鍵不等式**：若從位置 i 計算得 `lcp = h`，則從位置 i+1 計算的 lcp ≥ h-1。因此 h 的總增量 = O(n)，算法整體 O(n)。

```cpp
// src: source node index (0-based)
// n: number of nodes in the graph
// edges: edge list; each tuple is (u, v, w) for edge u -> v with weight w
// k: maximum number of stops; allows at most k+1 edges
vector<long long> bellmanFordK(int src, int n, const vector<tuple<int, int, int>>& edges, int k) {
    vector<long long> dist(n, LLONG_MAX);
    dist[src] = 0;
    for (int iter = 0; iter <= k; iter++) {
        vector<long long> ndist = dist;  // Use previous round's values
        for (auto [u, v, w] : edges) {
            if (dist[u] != LLONG_MAX) {
                ndist[v] = min(ndist[v], dist[u] + w);
            }
        }
        dist = ndist;
    }
    return dist;
}
```
⚠️ 每輪必須用上一輪的 dist 副本（`ndist = dist`），否則一輪內可能做多跳鬆弛，超過層數限制。

```cpp
// n: number of nodes in the graph
// g: adjacency list; g[u] stores pairs (v, w) for edges u -> v with weight w
bool hasNegativeCycle(int n, const vector<vector<pair<int, int>>>& g) {
    vector<long long> dist(n, 0);
    vector<int> cnt(n, 0);  // Edge count to reach this node
    vector<bool> in_queue(n, true);
    queue<int> q;
    for (int i = 0; i < n; i++) {
        q.push(i);  // Super source: start from all nodes
    }
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        in_queue[u] = false;
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                cnt[v] = cnt[u] + 1;
                if (cnt[v] >= n) {
                    return true;  // Negative cycle found
                }
                if (!in_queue[v]) {
                    q.push(v);
                    in_queue[v] = true;
                }
            }
        }
    }
    return false;
}
