```cpp
const int kMaxN = 100005;
const int kLog = 17;

int up[kMaxN][kLog];
int dep[kMaxN];
vector<int> g[kMaxN];

// v: neighbor node or right endpoint.
// p: parent node or previous node.
// d: current depth or distance value.
void dfs(int v, int p, int d) {
    up[v][0] = p;
    dep[v] = d;
    for (int k = 1; k < kLog; k++) {
        up[v][k] = up[up[v][k - 1]][k - 1];
    }
    for (int to : g[v]) {
        if (to == p) {
            continue;
        }
        dfs(to, v, d + 1);
    }
}

// u: current node or left endpoint.
// v: neighbor node or right endpoint.
int lca(int u, int v) {
    if (dep[u] < dep[v]) {
        swap(u, v);
    }
    int diff = dep[u] - dep[v];
    for (int k = 0; k < kLog; k++) {
        if (diff & (1 << k)) {
            u = up[u][k];
        }
    }
    if (u == v) {
        return u;
    }
    for (int k = kLog - 1; k >= 0; k--) {
        if (up[u][k] != up[v][k]) {
            u = up[u][k];
            v = up[v][k];
        }
    }
    return up[u][0];
}

// Usage:
// int root = 1;
// dfs(root, root, 0);
```
把 `root` 設成自己的父節點哨兵後，根以上的倍增表也會穩定停在根，不會碰到無效索引。查詢時先用深度差拉平，再從大 bit 往小 bit 同步嘗試上跳，最後留下的共同父節點就是答案。

```cpp
const int kMaxN = 100005;
const int kLog = 17;

int up[kMaxN][kLog], dep[kMaxN];
long long dist[kMaxN];
vector<pair<int, int>> g[kMaxN];  // {neighbor, weight}

// v: neighbor node or right endpoint.
// p: parent node or previous node.
void dfsWeighted(int v, int p) {
    up[v][0] = p;
    for (int k = 1; k < kLog; k++) {
        up[v][k] = up[up[v][k - 1]][k - 1];
    }
    for (auto [to, w] : g[v]) {
        if (to == p) {
            continue;
        }
        dep[to] = dep[v] + 1;
        dist[to] = dist[v] + w;
        dfsWeighted(to, v);
    }
}

// u: current node or left endpoint.
// v: neighbor node or right endpoint.
int lca(int u, int v) {
    if (dep[u] < dep[v]) {
        swap(u, v);
    }
    int diff = dep[u] - dep[v];
    for (int k = 0; k < kLog; k++) {
        if (diff & (1 << k)) {
            u = up[u][k];
        }
    }
    if (u == v) {
        return u;
    }
    for (int k = kLog - 1; k >= 0; k--) {
        if (up[u][k] != up[v][k]) {
            u = up[u][k];
            v = up[v][k];
        }
    }
    return up[u][0];
}

// u: current node or left endpoint.
// v: neighbor node or right endpoint.
long long pathDist(int u, int v) {
    int a = lca(u, v);
    return dist[u] + dist[v] - 2LL * dist[a];
}

// Usage:
// int root = 1;
// dep[root] = 0;
// dist[root] = 0;
// dfsWeighted(root, root);
```
`dist[u]` 與 `dist[v]` 都包含從根走到 `lca(u, v)` 的公共前綴，所以那一段會被算兩次；減掉 `2*dist[lca]` 後，留下的正是 `u` 到 `v` 的唯一路徑總權重。

```cpp
const int kMaxN = 100005;
const int kLog = 17;

int up[kMaxN][kLog];
int dep[kMaxN];

// v: neighbor node or right endpoint.
// k: limit, count, or window size used by the algorithm.
int kthAncestor(int v, int k) {
    if (k > dep[v]) {
        return -1;
    }
    for (int i = 0; i < kLog; i++) {
        if (k & (1 << i)) {
            v = up[v][i];
        }
    }
    return v;
}

// Example:
// int grandparent = kthAncestor(v, 2);
```
這個函式直接把 `k` 的每個 set bit 映射成一次 `2^i` 跳躍，因此不需要逐層往上爬。若有 root sentinel 但忘了先檢查 `k > dep[v]`，程式會安靜地停在根，卻回傳一個其實不存在的祖先。

```cpp
const int kMaxN = 100005;
const int kLog = 17;

int up[kMaxN][kLog], dep[kMaxN];
long long dist[kMaxN];

// v: neighbor node or right endpoint.
// k: limit, count, or window size used by the algorithm.
int kthAncestor(int v, int k) {
    if (k > dep[v]) {
        return -1;
    }
    for (int i = 0; i < kLog; i++) {
        if (k & (1 << i)) {
            v = up[v][i];
        }
    }
    return v;
}

// u: current node or left endpoint.
// v: neighbor node or right endpoint.
int lca(int u, int v) {
    if (dep[u] < dep[v]) {
        swap(u, v);
    }
    int diff = dep[u] - dep[v];
    for (int k = 0; k < kLog; k++) {
        if (diff & (1 << k)) {
            u = up[u][k];
        }
    }
    if (u == v) {
        return u;
    }
    for (int k = kLog - 1; k >= 0; k--) {
        if (up[u][k] != up[v][k]) {
            u = up[u][k];
            v = up[v][k];
        }
    }
    return up[u][0];
}

// u: current node or left endpoint.
// v: neighbor node or right endpoint.
int treeDist(int u, int v) {
    int a = lca(u, v);
    return dep[u] + dep[v] - 2 * dep[a];
}

// u: current node or left endpoint.
// v: neighbor node or right endpoint.
long long treeDistW(int u, int v) {
    int a = lca(u, v);
    return dist[u] + dist[v] - 2LL * dist[a];
}

// u: current node or left endpoint.
// v: neighbor node or right endpoint.
// w: edge weight or node weight.
bool onPath(int u, int v, int w) {
    return treeDist(u, w) + treeDist(w, v) == treeDist(u, v);
}

// k is 0-indexed from u toward v.
// u: current node or left endpoint.
// v: neighbor node or right endpoint.
// k: limit, count, or window size used by the algorithm.
int pathNode(int u, int v, int k) {
    int a = lca(u, v);
    int up_len = dep[u] - dep[a];
    int total = dep[u] + dep[v] - 2 * dep[a];
    if (k < 0 || k > total) {
        return -1;
    }
    if (k <= up_len) {
        return kthAncestor(u, k);
    }
    return kthAncestor(v, total - k);
}
```
`treeDist` 算的是邊數，若題目要路徑上的節點數，記得再加 1。`pathNode` 這裡採 **0-indexed**：`k = 0` 代表 `u` 本身；若題目把起點算成第 1 個節點，先做 `--k` 再套公式即可。

```cpp
const int kMaxN = 100005;

int par[kMaxN], color[kMaxN];
vector<int> g[kMaxN];
vector<pair<int, int>> qs[kMaxN];  // {other endpoint, query id}
vector<int> ans;

// x: value or node being processed.
int findSet(int x) {
    if (par[x] == x) {
        return x;
    }
    return par[x] = findSet(par[x]);
}

// v: neighbor node or right endpoint.
// p: parent node or previous node.
void dfs(int v, int p) {
    color[v] = 1;
    par[v] = v;
    for (int u : g[v]) {
        if (u == p) {
            continue;
        }
        dfs(u, v);
        par[findSet(u)] = v;
    }
    for (auto [u, qid] : qs[v]) {
        if (u == v) {
            ans[qid] = v;
        } else if (color[u] == 2) {
            ans[qid] = findSet(u);
        }
    }
    color[v] = 2;
}
```
這份程式的關鍵不是單純「回來就把孩子掛到父親」，而是一定要寫成 `par[findSet(u)] = v`，讓整個孩子子樹的代表元改成目前節點 `v`。之後只要另一端已完成，`findSet` 就會回傳目前最接近答案的共同祖先代表。

```cpp
const int kMaxN = 100005;

int par[kMaxN], color[kMaxN];
vector<int> g[kMaxN];
vector<pair<int, int>> qs[kMaxN];
vector<int> ans;

// x: value or node being processed.
int findSet(int x) {
    if (par[x] == x) {
        return x;
    }
    return par[x] = findSet(par[x]);
}

// v: neighbor node or right endpoint.
// p: parent node or previous node.
void dfs(int v, int p) {
    color[v] = 1;
    par[v] = v;
    for (int u : g[v]) {
        if (u == p) {
            continue;
        }
        dfs(u, v);
        par[findSet(u)] = v;
    }
    for (auto [u, qid] : qs[v]) {
        if (u == v) {
            ans[qid] = v;
        }
        else if (color[u] == 2) {
            ans[qid] = findSet(u);
        }
    }
    color[v] = 2;
}

struct Query {
    int u, v;
};

// root: root node.
// n: number of nodes or elements.
// queries: input or working vector used by the algorithm.
vector<int> solve(int root, int n, const vector<Query>& queries) {
    ans.assign((int)queries.size(), -1);
    for (int i = 1; i <= n; i++) {
        qs[i].clear();
        color[i] = 0;
        par[i] = i;
    }
    for (int i = 0; i < (int)queries.size(); i++) {
        int u = queries[i].u;
        int v = queries[i].v;
        qs[u].push_back({v, i});
        qs[v].push_back({u, i});
    }
    dfs(root, -1);
    return ans;
}

int main() {
    int n = 5;
    g[1] = {2, 3};
    g[2] = {1, 4, 5};
    g[3] = {1};
    g[4] = {2};
    g[5] = {2};

    vector<Query> queries = {{4, 5}, {3, 4}, {2, 2}};
    vector<int> res = solve(1, n, queries);

    for (int x : res) {
        cout << x << '\n';
    }
    return 0;
}
```
批量求解時要先把每個查詢 `(u, v)` 同時登記到 `qs[u]` 與 `qs[v]`，這樣第二個完成的端點才能拿到查詢編號並寫回答案。`u == v` 的自查詢在這裡直接回傳自己，避免被並查集一路合併到更高的祖先。

將長度 n 的陣列分成恰好 k 段（連續子陣列），求各段元素和的最大值之最小值。

```cpp
// Check if array can be split into at most k segments with each sum <= limit
// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
// limit: maximum allowed limit for the window condition.
bool canSplit(const vector<int>& a, int k, long long limit) {
    int segs = 1;
    long long cur = 0;
    for (int x : a) {
        if ((long long)x > limit) {
            return false;  // Single element exceeds limit
        }
        if (cur + x > limit) {
            segs++;
            cur = x;
        } else {
            cur += x;
        }
    }
    return segs <= k;
}

// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
long long minMaxSum(const vector<int>& a, int k) {
    long long lo = *max_element(a.begin(), a.end());     // Lower bound: max single element
    long long hi = accumulate(a.begin(), a.end(), 0LL);  // Upper bound: whole array one segment
    while (lo < hi) {
        long long mid = lo + (hi - lo) / 2;
        if (canSplit(a, k, mid)) {
            hi = mid;  // Feasible: try smaller limit
        }
        else {
            lo = mid + 1;  // Not feasible: need larger limit
        }
    }
    return lo;
}
```

`lo` 初始化為單一元素最大值（限制再小也不可能），`hi` 為全陣列和（只有一段的情形）。`check` 回傳 true 時縮右邊界，最終 `lo == hi` 即為答案。

在數線上 n 個位置中選 k 個放牛，最大化任意兩牛間距離的最小值。

```cpp
// Check if k cows can be placed with minimum pairwise distance >= dist
// pos: current position being constructed.
// k: limit, count, or window size used by the algorithm.
// dist: current distance value or distance table.
bool canPlace(const vector<int>& pos, int k, int dist) {
    int cnt = 1;
    int last = pos[0];  // Place first cow at leftmost position
    for (int i = 1; i < (int)pos.size(); i++) {
        if (pos[i] - last >= dist) {
            cnt++;
            last = pos[i];
        }
        if (cnt >= k) {
            return true;
        }
    }
    return cnt >= k;
}

// pos: current position being constructed.
// k: limit, count, or window size used by the algorithm.
int maxMinDist(vector<int> pos, int k) {
    sort(pos.begin(), pos.end());
    int lo = 1;                         // Minimum possible gap
    int hi = pos.back() - pos.front();  // Maximum possible gap
    while (lo < hi) {
        int mid = lo + (hi - lo + 1) / 2;  // Upper-mid to avoid infinite loop when lo=mid
        if (canPlace(pos, k, mid)) {
            lo = mid;  // Feasible: try larger gap
        }
        else {
            hi = mid - 1;  // Not feasible: reduce gap
        }
    }
    return lo;
}
```

最大化版本二分「答案是否 ≥ x」，`check` 通過時移動 `lo`，此時 `mid` **必須取上中點**（`lo + (hi - lo + 1) / 2`），避免 `lo = mid` 時區間不縮小而卡死。這是最大化與最小化二分唯一的結構差異。

陣列原本嚴格遞增，在某個未知位置旋轉（例如 `[4,5,6,7,0,1,2]`）。在其中搜尋 `target`，無重複元素。

```cpp
// a: input array or sequence.
// target: target value or remaining target to satisfy.
int searchRotated(const vector<int>& a, int target) {
    int lo = 0, hi = (int)a.size() - 1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (a[mid] == target) {
            return mid;
        }
        if (a[lo] <= a[mid]) {  // Left half [lo, mid] is sorted
            if (a[lo] <= target && target < a[mid]) {
                hi = mid - 1;  // Target falls in the sorted left half
            }
            else {
                lo = mid + 1;  // Target must be in the right half
            }
        } else {               // Right half [mid, hi] is sorted
            if (a[mid] < target && target <= a[hi]) {
                lo = mid + 1;  // Target falls in the sorted right half
            }
            else {
                hi = mid - 1;  // Target must be in the left half
            }
        }
    }
    return -1;  // Not found
}
```

判斷左半有序用 `a[lo] <= a[mid]`（含等號以處理 `lo == mid` 的兩元素區間）。確認 target 落在有序那半的閉區間值域後再縮範圍，否則去另一半。若陣列含重複元素，`a[lo] == a[mid]` 時無法判斷，需退化為 `lo++` 線性跳過，最壞 O(n)。

給定相鄰元素皆不相等的陣列（邊界外視為 -∞），找出任意一個峰值元素的下標（峰值：嚴格大於兩側相鄰元素）。

```cpp
// a: input array or sequence.
int findPeak(const vector<int>& a) {
    int lo = 0, hi = (int)a.size() - 1;
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        if (a[mid] < a[mid + 1]) {
            lo = mid + 1;  // Ascending: peak must be to the right of mid
        }
        else {
            hi = mid;  // Descending (a[mid] > a[mid+1]): peak is at mid or to its left
        }
    }
    return lo;  // Invariant guarantees lo == hi is a peak
}
```

**不變式**：`[lo, hi]` 內必有峰值。若 `a[mid] < a[mid+1]`，`mid+1` 比 `mid` 高且 `hi` 外側為 -∞，故 `[mid+1, hi]` 必有峰值，令 `lo = mid + 1`；若 `a[mid] > a[mid+1]`，`a[mid]` 比右側高且 `lo` 外側為 -∞，故 `[lo, mid]` 必有峰值，令 `hi = mid`。注意 `hi = mid`（非 `mid - 1`）——`a[mid]` 本身可能就是峰值，不能丟棄。

函數定義在整數點上，值嚴格單峰，求極大值所在下標。

```cpp
// f(x) is a user-supplied strictly unimodal function on integers
// Returns the x in [lo, hi] that maximizes f(x)
// lo: lower bound of the search range.
// hi: upper bound of the search range.
long long ternarySearchInt(long long lo, long long hi) {
    while (hi - lo > 2) {  // Stop when at most 3 candidates remain
        long long m1 = lo + (hi - lo) / 3;
        long long m2 = hi - (hi - lo) / 3;
        if (f(m1) < f(m2)) {
            lo = m1 + 1;  // Peak cannot be in [lo, m1]: eliminate left third
        }
        else {
            hi = m2 - 1;  // Peak cannot be in [m2, hi]: eliminate right third
        }
    }
    // Brute-force the remaining small interval (at most 3 points)
    long long best = lo;
    for (long long x = lo + 1; x <= hi; x++) {
        if (f(x) > f(best)) {
            best = x;
        }
    }
    return best;
}
```

整數三分以 `hi - lo > 2` 為迴圈條件，剩餘不超過 3 個候選點時直接枚舉，避免邊界複雜性。若求**極小值**（嚴格單谷），只需把 `f(m1) < f(m2)` 改成 `f(m1) > f(m2)`，移動方向相同，語意對調。

函數定義在實數上（如幾何最短距離、物理拋物線問題），求極值的近似位置。

```cpp
// f(x) is a user-supplied strictly unimodal real function
// Returns the approximate x in [lo, hi] that maximizes f(x)
// lo: lower bound of the search range.
// hi: upper bound of the search range.
double ternarySearchReal(double lo, double hi) {
    const int kIter = 200;  // (2/3)^200 ~ 1e-35: far exceeds double precision
    for (int i = 0; i < kIter; i++) {
        double m1 = lo + (hi - lo) / 3.0;
        double m2 = hi - (hi - lo) / 3.0;
        if (f(m1) < f(m2)) {
            lo = m1;  // Peak in [m1, hi]
        }
        else {
            hi = m2;  // Peak in [lo, m2]
        }
    }
    return (lo + hi) / 2.0;  // Midpoint of the converged interval
}
```

實數版不需 `+1`/`-1`，直接用浮點 `m1`、`m2` 更新邊界。迭代 200 次後區間縮小為原來的 `(2/3)^200 ≈ 10^{-35}` 倍，遠超雙精度需求。避免使用 `while (hi - lo > EPS)` — EPS 設太大會提早停止，設太小可能因浮點誤差造成無窮迴圈。

```cpp
// Set mask represented as a bitmask (element i is in mask iff bit i is set)

// Add/remove/query element i
// mask: bitmask representing the current subset/state.
// i: current index.
int addElem(int mask, int i) {
    return mask | (1 << i);
}
// mask: input value used by the function.
// i: input value used by the function.
int delElem(int mask, int i) {
    return mask & ~(1 << i);
}
// mask: input value used by the function.
// i: input value used by the function.
bool hasElem(int mask, int i) {
    return (mask >> i) & 1;
}

// lowbit: isolate the lowest set bit
// mask: input value used by the function.
int lowbit(int mask) {
    return mask & (-mask);
}

// Clear the lowest set bit
// mask: bitmask representing the current subset/state.
int clearLow(int mask) {
    return mask & (mask - 1);
}

// Count set bits (number of elements in the set)
// mask: input value used by the function.
int popcount(int mask) {
    return __builtin_popcount(mask);
}

// Iterate over all set bits in mask
// mask: input value used by the function.
void iterateBits(int mask) {
    for (int t = mask; t; t = clearLow(t)) {
        int bit = lowbit(t);       // Isolated lowest bit
        int i = __builtin_ctz(t);  // Index of lowest set bit
        // Process element i ...
    }
}

// Check if mask is a subset of T
// mask: bitmask representing the current subset/state.
// T: type or threshold parameter used by the routine.
bool isSubset(int mask, int T) {
    return (mask & T) == mask;
}

// Set complement within n bits
// mask: bitmask representing the current subset/state.
// n: number of nodes or elements.
int complement(int mask, int n) {
    return mask ^ ((1 << n) - 1);
}
```

`__builtin_ctz(x)` 返回 x 末尾 0 的個數，即最低位 1 的位置索引，時間 O(1)。`__builtin_popcount` 在大多數現代 CPU 上對應單條 POPCNT 指令。若需要對 64 位整數操作，改用 `__builtin_popcountll` 與 `1LL << i`。

```cpp
// Enumerate all non-empty subsets of mask in O(2^popcount(mask))
// mask: bitmask representing the current subset/state.
void enumSubsets(int mask) {
    for (int t = mask; t; t = (t - 1) & mask) {
        // t is a non-empty subset of mask
        // Process subset t ...
    }
    // Note: empty subset (t=0) is NOT included in the loop
}

// Enumerate all subsets of all masks: O(3^n) total
// For each mask in [0, 2^n), enumerate its subsets
// n: number of nodes or elements.
void enumAllSubsets(int n) {
    int full = 1 << n;
    for (int mask = 0; mask < full; mask++) {
        for (int t = mask; t; t = (t - 1) & mask) {
            // Process (mask, t) where t is a subset of mask
        }
    }
    // Total iterations = sum_{mask} 2^popcount(mask) = 3^n
    // Because each bit is in one of: {in mask but not t, in mask and t, not in mask}
}

// Enumerate all supersets of mask within n-bit universe
// mask: bitmask representing the current subset/state.
// n: number of nodes or elements.
void enumSupersets(int mask, int n) {
    int full = (1 << n) - 1;
    int comp = (~mask) & full;  // Bits NOT in mask
    for (int t = comp;; t = (t - 1) & comp) {
        int superset = mask | t;  // Superset of mask
        // Process superset ...
        if (t == 0) {
            break;
        }
    }
}
```

子集枚舉的時間複雜度分析：對所有掩碼枚舉其子集的總次數 = Σ_{k=0}^{n} C(n,k)·2^k = 3^n（每個位有「在 S 中且在 t 中」、「在 S 中但不在 t 中」、「不在 S 中」三種選擇）。超集枚舉的原理對稱：枚舉 S 的補集的所有子集，加上 S 本身即為超集。

```cpp
// TSP: find shortest Hamiltonian cycle through all n nodes
// dist[i][j] = distance from i to j (directed or undirected)
const long long kInf = 1e18;

// n: number of nodes or elements.
// dist: dynamic programming or distance array.
long long tsp(int n, const vector<vector<long long>>& dist) {
    int full = 1 << n;
    // dp[mask][v] = min cost: visited set = mask, currently at v
    vector<vector<long long>> dp(full, vector<long long>(n, kInf));
    dp[1][0] = 0;  // Start at node 0, visited = {0}

    for (int mask = 1; mask < full; mask++) {
        for (int v = 0; v < n; v++) {
            if (!(mask & (1 << v))) {
                continue;  // v must be in mask
            }
            if (dp[mask][v] == kInf) {
                continue;  // Unreachable state
            }
            // Try moving to each unvisited node u
            for (int u = 0; u < n; u++) {
                if (mask & (1 << u)) {
                    continue;  // u already visited
                }
                int new_mask = mask | (1 << u);
                long long new_cost = dp[mask][v] + dist[v][u];
                dp[new_mask][u] = min(dp[new_mask][u], new_cost);
            }
        }
    }

    // Return to start node 0 from each final node v
    long long ans = kInf;
    for (int v = 1; v < n; v++) {
        if (dp[full - 1][v] < kInf) {
            ans = min(ans, dp[full - 1][v] + dist[v][0]);
        }
    }
    return ans;  // kInf if no Hamiltonian cycle exists
}
```

枚舉所有 `2^n` 個狀態，每個狀態枚舉 n 個當前節點，每個節點再枚舉 n 個下一步，總複雜度 O(2^n × n²)。因為外層迴圈按照 `mask` 的大小遞增（小的 mask 先處理），所以不需要記憶化遞迴，直接迭代即可保證轉移順序正確。

```cpp
// Reconstruct the optimal Hamiltonian cycle path
const long long kInf = 1e18;

// n: number of nodes or elements.
// dist: dynamic programming or distance array.
vector<int> tspPath(int n, const vector<vector<long long>>& dist) {
    int full = 1 << n;
    vector<vector<long long>> dp(full, vector<long long>(n, kInf));
    vector<vector<int>> prev(full, vector<int>(n, -1));  // Predecessor node
    dp[1][0] = 0;

    for (int mask = 1; mask < full; mask++) {
        for (int v = 0; v < n; v++) {
            if (!(mask & (1 << v)) || dp[mask][v] == kInf) {
                continue;
            }
            for (int u = 0; u < n; u++) {
                if (mask & (1 << u)) {
                    continue;
                }
                int nm = mask | (1 << u);
                long long nc = dp[mask][v] + dist[v][u];
                if (nc < dp[nm][u]) {
                    dp[nm][u] = nc;
                    prev[nm][u] = v;  // Record predecessor
                }
            }
        }
    }

    // Find best last node before returning to 0
    int last = -1;
    long long best = kInf;
    for (int v = 1; v < n; v++) {
        long long cost = dp[full - 1][v] + dist[v][0];
        if (cost < best) {
            best = cost;
            last = v;
        }
    }

    // Trace back the path
    vector<int> path;
    int mask = full - 1, cur = last;
    while (cur != -1) {
        path.push_back(cur);
        int p = prev[mask][cur];
        mask ^= (1 << cur);  // Remove cur from mask
        cur = p;
    }
    reverse(path.begin(), path.end());
    path.push_back(0);  // Return to start
    return path;
}
```

路徑重建的關鍵是額外維護 `prev[mask][v]` 記錄每個狀態的前驅節點，反向追蹤時每步移除 `mask` 中的當前節點 `cur`（`mask ^= 1<<cur`），直到 `prev = -1`（回到起點）。空間需求因此增加一個 O(2^n × n) 的整數陣列。

core_idea:
**SOS DP（Sum over Subsets DP）** 計算函式 F[S] = Σ_{T ⊆ S} f[T]（對 S 的所有子集 T 求和）。直接暴力枚舉子集需要 O(3^n) 時間（所有 (S, T) 對的數量）；SOS DP 把它降至 O(2^n × n)。

**思路**：把每個二進位位視為一個「維度」，對每個維度做一次類似前綴和的掃描：
```
for i in 0..n-1:
    for S in 0..2^n-1:
        if S has bit i set:
            dp[S] += dp[S ^ (1<<i)]  // Add contribution from S without bit i
```

最終 `dp[S]` = Σ_{T ⊆ S} f[T]。直覺上，每個維度的掃描把「差一個位的兩個集合」合併，n 輪後所有子集都被合入了 F[S]。

**對稱版本**（Super-set Sum）：`dp[S]` = Σ_{T ⊇ S} f[T]，只需把條件改為「S 的第 i 位為 0 時，`dp[S] += dp[S | (1<<i)]`」即可，邏輯完全對稱。

deep_dive.body:
```cpp
// SOS DP: compute F[mask] = sum of f[T] for all T subset of mask
// f[] is given; dp[] is computed in-place (initialized to f[])
// dp: dynamic programming or distance array.
// n: number of nodes or elements.
void sosDp(vector<long long>& dp, int n) {
    // dp is initialized with f[] before calling
    for (int i = 0; i < n; i++) {  // Iterate over each bit dimension
        for (int mask = 0; mask < (1 << n); mask++) {
            if (mask & (1 << i)) {                // Only process masks with bit i set
                dp[mask] += dp[mask ^ (1 << i)];  // Add contribution from mask without bit i
            }
        }
    }
    // Now dp[mask] = sum of f[T] for all T subset of mask
}

// Superset sum variant: F[mask] = sum of f[T] for all T superset of mask
// dp: input or working vector used by the algorithm.
// n: number of nodes or elements.
void sosDpSuper(vector<long long>& dp, int n) {
    for (int i = 0; i < n; i++) {
        for (int mask = 0; mask < (1 << n); mask++) {
            if (!(mask & (1 << i))) {             // Only process masks with bit i clear
                dp[mask] += dp[mask | (1 << i)];  // Add contribution from mask with bit i
            }
        }
    }
    // Now dp[mask] = sum of f[T] for all T superset of mask
}
```

**正確性**（對 subset sum 版本）：記 `dp_i[S]` 為經過前 i 輪後的值。歸納可得：`dp_i[S]` = Σ_{T: T 與 S 在位 i..n-1 上相同，T 在位 0..i-1 上 ≤ S} f[T]。當 i = n 時，T 可以在所有位上 ≤ S（按位），即 T ⊆ S，因此 `dp_n[S]` = F[S]。

```cpp
// Application 1: For each mask, find max value among all subsets of mask
// f[i] = value at singleton {i}; ans[mask] = max f[T] for T subset mask
// dp: dynamic programming or distance array.
// n: number of nodes or elements.
void maxSubsetSOS(vector<int>& dp, int n) {
    for (int i = 0; i < n; i++) {
        for (int mask = 0; mask < (1 << n); mask++) {
            if (mask & (1 << i)) {
                dp[mask] = max(dp[mask], dp[mask ^ (1 << i)]);  // Max instead of sum
            }
        }
    }
}

// Application 2: Count pairs (A, B) with A AND B = 0 (A, B subset of universe)
// Step 1: cnt[mask] = number of given sets equal to mask
// Step 2: SOS to get sub[mask] = number of given sets that are subsets of mask
// Step 3: For each A, B with A AND B = 0 means B is subset of complement(A)
//         ans = sum over all A of cnt[A] * sub[complement(A)]
// sets: input or working vector used by the algorithm.
// n: number of nodes or elements.
long long countDisjointPairs(const vector<int>& sets, int n) {
    int full = 1 << n;
    vector<long long> sub(full, 0);
    for (int s : sets) {
        sub[s]++;  // Initialize with counts
    }
    // SOS: sub[mask] = number of input sets that are subsets of mask
    for (int i = 0; i < n; i++) {
        for (int mask = 0; mask < full; mask++) {
            if (mask & (1 << i)) {
                sub[mask] += sub[mask ^ (1 << i)];
            }
        }
    }
    long long ans = 0;
    for (int s : sets) {
        ans += sub[(full - 1) ^ s];  // Complement of s
    }
    return ans;
}
```

SOS DP 的聚合操作不限於加法，也可以是取最大值、按位 OR 等滿足分配律的操作。「計算 AND 為 0 的配對數」是經典應用：利用 SOS DP 求每個集合 S 的子集計數，再對每個集合 A 查詢其補集的子集計數（補集的所有子集都與 A AND 為 0），O(2^n × n + m) 總複雜度。

```cpp
struct Point {
    long long x, y;
};
Point operator-(Point a, Point b) {
    return {a.x - b.x, a.y - b.y};
}
bool operator==(Point a, Point b) {
    return a.x == b.x && a.y == b.y;
}
// a: first point/vector.
// b: second point/vector.
long long cross(Point a, Point b) {
    return a.x * b.y - a.y * b.x;
}  // z of a x b
// a: numeric input value.
// b: second numeric input value.
long long dot(Point a, Point b) {
    return a.x * b.x + a.y * b.y;
}
// v: neighbor node or right endpoint.
int sgn(long long v) {
    return (v > 0) - (v < 0);
}

// Orientation of c relative to directed line a->b
// >0 left (CCW), 0 collinear, <0 right (CW)
// a: input array or sequence.
// b: second numeric input value.
// c: candidate character or capacity value.
long long ccw(Point a, Point b, Point c) {
    return cross(b - a, c - a);
}
```

`ccw` 回傳的是 `cross(b - a, c - a)`，等於三角形 `a, b, c` 有號面積的兩倍。只取**符號**即可判斷轉向，這是大多數幾何演算法唯一需要的資訊——不需要真的算出角度或長度。

```cpp
// Twice the SIGNED area of polygon p[0..n-1].
// Positive if vertices are in CCW order, negative if CW.
// p: polygon vertices in order.
long long area2(const vector<Point>& p) {
    long long s = 0;
    int n = p.size();
    for (int i = 0; i < n; i++) {
        Point a = p[i], b = p[(i + 1) % n];
        s += cross(a, b);  // a.x*b.y - a.y*b.x
    }
    return s;  // real area = abs(s) / 2.0
}
```

鞋帶公式把多邊形拆成一堆以原點為頂點的三角形，用叉積累加有號面積，重疊部分自動正負相消。回傳值是面積的**兩倍**且**有號**：保持整數運算到最後，需要實際面積時才除以 2。符號還能順帶判斷頂點順序是順時針還是逆時針。

```cpp
struct Point {
    long long x, y;
};
Point operator-(Point a, Point b) {
    return {a.x - b.x, a.y - b.y};
}
bool operator==(Point a, Point b) {
    return a.x == b.x && a.y == b.y;
}
// a: first point/vector.
// b: second point/vector.
long long cross(Point a, Point b) {
    return a.x * b.y - a.y * b.x;
}  // z of a x b
// a: numeric input value.
// b: second numeric input value.
long long dot(Point a, Point b) {
    return a.x * b.x + a.y * b.y;
}
// v: neighbor node or right endpoint.
int sgn(long long v) {
    return (v > 0) - (v < 0);
}

// Returns hull vertices in CCW order. Uses <= 0 to DROP collinear
// points on edges; use < 0 to KEEP them.
// p: points used to build the convex hull.
vector<Point> convexHull(vector<Point> p) {
    sort(p.begin(), p.end(), [](Point a, Point b) { return a.x != b.x ? a.x < b.x : a.y < b.y; });
    p.erase(unique(p.begin(), p.end()), p.end());
    int n = p.size(), k = 0;
    if (n < 3) {
        return p;
    }
    vector<Point> h(2 * n);
    for (int i = 0; i < n; i++) {  // lower hull
        while (k >= 2 && cross(h[k - 1] - h[k - 2], p[i] - h[k - 2]) <= 0) {
            k--;
        }
        h[k++] = p[i];
    }
    for (int i = n - 2, t = k + 1; i >= 0; i--) {  // upper hull
        while (k >= t && cross(h[k - 1] - h[k - 2], p[i] - h[k - 2]) <= 0) {
            k--;
        }
        h[k++] = p[i];
    }
    h.resize(k - 1);  // last point == first, drop it
    return h;
}
```

`t = k + 1` 確保建上凸包時不會把下凸包的起點彈掉。最後一個點與第一個點重合，故 `resize(k - 1)`。

```cpp
struct Point {
    long long x, y;
};
Point operator-(Point a, Point b) {
    return {a.x - b.x, a.y - b.y};
}
bool operator==(Point a, Point b) {
    return a.x == b.x && a.y == b.y;
}
// a: first point/vector.
// b: second point/vector.
long long cross(Point a, Point b) {
    return a.x * b.y - a.y * b.x;
}  // z of a x b
// a: numeric input value.
// b: second numeric input value.
long long dot(Point a, Point b) {
    return a.x * b.x + a.y * b.y;
}
// v: neighbor node or right endpoint.
int sgn(long long v) {
    return (v > 0) - (v < 0);
}

// Is q on segment a-b, assuming a, b, q are collinear?
// a: input array or sequence.
// b: second numeric input value.
// q: query list or queue-related parameter.
bool onSegment(Point a, Point b, Point q) {
    return min(a.x, b.x) <= q.x && q.x <= max(a.x, b.x) && min(a.y, b.y) <= q.y &&
           q.y <= max(a.y, b.y);
}

// Do segments a-b and c-d intersect (touching counts)?
// a: input array or sequence.
// b: second numeric input value.
// c: first endpoint of the second segment.
// d: second endpoint of the second segment.
bool segInter(Point a, Point b, Point c, Point d) {
    long long d1 = cross(b - a, c - a), d2 = cross(b - a, d - a);
    long long d3 = cross(d - c, a - c), d4 = cross(d - c, b - c);
    if (sgn(d1) * sgn(d2) < 0 && sgn(d3) * sgn(d4) < 0) {
        return true;  // proper
    }
    if (d1 == 0 && onSegment(a, b, c)) {
        return true;  // collinear endpoint cases
    }
    if (d2 == 0 && onSegment(a, b, d)) {
        return true;
    }
    if (d3 == 0 && onSegment(c, d, a)) {
        return true;
    }
    if (d4 == 0 && onSegment(c, d, b)) {
        return true;
    }
    return false;
}
```

`sgn(d1)*sgn(d2) < 0` 表示 c、d 嚴格落在直線 ab 兩側；兩對都異側即**規範相交**。其餘四個 `== 0` 分支處理端點剛好落在另一線段上的接觸情形。

```cpp
// Returns 1 = strictly inside, 0 = outside, -1 = on boundary.
// q: query list or queue-related parameter.
// poly: input or working vector used by the algorithm.
int pointInPoly(Point q, const vector<Point>& poly) {
    int n = poly.size(), cnt = 0;
    for (int i = 0; i < n; i++) {
        Point a = poly[i], b = poly[(i + 1) % n];
        if (cross(b - a, q - a) == 0 && onSegment(a, b, q)) {
            return -1;                     // on edge
        }
        if ((a.y > q.y) != (b.y > q.y)) {  // edge straddles ray's height
            Point lo = a, hi = b;
            if (lo.y > hi.y) {
                swap(lo, hi);
            }
            if (cross(hi - lo, q - lo) > 0) {
                cnt++;  // q strictly left of upward edge
            }
        }
    }
    return cnt & 1;
}
```

用半開區間條件 `(a.y > q.y) != (b.y > q.y)` 避免在頂點處重複計數；再用「q 是否在**向上**有向邊左側」（叉積 `> 0`）取代浮點交點比較，整數精確判斷射線是否與這條邊相交。

```cpp
struct Point {
    long long x, y;
};
Point operator-(Point a, Point b) {
    return {a.x - b.x, a.y - b.y};
}
bool operator==(Point a, Point b) {
    return a.x == b.x && a.y == b.y;
}
// a: first point/vector.
// b: second point/vector.
long long cross(Point a, Point b) {
    return a.x * b.y - a.y * b.x;
}  // z of a x b
// a: numeric input value.
// b: second numeric input value.
long long dot(Point a, Point b) {
    return a.x * b.x + a.y * b.y;
}
// v: neighbor node or right endpoint.
int sgn(long long v) {
    return (v > 0) - (v < 0);
}

// a: numeric input value.
// b: second numeric input value.
long long dist2(Point a, Point b) {
    long long dx = a.x - b.x, dy = a.y - b.y;
    return dx * dx + dy * dy;
}

// Sort by x first, then call rec(0, n). a[] gets reordered by y in-place.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
// a: input array or sequence.
long long rec(int l, int r, vector<Point>& a) {
    if (r - l <= 3) {  // base case: brute force + sort by y
        long long best = LLONG_MAX;
        for (int i = l; i < r; i++) {
            for (int j = i + 1; j < r; j++) {
                best = min(best, dist2(a[i], a[j]));
            }
        }
        sort(a.begin() + l, a.begin() + r, [](Point p, Point q) { return p.y < q.y; });
        return best;
    }
    int m = (l + r) / 2;
    long long midx = a[m].x;
    long long d = min(rec(l, m, a), rec(m, r, a));
    inplace_merge(a.begin() + l, a.begin() + m, a.begin() + r,
                  [](Point p, Point q) { return p.y < q.y; });  // now [l, r) sorted by y
    vector<Point> strip;
    for (int i = l; i < r; i++) {
        if ((a[i].x - midx) * (a[i].x - midx) < d) {
            strip.push_back(a[i]);
        }
    }
    for (int i = 0; i < (int)strip.size(); i++) {
        for (int j = i + 1;
             j < (int)strip.size() && (strip[j].y - strip[i].y) * (strip[j].y - strip[i].y) < d;
             j++) {
            d = min(d, dist2(strip[i], strip[j]));
        }
    return d;
}
```

用 `inplace_merge` 在回溯時順手把區間依 y 合併好，避免每層重新排序，維持 O(n log n)。內層 j 迴圈一旦 y 差距平方 `>= d` 就 break，這是「每點只比常數個」的關鍵。

```cpp
// Sweep by x, keep a window of points whose x is within best distance.
// Store active points in a set ordered by (y, x); query the y-band [y-d, y+d].
// pts: input or working vector used by the algorithm.
long long closestPairSweep(vector<Point> pts) {
    sort(pts.begin(), pts.end(), [](Point a, Point b) { return a.x < b.x; });
    long long best = LLONG_MAX;
    set<pair<long long, long long>> active;  // (y, x)
    int j = 0;
    for (int i = 0; i < (int)pts.size(); i++) {
        while (j < i && (pts[i].x - pts[j].x) * (pts[i].x - pts[j].x) >= best) {
            active.erase({pts[j].y, pts[j].x});
            j++;
        }
        long long d = (long long)ceil(sqrt((double)best)) + 1;
        auto lo = active.lower_bound({pts[i].y - d, LLONG_MIN});
        auto hi = active.upper_bound({pts[i].y + d, LLONG_MAX});
        for (auto it = lo; it != hi; ++it) {
            best = min(best, dist2(Point{it->second, it->first}, pts[i]));
        }
        active.insert({pts[i].y, pts[i].x});
    }
    return best;
}
```

掃描線版好寫好記：用 `set` 維護 x 在當前最近距離內的「活躍點」，每個新點只查 y 介於 `[y-d, y+d]` 的少數點。實作較短，常被用來替代分治。

```cpp
// Patience sorting: maintain tails[] for O(n log n) LIS
// tails[i] = smallest tail element of all IS of length i+1
// a: input array or sequence.
int lisLength(vector<int>& a) {
    vector<int> tails;
    for (int x : a) {
        // Find first tail >= x (strict: use lower_bound)
        auto it = lower_bound(tails.begin(), tails.end(), x);
        if (it == tails.end()) {
            tails.push_back(x);  // Extend
        }
        else {
            *it = x;  // Replace to keep tails minimal
        }
    }
    return (int)tails.size();
}
```
`tails` 陣列始終保持嚴格遞增，長度即為 LIS 長度。`lower_bound` 找到第一個 `>= x` 的位置並替換，使尾端盡可能小，為後續元素留出更多延伸空間。若要求**非遞減**（允許相等）子序列，將 `lower_bound` 改為 `upper_bound` 即可。

```cpp
// LCS: O(nm), space-optimised to O(m) with rolling array
// a: input array or sequence.
// b: input string.
int lcs(const string& a, const string& b) {
    int n = a.size(), m = b.size();
    vector<int> prev(m + 1, 0), cur(m + 1, 0);
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            cur[j] = (a[i - 1] == b[j - 1]) ? prev[j - 1] + 1 : max(prev[j], cur[j - 1]);
        }
        swap(prev, cur);
        fill(cur.begin(), cur.end(), 0);
    }
    return prev[m];
}

// Maximum subarray sum: Kadane's algorithm O(n)
// a: input array or sequence.
long long maxSubarray(vector<int>& a) {
    long long ans = a[0], cur = a[0];
    for (int i = 1; i < (int)a.size(); i++) {
        cur = max((long long)a[i], cur + a[i]);  // Restart if prefix is negative
        ans = max(ans, cur);
    }
    return ans;
}
```
LCS 轉移：若 `a[i-1]==b[j-1]` 則延伸公共序列；否則從「捨棄 a 的第 i 字元」或「捨棄 b 的第 j 字元」取較大值。滾動陣列（只保留前一行）可將空間從 O(nm) 降至 O(m)。Kadane 算法每步只問：「繼續延伸前綴」還是「放棄重新開始」哪個更大，一遍線性掃描即可。

範例：最長遞增子序列（LIS）以 `dp[i]` = 以 a[i] 結尾的最長長度。

```cpp
int lengthOfLIS(vector<int>& a){
    vector<int> tails;                  // tails[k]=長度 k+1 的最小結尾
    for(int x : a){
        auto it=lower_bound(tails.begin(),tails.end(),x);
        if(it==tails.end()) tails.push_back(x);
        else *it=x;
    }
    return tails.size();
}
```

計數型（合法子序列數）通常維護「以每個值/狀態結尾的方案數」並用前綴和加總；不相交區間選取則按右端排序後 `dp` 轉移自最後一個不重疊區間。

以「除自身以外陣列的乘積」為例：每位答案 = 左前綴積 × 右後綴積。

```cpp
vector<int> productExceptSelf(vector<int>& a){
    int n=a.size(); vector<int> res(n,1);
    for(int i=1;i<n;i++) res[i]=res[i-1]*a[i-1];   // 左前綴積
    int suf=1;
    for(int i=n-1;i>=0;i--){ res[i]*=suf; suf*=a[i]; } // 右後綴積即時合併
    return res;
}
```

「買賣股票（先買後賣的最大利潤）」也是此型：`pre[i]` 維護左側最小價、`suf[i]` 維護右側最大價，枚舉分割點。

```cpp
// 0/1 Knapsack: each item used at most once
// Iterate capacity in reverse to prevent reuse
// cap: capacity limit.
// w: weights or node values.
// v: neighbor node or right endpoint.
int knapsack01(int cap, vector<int>& w, vector<int>& v) {
    int n = w.size();
    vector<int> dp(cap + 1, 0);
    for (int i = 0; i < n; i++) {
        for (int j = cap; j >= w[i]; j--) {  // Reverse: no reuse
            dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
        }
    }
    return dp[cap];
}

// Unbounded Knapsack: each item used unlimited times
// Iterate capacity forward to allow reuse
// cap: capacity limit.
// w: weights or node values.
// v: neighbor node or right endpoint.
int knapsackUnbounded(int cap, vector<int>& w, vector<int>& v) {
    int n = w.size();
    vector<int> dp(cap + 1, 0);
    for (int i = 0; i < n; i++) {
        for (int j = w[i]; j <= cap; j++) {  // Forward: allow reuse
            dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
        }
    }
    return dp[cap];
}
```
兩者唯一差異是內層迴圈方向：**逆序**保證每件物品至多選一次（更新時 `dp[j-w[i]]` 尚未包含第 i 件）；**正序**允許重複選（`dp[j-w[i]]` 已更新過，代表已可能再選一次第 i 件）。記憶口訣：0/1 逆，完全正。

```cpp
// Multiple Knapsack via binary grouping
// Each item i: weight w[i], value v[i], count c[i]
// cap: capacity limit.
// w: weights or node values.
// v: neighbor node or right endpoint.
// c: candidate character or capacity value.
int knapsackMultiple(int cap, vector<int>& w, vector<int>& v, vector<int>& c) {
    // Decompose each item into groups of sizes 1, 2, 4, ..., remainder
    vector<int> gw, gv;
    for (int i = 0; i < (int)w.size(); i++) {
        int rem = c[i];
        for (int k = 1; rem > 0; k <<= 1) {
            int take = min(k, rem);
            gw.push_back(take * w[i]);
            gv.push_back(take * v[i]);
            rem -= take;
        }
    }
    // Standard 0/1 knapsack on grouped items
    vector<int> dp(cap + 1, 0);
    for (int i = 0; i < (int)gw.size(); i++) {
        for (int j = cap; j >= gw[i]; j--) {
            dp[j] = max(dp[j], dp[j - gw[i]] + gv[i]);
        }
    }
    return dp[cap];
}
```
二進位分組的正確性：任意 `0 <= x <= c` 都能以 `{1, 2, 4, …, 2^k, r}` 的子集之和表示，因此不會遺漏任何合法選取數量，同時組數從 O(C) 壓縮到 O(log C)，顯著減少虛擬物品總數。

```cpp
// Stone merging: n piles in a row, minimize total merge cost
// Cost of any merge equals the total weight of the merged piles
// stones: input or working vector used by the algorithm.
int stoneMerge(vector<int>& stones) {
    int n = stones.size();
    vector<int> pre(n + 1, 0);  // Prefix sum
    for (int i = 0; i < n; i++) {
        pre[i + 1] = pre[i] + stones[i];
    }

    // dp[l][r] = min cost to merge stones[l..r] into one pile
    vector<vector<int>> dp(n, vector<int>(n, 0));
    for (int len = 2; len <= n; len++) {
        for (int l = 0; l + len - 1 < n; l++) {
            int r = l + len - 1;
            dp[l][r] = INT_MAX;
            int cost = pre[r + 1] - pre[l];  // Total weight of [l..r]
            for (int k = l; k < r; k++) {  // Split: left=[l, k], right=[k+1, r]
                dp[l][r] = min(dp[l][r], dp[l][k] + dp[k + 1][r] + cost);
            }
        }
    }
    return dp[0][n - 1];
}
```
`dp[i][i] = 0`（單堆不需合併），作為長度 1 的邊界。合併代價始終為 `sum(l..r)`，用前綴和 O(1) 查詢。注意內層迴圈 `k` 的範圍是 `[l, r-1]`，k 是左半部分的右端點，確保兩個子問題 `[l,k]` 和 `[k+1,r]` 均非空。

```cpp
// Matrix chain: minimize scalar multiplications
// dims[i] x dims[i+1] is the size of matrix i (0-indexed)
// dims: input or working vector used by the algorithm.
long long matrixChain(vector<int>& dims) {
    int n = dims.size() - 1;  // Number of matrices
    vector<vector<long long>> dp(n, vector<long long>(n, 0));
    for (int len = 2; len <= n; len++) {
        for (int l = 0; l + len - 1 < n; l++) {
            int r = l + len - 1;
            dp[l][r] = LLONG_MAX;
            for (int k = l; k < r; k++) {
                // Cost of multiplying [l..k] x [k+1..r]
                long long cost = (long long)dims[l] * dims[k + 1] * dims[r + 1];
                dp[l][r] = min(dp[l][r], dp[l][k] + dp[k + 1][r] + cost);
            }
        }
    }
    return dp[0][n - 1];
}
```
矩陣 i 大小為 `dims[i] × dims[i+1]`，合併 `[l,k]` 結果矩陣（`dims[l] × dims[k+1]`）與 `[k+1,r]` 結果矩陣（`dims[k+1] × dims[r+1]`）的代價是 `dims[l] × dims[k+1] × dims[r+1]`。分割點 k 代表最後一次矩陣乘法在哪裡切，窮舉 k 找到最小純量乘法次數。

```cpp
// Number triangle: min cost path from top to bottom row
// Move from (r, c) to (r+1, c) or (r+1, c+1)
vector<vector<int>> tri;
vector<vector<int>> memo;

// r: right boundary, row, or endpoint.
// c: candidate character or capacity value.
int minPath(int r, int c) {
    if (r == (int)tri.size() - 1) {
        return tri[r][c];  // Base case: last row
    }
    if (memo[r][c] != -1) {
        return memo[r][c];  // Cache hit
    }
    int down = minPath(r + 1, c);
    int down_right = minPath(r + 1, c + 1);
    return memo[r][c] = tri[r][c] + min(down, down_right);
}

// n: number of nodes or elements.
int solve(int n) {
    memo.assign(n, vector<int>(n, -1));
    return minPath(0, 0);
}
```
`memo[r][c]` 同時擔任「是否已計算」與「快取結果」兩個角色，以 `-1` 為哨兵（此題答案恆為正整數）。每個 `(r, c)` 狀態至多計算一次，總呼叫次數等於三角形節點數 O(n²)。

```cpp
// Fibonacci-style memoization with unordered_map for sparse states
unordered_map<long long, long long> memo;

// Example: count distinct ways to tile a 2xN board
// n: number of nodes or elements.
long long tile(int n) {
    if (n <= 0) {
        return 1;  // Empty board: 1 way
    }
    if (n == 1) {
        return 1;
    }
    auto it = memo.find(n);
    if (it != memo.end()) {
        return it->second;  // Cache hit
    }
    // Place vertical tile or two horizontal tiles
    return memo[n] = tile(n - 1) + tile(n - 2);
}

// 2D sparse: encode state as single key
// a: input array or sequence.
// b: second numeric input value.
long long dp2d(int a, int b) {
    if (a == 0 || b == 0) {
        return 1;
    }
    long long key = (long long)a * 100001 + b;  // Pack two dims
    auto it = memo.find(key);
    if (it != memo.end()) {
        return it->second;
    }
    return memo[key] = dp2d(a - 1, b) + dp2d(a, b - 1);
}
```
當狀態可以用整數或字串表示但難以直接當陣列索引時（如座標範圍極大、狀態為分數或字串），用 `unordered_map` 作 memo 可省去手動映射的麻煩，但存取常數比陣列大，大量狀態時注意雜湊碰撞與記憶體用量。

下面把最常見的遞迴版與不會吃 stack 的迭代版放在一起比較：

```cpp
struct DsuFindDemo {
    vector<int> par;

    // n: number of nodes or elements.
    explicit DsuFindDemo(int n) : par(n + 1) {
        iota(par.begin(), par.end(), 0);
    }

    // x: value or node being processed.
    int findRec(int x) {
        if (par[x] == x) {
            return x;
        }
        return par[x] = findRec(par[x]);
    }

    // x: value, node, or output coefficient used by the function.
    int findIter(int x) {
        int root = x;
        while (par[root] != root) {
            root = par[root];
        }
        while (par[x] != x) {
            int parent = par[x];
            par[x] = root;
            x = parent;
        }
        return root;
    }
};
```

遞迴版最精簡，`return par[x] = findRec(par[x]);` 直接在回傳路上完成壓縮；但若一開始樹非常深，仍有 stack overflow 風險。迭代版採兩段式：先一路找到根，再回頭把整條路徑改指向根，因此不依賴遞迴深度，在資料範圍很大時更穩定。

`rank` 與 `size` 都是在合併時避免樹退化，只是記錄的資訊不同：

```cpp
struct DsuRank {
    vector<int> par, rnk;

    // n: number of nodes or elements.
    explicit DsuRank(int n) : par(n + 1), rnk(n + 1, 0) {
        iota(par.begin(), par.end(), 0);
    }

    // x: value or node being processed.
    int findRoot(int x) {
        if (par[x] == x) {
            return x;
        }
        return par[x] = findRoot(par[x]);
    }

    // a: input array or sequence.
    // b: second numeric input value.
    bool unite(int a, int b) {
        a = findRoot(a);
        b = findRoot(b);
        if (a == b) {
            return false;
        }
        if (rnk[a] < rnk[b]) {
            swap(a, b);
        }
        par[b] = a;
        if (rnk[a] == rnk[b]) {
            rnk[a]++;
        }
        return true;
    }
};

struct DsuSize {
    vector<int> par, sz;

    // n: number of nodes or elements.
    explicit DsuSize(int n) : par(n + 1), sz(n + 1, 1) {
        iota(par.begin(), par.end(), 0);
    }

    // x: value or node being processed.
    int findRoot(int x) {
        if (par[x] == x) {
            return x;
        }
        return par[x] = findRoot(par[x]);
    }

    // a: input array or sequence.
    // b: second numeric input value.
    bool unite(int a, int b) {
        a = findRoot(a);
        b = findRoot(b);
        if (a == b) {
            return false;
        }
        if (sz[a] < sz[b]) {
            swap(a, b);
        }
        par[b] = a;
        sz[a] += sz[b];
        return true;
    }
};
```

按秩合併裡的 `rnk` 是高度上界，所以只有兩棵同 `rank` 的樹合併時才會增加一層；按大小合併則直接保證小集合掛到大集合下。兩種策略都能把樹高壓在對數級，再配合路徑壓縮，就會得到幾乎常數的攤還效率。

差值型最常見，適合處理「兩點差多少」的等式關係：

```cpp
struct AdditiveWeightedDsu {
    vector<int> par, sz;
    vector<long long> d;  // val[x] - val[parent[x]]

    AdditiveWeightedDsu() = default;
    // n: number of nodes or elements.
    explicit AdditiveWeightedDsu(int n) {
        init(n);
    }

    // n: number of nodes or elements.
    void init(int n) {
        par.resize(n + 1);
        iota(par.begin(), par.end(), 0);
        sz.assign(n + 1, 1);
        d.assign(n + 1, 0);
    }

    // x: value or node being processed.
    int findRoot(int x) {
        if (par[x] == x) {
            return x;
        }
        int p = par[x];
        int root = findRoot(p);
        d[x] += d[p];
        return par[x] = root;
    }

    // x: value or node being processed.
    // y: y-coordinate or output coefficient.
    // w: edge weight or node weight.
    bool unite(int x, int y, long long w) {  // val[x] - val[y] = w
        int rx = findRoot(x);
        int ry = findRoot(y);
        long long dx = d[x];
        long long dy = d[y];
        if (rx == ry) {
            return dx - dy == w;
        }

        if (sz[rx] < sz[ry]) {
            par[rx] = ry;
            d[rx] = w + dy - dx;  // val[rx] - val[ry]
            sz[ry] += sz[rx];
        } else {
            par[ry] = rx;
            d[ry] = dx - dy - w;  // val[ry] - val[rx]
            sz[rx] += sz[ry];
        }
        return true;
    }

    // x: value or node being processed.
    // y: y-coordinate or output coefficient.
    long long query(int x, int y) {
        if (findRoot(x) != findRoot(y)) {
            return LLONG_MIN;
        }
        return d[x] - d[y];
    }
};
```

這裡最容易錯的是讀值時機：一定要先做 `find(x)`、`find(y)`，再讀 `d[x]`、`d[y]`，因為壓縮後它們才是相對根的差值。若兩點本來就在同一集合，`unite` 也不能直接略過，而要檢查 `dx - dy` 是否真的等於新約束 `w`。

若題目關係是比例而不是差值，就把路徑合成從加法改成乘法：

```cpp
struct MultiplicativeWeightedDsu {
    static constexpr double kEps = 1e-9;
    vector<int> par, sz;
    vector<double> dm;  // val[x] / val[parent[x]]

    MultiplicativeWeightedDsu() = default;
    // n: number of nodes or elements.
    explicit MultiplicativeWeightedDsu(int n) {
        init(n);
    }

    // n: number of nodes or elements.
    void init(int n) {
        par.resize(n + 1);
        iota(par.begin(), par.end(), 0);
        sz.assign(n + 1, 1);
        dm.assign(n + 1, 1.0);
    }

    // x: value or node being processed.
    int findM(int x) {
        if (par[x] == x) {
            return x;
        }
        int p = par[x];
        int root = findM(p);
        dm[x] *= dm[p];
        return par[x] = root;
    }

    // x: value or node being processed.
    // y: y-coordinate or output coefficient.
    // r: right boundary, row, or endpoint.
    bool uniteM(int x, int y, double r) {  // val[x] / val[y] = r
        int rx = findM(x);
        int ry = findM(y);
        double dx = dm[x];
        double dy = dm[y];
        if (rx == ry) {
            if (fabs(dy) <= kEps) {
                return false;
            }
            return fabs(dx / dy - r) <= kEps;
        }
        if (fabs(dx) <= kEps || fabs(dy) <= kEps || fabs(r) <= kEps) {
            return false;
        }

        if (sz[rx] < sz[ry]) {
            par[rx] = ry;
            dm[rx] = r * dy / dx;  // val[rx] / val[ry]
            sz[ry] += sz[rx];
        } else {
            par[ry] = rx;
            dm[ry] = dx / (dy * r);  // val[ry] / val[rx]
            sz[rx] += sz[ry];
        }
        return true;
    }

    // x: value or node being processed.
    // y: y-coordinate or output coefficient.
    double queryM(int x, int y) {
        int rx = findM(x);
        int ry = findM(y);
        if (rx != ry || fabs(dm[y]) <= kEps) {
            return numeric_limits<double>::quiet_NaN();
        }
        return dm[x] / dm[y];
    }
};
```

乘法型的 `findM` 是把整條路徑上的比例一路相乘，因此 `dm[x]` 最後會變成 `x` 相對根的比值。因為使用浮點數，檢查同集合約束時要搭配 `EPS`；另外公式裡有除法，若題目可能出現 0 或極小值，也必須先做防呆。

食物鏈題的重點不是只做一條合併，而是把一句敘述翻成三個域上的同步約束：

```cpp
struct Dsu {
    vector<int> par, sz;

    // n: number of nodes or elements.
    void init(int n) {
        par.resize(n);
        iota(par.begin(), par.end(), 0);
        sz.assign(n, 1);
    }

    // x: value or node being processed.
    int findRoot(int x) {
        if (par[x] == x) {
            return x;
        }
        return par[x] = findRoot(par[x]);
    }

    // a: input array or sequence.
    // b: second numeric input value.
    bool unite(int a, int b) {
        a = findRoot(a);
        b = findRoot(b);
        if (a == b) {
            return false;
        }
        if (sz[a] < sz[b]) {
            swap(a, b);
        }
        par[b] = a;
        sz[a] += sz[b];
        return true;
    }

    // a: numeric input value.
    // b: second numeric input value.
    bool same(int a, int b) {
        return findRoot(a) == findRoot(b);
    }
};

struct Query {
    int op, x, y;
};

// n: number of nodes or elements.
// queries: input or working vector used by the algorithm.
int foodChain(int n, const vector<Query>& queries) {
    Dsu dsu;
    dsu.init(3 * (n + 1));
    int lies = 0;

    for (auto [op, x, y] : queries) {
        if (x < 1 || x > n || y < 1 || y > n) {
            lies++;
            continue;
        }

        if (op == 1) {
            if (dsu.same(x, y + n) || dsu.same(x, y + 2 * n)) {
                lies++;
                continue;
            }
            dsu.unite(x, y);
            dsu.unite(x + n, y + n);
            dsu.unite(x + 2 * n, y + 2 * n);
        } else if (op == 2) {
            if (x == y || dsu.same(x, y) || dsu.same(x, y + n)) {
                lies++;
                continue;
            }
            dsu.unite(x + n, y);
            dsu.unite(x + 2 * n, y + n);
            dsu.unite(x, y + 2 * n);
        }
    }
    return lies;
}
```

這裡的三次 `unite` 缺一不可，因為同一條敘述會同時影響自己、獵物、天敵三個域。矛盾檢查一定要放在合併之前；一旦先把錯誤關係寫進並查集，再回頭判斷就已經來不及了。

二分圖只是 2 域版本：每個點拆成兩種顏色，邊代表兩端必須落在不同域。

```cpp
struct Dsu {
    vector<int> par, sz;

    // n: number of nodes or elements.
    explicit Dsu(int n = 0) {
        if (n) {
            init(n);
        }
    }

    // n: number of nodes or elements.
    void init(int n) {
        par.resize(n + 1);
        iota(par.begin(), par.end(), 0);
        sz.assign(n + 1, 1);
    }

    // x: value or node being processed.
    int findRoot(int x) {
        if (par[x] == x) {
            return x;
        }
        return par[x] = findRoot(par[x]);
    }

    // a: input array or sequence.
    // b: second numeric input value.
    bool unite(int a, int b) {
        a = findRoot(a);
        b = findRoot(b);
        if (a == b) {
            return false;
        }
        if (sz[a] < sz[b]) {
            swap(a, b);
        }
        par[b] = a;
        sz[a] += sz[b];
        return true;
    }

    // a: numeric input value.
    // b: second numeric input value.
    bool same(int a, int b) {
        return findRoot(a) == findRoot(b);
    }
};

struct BipartiteDsu {
    int n = 0;
    Dsu dsu;

    // n_: number of nodes/elements used to initialize the structure.
    explicit BipartiteDsu(int n_ = 0) {
        if (n_) {
            init(n_);
        }
    }

    // n_: number of nodes/elements used to initialize the structure.
    void init(int n_) {
        n = n_;
        dsu.init(2 * n);
    }

    // u: current node or left endpoint.
    // v: neighbor node or right endpoint.
    bool addEnemy(int u, int v) {
        if (dsu.same(u, v)) {
            return false;
        }
        dsu.unite(u, v + n);
        dsu.unite(u + n, v);
        return true;
    }

    // u: current node or left endpoint.
    // v: neighbor node or right endpoint.
    bool isEnemy(int u, int v) {
        return dsu.same(u, v + n);
    }
};
```

`u` 與 `u+n` 可以視為兩種互斥顏色。每加入一條邊，就把 `u` 連到 `v+n`、把 `u+n` 連到 `v`；如果加入前 `u` 與 `v` 已經是同一色，代表圖中出現奇環，因此不再是二分圖。

```cpp
// Standard BFS: single source shortest distance on unweighted graph
// src: source node index.
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
vector<int> bfs(int src, int n, const vector<vector<int>>& g) {
    vector<int> dist(n, -1);
    queue<int> q;
    dist[src] = 0;
    q.push(src);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : g[u]) {
            if (dist[v] == -1) {
                dist[v] = dist[u] + 1;
                q.push(v);
            }
        }
    }
    return dist;
}

// Multi-source BFS: distance to nearest source for each node
// sources: input or working vector used by the algorithm.
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
vector<int> multiBfs(const vector<int>& sources, int n, const vector<vector<int>>& g) {
    vector<int> dist(n, -1);
    queue<int> q;
    for (int s : sources) {
        dist[s] = 0;
        q.push(s);
    }  // All sources enqueued at once
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : g[u]) {
            if (dist[v] == -1) {
                dist[v] = dist[u] + 1;
                q.push(v);
            }
        }
    }
    return dist;
}
```
多源 BFS 的關鍵在於把所有源點**同時**放 enqueue 並設距離為 0，此後展開與單源完全相同。等效於加入一個超級源點 S，對每個源點 s 連一條邊權為 0 的邊 S→s。

```cpp
// 0-1 BFS: edges have weight 0 or 1 only
// g[u] = {(v, w)} where w is 0 or 1
// src: source node index.
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
vector<int> bfs01(int src, int n, const vector<vector<pair<int, int>>>& g) {
    vector<int> dist(n, INT_MAX);
    deque<int> dq;
    dist[src] = 0;
    dq.push_back(src);
    while (!dq.empty()) {
        int u = dq.front();
        dq.pop_front();
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                if (w == 0) {
                    dq.push_front(v);  // Same layer: push to front
                }
                else {
                    dq.push_back(v);  // Next layer:  push to back
                }
            }
        }
    }
    return dist;
}
```
邊權 0 的鄰居從**前端**插入確保先被處理（當前層）；邊權 1 的鄰居從**後端**插入（下一層）。deque 中元素的距離始終非遞減，等效於 min-heap 但每次操作為 O(1)，整體 O(n + m)。

```cpp
int timer_count = 0;
vector<int> tin, tout;
vector<bool> visited;

// u: current node or left endpoint.
// par: parent node.
// g: grid or adjacency structure used by the algorithm.
void dfs(int u, int par, const vector<vector<int>>& g) {
    visited[u] = true;
    tin[u] = timer_count++;  // Record entry time
    for (int v : g[u]) {
        if (!visited[v]) {
            dfs(v, u, g);  // Tree edge
        }
        // else: back edge (or forward/cross in directed graph)
    }
    tout[u] = timer_count++;  // Record exit time
}

// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
void solve(int n, const vector<vector<int>>& g) {
    tin.assign(n, 0);
    tout.assign(n, 0);
    visited.assign(n, false);
    timer_count = 0;
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            dfs(i, -1, g);
        }
    }
}
```
`tin[u] < tin[v] && tout[u] > tout[v]` 等價於「u 是 v 的祖先」。此性質被廣泛用於 DFS 序（Euler Tour）、樹上差分、子樹查詢等技巧。

```cpp
// Iterative DFS to avoid stack overflow on long-chain graphs
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
int countComponents(int n, const vector<vector<int>>& g) {
    vector<bool> visited(n, false);
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (visited[i]) {
            continue;
        }
        count++;  // New connected component
        stack<int> st;
        st.push(i);
        visited[i] = true;
        while (!st.empty()) {
            int u = st.top();
            st.pop();
            for (int v : g[u]) {
                if (!visited[v]) {
                    visited[v] = true;
                    st.push(v);
                }
            }
        }
    }
    return count;
}
```
迭代 DFS 用顯式 `stack` 替代系統 recursion stack，避免深鏈圖（如長鏈 n = 10⁵）導致的 stack overflow。每次進入外層 `for` 迴圈發現未訪問節點，即開啟一個新的連通分量。

```cpp
// Kahn's topological sort; returns empty vector if cycle exists
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
vector<int> kahnTopoSort(int n, const vector<vector<int>>& g) {
    vector<int> indegree(n, 0);
    for (int u = 0; u < n; u++) {
        for (int v : g[u]) {
            indegree[v]++;
        }
    }
    queue<int> q;
    for (int i = 0; i < n; i++) {
        if (indegree[i] == 0) {
            q.push(i);
        }
    }

    vector<int> order;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        order.push_back(u);
        for (int v : g[u]) {
            if (--indegree[v] == 0) {
                q.push(v);
            }
        }
    }
    return order;  // order.size() < n means cycle detected
}
```
若需輸出**字典序最小**的拓撲序，將 `queue` 改為 `priority_queue<int, vector<int>, greater<int>>`（min-heap），每次取出入度 0 中編號最小的節點，時間複雜度增加為 O((n + m) log n)。

```cpp
// DFS-based topological sort with cycle detection
// color: 0=unvisited, 1=in-progress(gray), 2=done(black)
// u: current node or left endpoint.
// color: input or working vector used by the algorithm.
// g: grid or adjacency structure used by the algorithm.
// order: input or working vector used by the algorithm.
bool dfsTopo(int u, vector<int>& color, const vector<vector<int>>& g, vector<int>& order) {
    color[u] = 1;  // Mark in-progress
    for (int v : g[u]) {
        if (color[v] == 1) {
            return false;  // Back edge: cycle!
        }
        if (color[v] == 0 && !dfsTopo(v, color, g, order)) {
            return false;
        }
    }
    color[u] = 2;        // Fully processed
    order.push_back(u);  // Post-order: push after all successors done
    return true;
}

// Returns empty vector if cycle detected
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
vector<int> topoSortDFS(int n, const vector<vector<int>>& g) {
    vector<int> color(n, 0), order;
    for (int i = 0; i < n; i++) {
        if (color[i] == 0 && !dfsTopo(i, color, g, order)) {
            return {};
        }
    }
    reverse(order.begin(), order.end());
    return order;
}
```
三色標記的核心：灰色（1）代表「遞迴正在處理中」，若走到灰色節點說明有後向邊（有向環）。黑色（2）代表已完全處理。

```cpp
// BFS bipartite check; color[] stores 0/1 partition, -1 if uncolored
// Handles disconnected graphs by iterating over all nodes
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
// color: input or working vector used by the algorithm.
bool isBipartite(int n, const vector<vector<int>>& g, vector<int>& color) {
    color.assign(n, -1);
    for (int start = 0; start < n; start++) {
        if (color[start] != -1) {
            continue;  // Already colored
        }
        queue<int> q;
        q.push(start);
        color[start] = 0;
        while (!q.empty()) {
            int u = q.front();
            q.pop();
            for (int v : g[u]) {
                if (color[v] == -1) {
                    color[v] = 1 - color[u];  // Assign opposite color
                    q.push(v);
                } else if (color[v] == color[u]) {
                    return false;  // Same color: odd cycle found
                }
            }
        }
    }
    return true;
}
```
`color[v] = 1 - color[u]` 自動切換 0↔1，確保兩端節點顏色相反。`color[]` 陣列最後也記錄了兩個分組的歸屬，可直接用於後續二分匹配。

```cpp
// DFS bipartite coloring; returns false on conflict
vector<int> side;  // 0 or 1, -1 if unassigned

// u: current node or left endpoint.
// c: candidate character or capacity value.
// g: grid or adjacency structure used by the algorithm.
bool dfsBipartite(int u, int c, const vector<vector<int>>& g) {
    side[u] = c;
    for (int v : g[u]) {
        if (side[v] == -1) {
            if (!dfsBipartite(v, 1 - c, g)) {
                return false;
            }
        } else if (side[v] == c) {
            return false;  // Adjacent nodes have same color
        }
    }
    return true;
}

// Returns {left, right} partition; {{}, {}} if not bipartite
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
pair<vector<int>, vector<int>> getBipartition(int n, const vector<vector<int>>& g) {
    side.assign(n, -1);
    for (int i = 0; i < n; i++) {
        if (side[i] == -1 && !dfsBipartite(i, 0, g)) {
            return {{}, {}};
        }
    }
    vector<int> left, right;
    for (int i = 0; i < n; i++) {
        (side[i] == 0 ? left : right).push_back(i);
    }
    return {left, right};
}
```
DFS 版直接取得兩個分組（`left`/`right`），便於後續匹配。若需還原奇環的具體路徑，在 DFS 中同時記錄父節點，偵測衝突時沿父節點回溯即可。

```cpp
const int kMaxN = 200000;
int heap_arr[kMaxN + 5];
int heap_size = 0;

// idx: current recursion index.
void siftUp(int idx) {
    while (idx > 1 && heap_arr[idx] > heap_arr[idx / 2]) {
        swap(heap_arr[idx], heap_arr[idx / 2]);
        idx /= 2;
    }
}

// idx: current recursion index.
void siftDown(int idx) {
    while (true) {
        int left = idx * 2;
        int right = left + 1;
        int largest = idx;
        if (left <= heap_size && heap_arr[left] > heap_arr[largest]) {
            largest = left;
        }
        if (right <= heap_size && heap_arr[right] > heap_arr[largest]) {
            largest = right;
        }
        if (largest == idx) {
            break;
        }
        swap(heap_arr[idx], heap_arr[largest]);
        idx = largest;
    }
}

// val: value being inserted, queried, or compared.
void push(int val) {
    heap_arr[++heap_size] = val;
    siftUp(heap_size);
}

int top() {
    return heap_arr[1];
}

void pop() {
    swap(heap_arr[1], heap_arr[heap_size]);
    heap_size--;
    if (heap_size > 0) {
        siftDown(1);
    }
}
```
`push` 先把新元素放到陣列尾端，再靠 `siftUp` 沿著父鏈往上修正；`pop` 則把根與尾端交換後縮小堆，再用 `siftDown` 往下和較大的孩子交換。因為兩種操作都只會沿著一條根到葉或葉到根的路徑移動，所以交換次數最多就是樹高。

```cpp
const int kMaxN = 200000;
int heap_arr[kMaxN + 5];
int heap_size = 0;

// idx: current recursion index.
void siftDown(int idx) {
    while (true) {
        int left = idx * 2;
        int right = left + 1;
        int largest = idx;
        if (left <= heap_size && heap_arr[left] > heap_arr[largest]) {
            largest = left;
        }
        if (right <= heap_size && heap_arr[right] > heap_arr[largest]) {
            largest = right;
        }
        if (largest == idx) {
            break;
        }
        swap(heap_arr[idx], heap_arr[largest]);
        idx = largest;
    }
}

// a: input array or sequence.
void buildHeap(const vector<int>& a) {
    heap_size = (int)a.size();
    for (int i = 0; i < heap_size; i++) {
        heap_arr[i + 1] = a[i];
    }
    for (int i = heap_size / 2; i >= 1; i--) {
        siftDown(i);
    }
}
```
Floyd 建堆直接從最後一個內部節點開始往上整理，葉節點完全不需要處理。底層節點雖然很多，但能下沉的距離很短；高層節點雖然下沉距離較長，數量卻很少，因此所有 `siftDown` 的總工作量加總後就是 O(n)。

```cpp
// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
vector<int> topK(const vector<int>& a, int k) {
    if (k <= 0) {
        return {};
    }
    priority_queue<int, vector<int>, greater<int>> pq;
    for (int x : a) {
        if ((int)pq.size() < k) {
            pq.push(x);
        } else if (x > pq.top()) {
            pq.pop();
            pq.push(x);
        }
    }

    vector<int> result;
    while (!pq.empty()) {
        result.push_back(pq.top());
        pq.pop();
    }
    sort(result.rbegin(), result.rend());
    return result;
}

// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
int kthLargest(const vector<int>& a, int k) {
    if (k <= 0) {
        return INT_MIN;
    }
    priority_queue<int, vector<int>, greater<int>> pq;
    for (int x : a) {
        if ((int)pq.size() < k) {
            pq.push(x);
        } else if (x > pq.top()) {
            pq.pop();
            pq.push(x);
        }
    }
    return (int)pq.size() == k ? pq.top() : INT_MIN;
}
```
`pq` 始終只保留目前最強的 `k` 個元素，所以堆頂就是這批元素裡最小者，也就是第 `k` 大。若最後還想把答案列出來，可以把堆內容取出後再排序；若只要第 `k` 大，直接讀 `pq.top()` 即可。

```cpp
class KthLargest {
   private:
    int k;
    priority_queue<int, vector<int>, greater<int>> pq;

   public:
    // k_: requested order/statistic or limit.
    // initial_values: input or working vector used by the algorithm.
    KthLargest(int k_, const vector<int>& initial_values) : k(k_) {
        for (int x : initial_values) {
            add(x);
        }
    }

    // val: value being inserted, queried, or compared.
    int add(int val) {
        if (k <= 0) {
            return INT_MIN;
        }
        if ((int)pq.size() < k) {
            pq.push(val);
        } else if (val > pq.top()) {
            pq.pop();
            pq.push(val);
        }
        return (int)pq.size() == k ? pq.top() : INT_MIN;
    }
};
```
這個類別把「維護大小為 `k` 的 min-heap」封裝成資料流介面。當目前總元素還不到 `k` 個時，這裡用 `INT_MIN` 當作尚未形成第 `k` 大的哨兵；實戰中也可以改成回傳 `optional<int>`，或另外提供 `ready()` 之類的狀態判斷。

```cpp
class MedianFinder {
   private:
    priority_queue<int> max_heap;
    priority_queue<int, vector<int>, greater<int>> min_heap;

    void rebalance() {
        if (max_heap.size() > min_heap.size() + 1) {
            min_heap.push(max_heap.top());
            max_heap.pop();
        } else if (min_heap.size() > max_heap.size()) {
            max_heap.push(min_heap.top());
            min_heap.pop();
        }
    }

   public:
    // num: number being tested or processed.
    void addNum(int num) {
        if (max_heap.empty() || num <= max_heap.top()) {
            max_heap.push(num);
        } else {
            min_heap.push(num);
        }

        if (!max_heap.empty() && !min_heap.empty() && max_heap.top() > min_heap.top()) {
            int left_top = max_heap.top();
            int right_top = min_heap.top();
            max_heap.pop();
            min_heap.pop();
            max_heap.push(right_top);
            min_heap.push(left_top);
        }

        rebalance();
    }

    double getMedian() const {
        if (max_heap.empty() && min_heap.empty()) {
            return 0.0;
        }
        if (max_heap.size() > min_heap.size()) {
            return static_cast<double>(max_heap.top());
        }
        return (static_cast<long long>(max_heap.top()) + min_heap.top()) / 2.0;
    }
};
```
這份寫法先依 `num` 與左堆堆頂的大小決定放哪一邊，再檢查兩個不變量：左堆所有元素要 `<=` 右堆，且左堆大小最多只比右堆多 `1`。一旦這兩條都成立，中位數就只會出現在兩個堆頂，不必掃描全部資料。

```cpp
struct SlidingMedian {
    multiset<int> lower, upper;

    void balance() {
        while (lower.size() > upper.size() + 1) {
            auto it = prev(lower.end());
            upper.insert(*it);
            lower.erase(it);
        }
        while (lower.size() < upper.size()) {
            auto it = upper.begin();
            lower.insert(*it);
            upper.erase(it);
        }
    }

    // x: value or node being processed.
    void add(int x) {
        if (lower.empty() || x <= *prev(lower.end())) {
            lower.insert(x);
        }
        else {
            upper.insert(x);
        }
        balance();
    }

    // x: value, node, or output coefficient used by the function.
    void eraseOne(int x) {
        auto it = lower.find(x);
        if (it != lower.end()) {
            lower.erase(it);
        } else {
            it = upper.find(x);
            if (it != upper.end()) {
                upper.erase(it);
            }
        }
        balance();
    }

    double median() const {
        if (lower.empty() && upper.empty()) {
            return 0.0;
        }
        if (lower.size() > upper.size()) {
            return static_cast<double>(*prev(lower.end()));
        }
        return (static_cast<long long>(*prev(lower.end())) + *upper.begin()) / 2.0;
    }
};
```
`multiset` 能同時支援 `insert`、`erase` 與取極值，因此比 `priority_queue` 更適合滑動視窗這種必須刪除舊元素的情境。若你仍想保留堆結構，就要把刪除改成延遲刪除：先記錄待刪數量，等元素浮到堆頂時再真正移除。

```cpp
class LazyHeap {
   private:
    priority_queue<int, vector<int>, greater<int>> pq;
    unordered_map<int, int> to_delete;

    void cleanup() {
        while (!pq.empty()) {
            int x = pq.top();
            auto it = to_delete.find(x);
            if (it == to_delete.end() || it->second == 0) {
                break;
            }
            if (--it->second == 0) {
                to_delete.erase(it);
            }
            pq.pop();
        }
    }

   public:
    // x: value or node being processed.
    void push(int x) {
        pq.push(x);
    }

    // x: value, node, or output coefficient used by the function.
    void erase(int x) {
        to_delete[x]++;
    }

    int top() {
        cleanup();
        return pq.top();
    }

    void pop() {
        cleanup();
        if (!pq.empty()) {
            pq.pop();
        }
    }

    bool empty() {
        cleanup();
        return pq.empty();
    }
};
```
`erase(x)` 並不會立刻從堆中找出 `x`，而只是把「未來遇到 `x` 時要跳過一次」記到 `toDelete`。真正保證答案正確的是 `cleanup()`：任何讀取堆頂的操作都先把失效元素清光，讓 `top()` 永遠回傳第一個仍然有效的值。

```cpp
struct DualHeapMedian {
    priority_queue<int> small;
    priority_queue<int, vector<int>, greater<int>> large;
    unordered_map<int, int> delayed;
    int small_size = 0;  // Valid elements only
    int large_size = 0;  // Valid elements only

    // x: value or node being processed.
    bool isDelayed(int x) const {
        auto it = delayed.find(x);
        return it != delayed.end() && it->second > 0;
    }

    void pruneSmall() {
        while (!small.empty() && isDelayed(small.top())) {
            int x = small.top();
            auto it = delayed.find(x);
            if (--it->second == 0) {
                delayed.erase(it);
            }
            small.pop();
        }
    }

    void pruneLarge() {
        while (!large.empty() && isDelayed(large.top())) {
            int x = large.top();
            auto it = delayed.find(x);
            if (--it->second == 0) {
                delayed.erase(it);
            }
            large.pop();
        }
    }

    void rebalance() {
        if (small_size > large_size + 1) {
            large.push(small.top());
            small.pop();
            small_size--;
            large_size++;
            pruneSmall();
        } else if (small_size < large_size) {
            small.push(large.top());
            large.pop();
            small_size++;
            large_size--;
            pruneLarge();
        }
    }

    // num: number being tested or processed.
    void addNum(int num) {
        if (small.empty() || num <= small.top()) {
            small.push(num);
            small_size++;
        } else {
            large.push(num);
            large_size++;
        }
        rebalance();
    }

    // num: input value used by the function.
    void eraseNum(int num) {
        delayed[num]++;
        pruneSmall();
        pruneLarge();
        if (!small.empty() && num <= small.top()) {
            small_size--;
            if (!small.empty() && small.top() == num) {
                pruneSmall();
            }
        } else {
            large_size--;
            if (!large.empty() && large.top() == num) {
                pruneLarge();
            }
        }
        rebalance();
    }

    double getMedian() {
        pruneSmall();
        pruneLarge();
        if (small_size > large_size) {
            return static_cast<double>(small.top());
        }
        return (static_cast<long long>(small.top()) + large.top()) / 2.0;
    }
};
```
`smallSize` 與 `largeSize` 記錄的是**有效元素數**，不是實際堆大小，因為堆內可能還躺著尚未清掉的舊值。`pruneSmall()`／`pruneLarge()` 只在元素來到堆頂時才物理刪除它們，而 `rebalance()` 則根據有效元素數維持左右半邊的比例，這正是滑動視窗中位數常見的標準模板。

```cpp
// Merge overlapping intervals. Input: pairs [l, r] (inclusive).
// segs: input or working vector used by the algorithm.
vector<pair<int, int>> mergeIntervals(vector<pair<int, int>> segs) {
    sort(segs.begin(), segs.end());  // Sort by left endpoint
    vector<pair<int, int>> res;
    for (auto [l, r] : segs) {
        if (!res.empty() && l <= res.back().second) {
            res.back().second = max(res.back().second, r);  // Extend
        } else {
            res.push_back({l, r});  // New disjoint interval
        }
    }
    return res;
}
```

`l <= res.back().second`：新區間左端 ≤ 當前右端，代表重疊（含端點接觸）。若題目定義「相鄰但不重疊的區間不合併」，改成 `l < res.back().second` 即可。

```cpp
// Insert [l, r] into a sorted set of disjoint intervals.
// Merge overlapping intervals in O(k log n), where k is the merged count.
// segs: list of line segments.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
set<pair<int, int>> insertInterval(set<pair<int, int>>& segs, int l, int r) {
    // Find first interval that starts after l-1 (could overlap)
    auto it = segs.lower_bound({l, INT_MIN});
    if (it != segs.begin()) {  // Check prev interval
        --it;
        if (it->second < l) {
            ++it;  // No overlap with prev
        }
    }
    // Merge all overlapping intervals
    while (it != segs.end() && it->first <= r) {
        l = min(l, it->first);
        r = max(r, it->second);
        it = segs.erase(it);
    }
    segs.insert({l, r});
    return segs;
}
```

動態維護不重疊集合時用 `std::set`（按 `(l, r)` 排序），插入一個新區間後，用 `lower_bound` 定位可能重疊的鄰近區間，逐一合併。每次插入均攤 O(log n)（被刪除的區間後續不會再出現）。

```cpp
// Maximum number of non-overlapping intervals.
// Ties in end time: either works, but sort stably for determinism.
// segs: input or working vector used by the algorithm.
int maxNonOverlap(vector<pair<int, int>> segs) {
    // Sort by END time (then start time as tiebreak)
    sort(segs.begin(), segs.end(), [](auto& a, auto& b) {
        return a.second != b.second ? a.second < b.second : a.first < b.first;
    });
    int count = 0, last = INT_MIN;
    for (auto [l, r] : segs) {
        if (l >= last) {  // No overlap with last selected
            count++;
            last = r;  // Update last ending time
        }
    }
    return count;
}
```

`l >= last`：新區間的左端嚴格不早於上一個選取區間的右端——兩者不重疊（端點接觸允許）。若題目認為端點接觸算重疊，改成 `l > last`。

```cpp
// Minimum number of machines = maximum concurrent intervals.
// Equivalent to: find max number of intervals active at one time.
// segs: input or working vector used by the algorithm.
int minMachines(vector<pair<int, int>> segs) {
    vector<pair<int, int>> events;
    for (auto [l, r] : segs) {
        events.push_back({l, 1});   // Start event
        events.push_back({r, -1});  // End event
    }
    // Sort: same time -> end (-1) before start (1) avoids double counting
    sort(events.begin(), events.end(), [](auto& a, auto& b) {
        return a.first != b.first ? a.first < b.first : a.second < b.second;
    });
    int machines = 0, cur = 0;
    for (auto [t, d] : events) {
        cur += d;
        machines = max(machines, cur);
    }
    return machines;
}
```

若區間定義為半開 `[l, r)`，相同時間點的結束事件先於開始事件，不需要特別排序技巧。閉區間 `[l, r]` 則需保證 `r` 的 `-1` 在 `l` 的 `+1` 之前（如上），否則 `r == l'` 時兩個不重疊的區間會被誤算為同時活躍。

```cpp
// Difference array: apply range [l, r] += v in O(1), recover in O(n)
struct DiffArray {
    vector<long long> d;
    int n;
    // n: number of nodes or elements.
    DiffArray(int n) : n(n), d(n + 2, 0) {}
    // Add v to a[l..r] (0-indexed, inclusive)
    // l: left boundary or endpoint.
    // r: right boundary, row, or endpoint.
    // v: neighbor node or right endpoint.
    void add(int l, int r, long long v) {
        d[l] += v;
        d[r + 1] -= v;
    }
    // Recover original array (prefix sum of d)
    vector<long long> build() {
        vector<long long> a(n);
        long long cur = 0;
        for (int i = 0; i < n; i++) {
            cur += d[i];
            a[i] = cur;
        }
        return a;
    }
};
```

`d` 大小開 `n + 2` 避免 `d[r+1]` 越界（r 最大為 n-1 時 r+1 = n）。若需要在 `build` 後繼續 `add`，要重置 `d`；通常差分陣列是一次性工具。

```cpp
// 2D difference array: add v to rectangle (r1, c1)-(r2, c2) in O(1)
struct Diff2D {
    int rowCount, col_count;
    vector<vector<long long>> d;
    // row_count_: number of rows.
    // col_count_: number of columns.
    Diff2d(int row_count_, int col_count_)
        : rowCount(row_count_),
          // col_count_: input value used by the function.
          col_count(col_count_),
          // rowCount: number of rows.
          // col_count: input or working vector used by the algorithm.
          d(rowCount + 2, vector<long long>(col_count + 2, 0)) {}
    // r1: right index of the first interval/string segment.
    // c1: first column or character index.
    // r2: right index of the second interval/string segment.
    // c2: second column or character index.
    // v: neighbor node or right endpoint.
    void add(int r1, int c1, int r2, int c2, long long v) {
        d[r1][c1] += v;
        d[r1][c2 + 1] -= v;
        d[r2 + 1][c1] -= v;
        d[r2 + 1][c2 + 1] += v;  // Double-subtract fix
    }
    // Recover matrix via 2D prefix sum
    vector<vector<long long>> build() {
        vector<vector<long long>> a(rowCount, vector<long long>(col_count, 0));
        for (int i = 0; i < rowCount; i++) {
            for (int j = 0; j < col_count; j++) {
                d[i][j] +=
                    (i ? d[i - 1][j] : 0) + (j ? d[i][j - 1] : 0) - (i && j ? d[i - 1][j - 1] : 0);
                a[i][j] = d[i][j];
            }
        }
        return a;
    }
};
```

二維差分四個角落的加減是容斥原理的體現（與二維前綴和的拆法對稱）：加左上角、減兩個端線角、加右下角，使前綴和後正好在矩形內多 v、矩形外為 0。

```cpp
// Minimum meeting rooms (= maximum concurrent intervals).
// Closed intervals: [l, r]. End events before start at same time.
// segs: input or working vector used by the algorithm.
int minMeetingRooms(vector<pair<int, int>>& segs) {
    vector<pair<int, int>> ev;  // (time, type): type -1=end, +1=start
    for (auto [l, r] : segs) {
        ev.push_back({l, 1});
        ev.push_back({r, -1});
    }
    // Sort: same time -> end (-1) before start (+1)
    sort(ev.begin(), ev.end(), [](auto& a, auto& b) {
        return a.first != b.first ? a.first < b.first : a.second < b.second;
    });
    int cur = 0, ans = 0;
    for (auto [t, d] : ev) {
        cur += d;
        ans = max(ans, cur);
    }
    return ans;
}
```

排序比較器 `a.second < b.second` 把 `-1`（結束）排在 `+1`（開始）之前——同時刻的離開先處理，避免「上一場剛結束同時下一場開始」被算為兩間同時佔用。

```cpp
// Total length covered by the union of segments [l, r).
// Uses half-open intervals to simplify overlap counting.
// segs: input or working vector used by the algorithm.
long long unionLength(vector<pair<int, int>>& segs) {
    vector<pair<int, int>> ev;
    for (auto [l, r] : segs) {
        ev.push_back({l, 1});
        ev.push_back({r, -1});  // Half-open: r is exclusive
    }
    sort(ev.begin(), ev.end());
    long long total = 0, prev = 0;
    int cnt = 0;
    for (auto [t, d] : ev) {
        if (cnt > 0) {
            total += t - prev;  // Covered while cnt > 0
        }
        cnt += d;
        prev = t;
    }
    return total;
}
```

關鍵：在處理事件**之前**，若 `cnt > 0`，把 `[prev, t)` 這段長度加入答案（現在這段都在至少一個區間覆蓋中）；然後更新 cnt，記錄新時刻 prev = t。半開區間時同時刻的結束與開始自然正確排序。

```cpp
const int kMaxN = 1e7 + 5;
bool is_composite[kMaxN];
vector<int> primes;

// n: number of nodes or elements.
void sieveEratosthenes(int n) {
    // Start marking from i*i; smaller multiples already sieved by smaller primes
    for (int i = 2; i <= n; i++) {
        if (!is_composite[i]) {
            primes.push_back(i);
            for (long long j = (long long)i * i; j <= n; j += i) {
                is_composite[j] = true;
            }
        }
    }
}
```
從 `(long long)i * i` 開始標記，可省去重複篩除小倍數的工作；同時用 `long long` 防止 i > 46340 時 `i * i` 整數溢位。

```cpp
const int kMaxN = 1e7 + 5;
int spf[kMaxN];      // Smallest prime factor (0 = uninitialized)
int phi_arr[kMaxN];  // Euler's totient function
vector<int> primes;

// n: number of nodes or elements.
void linearSieve(int n) {
    phi_arr[1] = 1;
    for (int i = 2; i <= n; i++) {
        if (!spf[i]) {  // i is prime
            spf[i] = i;
            phi_arr[i] = i - 1;
            primes.push_back(i);
        }
        for (int j = 0; j < (int)primes.size(); j++) {
            int p = primes[j];
            if ((long long)p * i > n || p > spf[i]) {
                break;
            }
            spf[p * i] = p;  // p is the smallest prime factor of p*i
            phi_arr[p * i] = (spf[i] == p) ? phi_arr[i] * p         // p already divides i
                                           : phi_arr[i] * (p - 1);  // p is a new prime factor
        }
    }
}

// Factorize n using spf table: O(log n)
// n: number of nodes or elements.
vector<pair<int, int>> factorize(int n) {
    vector<pair<int, int>> res;
    while (n > 1) {
        int p = spf[n], cnt = 0;
        while (n % p == 0) {
            n /= p;
            cnt++;
        }
        res.push_back({p, cnt});
    }
    return res;
}
```
`p > spf[i]` 時立即 break：此時 p*i 的最小質因子是 spf[i] 而非 p，由對應的 i' 負責標記，確保每個合數只被處理一次。

```cpp
// a: input array or sequence.
// b: second numeric input value.
long long gcd(long long a, long long b) {
    return b ? gcd(b, a % b) : a;
}

// Extended Euclidean: returns gcd(a, b), sets x, y s.t. a*x + b*y = gcd(a, b)
// a: input array or sequence.
// b: second numeric input value.
// x: value or node being processed.
// y: y-coordinate or output coefficient.
long long exgcd(long long a, long long b, long long& x, long long& y) {
    if (b == 0) {
        x = 1;
        y = 0;
        return a;
    }
    long long x1, y1;
    long long g = exgcd(b, a % b, x1, y1);
    x = y1;                 // x  = y'
    y = x1 - (a / b) * y1;  // y  = x' - floor(a/b)*y'
    return g;
}
```
基礎情形 b=0：令 x=1, y=0，使 a·1 + 0·0 = a = gcd。每層遞迴按公式重組解，保證回傳時 `a*x + b*y == g` 始終成立。

```cpp
// Solve ax ≡ c (mod m).
// Returns smallest non-negative solution, or -1 if no solution exists.
// a: input array or sequence.
// c: candidate character or capacity value.
// m: number of edges, columns, or elements depending on the problem.
long long solveCongruence(long long a, long long c, long long m) {
    long long x, y;
    long long g = exgcd(a, m, x, y);
    if (c % g != 0) {
        return -1;          // No solution: g does not divide c
    }
    long long mod = m / g;  // Solution period
    // x is a particular solution to a*x + m*y = g; scale by c/g
    return ((__int128)x * (c / g) % mod + mod) % mod;
}
```
`(__int128)x * (c / g)` 防止 x 與 c/g 相乘超過 `long long` 範圍；最終結果在 [0, mod) 之間，是最小非負解。所有解為 `x₀ + k * (m/g)`，k ∈ ℤ。

```cpp
// Iterative binary exponentiation: returns a^b mod m
// Safe when m < ~3e9 (product of two residues fits in long long)
// a: input array or sequence.
// b: second numeric input value.
// m: number of edges, columns, or elements depending on the problem.
long long fastPow(long long a, long long b, long long m) {
    long long res = 1;
    a %= m;  // Normalize base (also handles a >= m)
    for (; b > 0; b >>= 1) {
        if (b & 1) {
            res = res * a % m;  // Accumulate when bit is set
        }
        a = a * a % m;          // Square the base
    }
    return res;
}
```
迭代版從最低位開始處理，無遞迴開銷。b = 0 時迴圈不執行，直接回傳 1（任何數的 0 次方為 1），行為正確。

```cpp
typedef vector<vector<long long>> Matrix;
const long long kMod = 1e9 + 7;

// Matrix multiplication mod kMod
// matrix_a: left matrix operand.
// matrix_b: right matrix operand.
Matrix matMul(const Matrix& matrix_a, const Matrix& matrix_b) {
    int n = matrix_a.size();
    Matrix result(n, vector<long long>(n, 0));
    for (int i = 0; i < n; i++) {
        for (int k = 0; k < n; k++) {
            if (matrix_a[i][k]) {
                for (int j = 0; j < n; j++) {
                    result[i][j] = (result[i][j] + matrix_a[i][k] * matrix_b[k][j]) % kMod;
                }
            }
        }
    }
    return result;
}

// Matrix exponentiation: matrix_a^p mod kMod
// matrix_a: left matrix operand.
// p: exponent applied to the matrix.
Matrix matPow(Matrix matrix_a, long long p) {
    int n = matrix_a.size();
    Matrix result(n, vector<long long>(n, 0));
    for (int i = 0; i < n; i++) {
        result[i][i] = 1;  // Identity matrix (plays role of "res=1")
    }
    for (; p > 0; p >>= 1) {
        if (p & 1) {
            result = matMul(result, matrix_a);
        }
        matrix_a = matMul(matrix_a, matrix_a);
    }
    return result;
}
// Fibonacci: [[1, 1], [1, 0]]^n gives F(n+1) at [0][0]
```
矩陣乘法需保證每次中間乘積 `A[i][k] * B[k][j]` 不溢位：若 MOD < 3×10⁹，兩個元素相乘 < 9×10¹⁸，在 `long long` 範圍內安全。

```cpp
const long long kMod = 1e9 + 7;
const int kCombN = 2e6 + 5;
long long fact[kCombN], inv_fact[kCombN];

// a: input array or sequence.
// b: second numeric input value.
// m: number of edges, columns, or elements depending on the problem.
long long fastPow(long long a, long long b, long long m) {
    long long res = 1;
    a %= m;
    for (; b > 0; b >>= 1) {
        if (b & 1) {
            res = res * a % m;
        }
        a = a * a % m;
    }
    return res;
}

// n: number of nodes or elements.
void precomputeComb(int n) {
    fact[0] = 1;
    for (int i = 1; i <= n; i++) {
        fact[i] = fact[i - 1] * i % kMod;
    }
    inv_fact[n] = fastPow(fact[n], kMod - 2, kMod);  // One modular inverse
    for (int i = n - 1; i >= 0; i--) {
        inv_fact[i] = inv_fact[i + 1] * (i + 1) % kMod;  // Backward recurrence
    }
}

// n: number of nodes or elements.
// k: limit, count, or window size used by the algorithm.
long long comb(int n, int k) {
    if (k < 0 || k > n || n < 0) {
        return 0;
    }
    return fact[n] * inv_fact[k] % kMod * inv_fact[n - k] % kMod;
}
```
反向遞推 `inv_fact[i] = inv_fact[i+1] * (i+1)` 利用了 `(i!)⁻¹ = ((i+1)!)⁻¹ * (i+1)`，只需一次快速冪即可算出所有逆階乘。

```cpp
// Lucas theorem: comb(n, k) mod p where p is a small prime
// Requires: precomputeComb(p - 1) called with kMod = p beforehand
// n: number of nodes or elements.
// k: limit, count, or window size used by the algorithm.
// p: prime modulus used by Lucas theorem.
long long lucas(long long n, long long k, long long p) {
    if (k == 0) {
        return 1;
    }
    if (n < k) {
        return 0;  // Out of range: result is 0
    }
    return lucas(n / p, k / p, p) * comb(n % p, k % p) % p;
}
```
`C(n % p, k % p)` 使用小範圍的預計算表（長度僅需 p），Lucas 遞迴深度 O(log_p n)。若 n % p < k % p，`C(n % p, k % p)` 回傳 0，符合 Kummer 定理。

```cpp
// exgcd needed (defined separately)
long long exgcd(long long a, long long b, long long& x, long long& y);

// CRT for pairwise coprime moduli: x ≡ r[i] (mod m[i])
// Returns x mod (product of all m[i]); assumes product fits in long long
// r: right boundary, row, or endpoint.
// m: number of edges, columns, or elements depending on the problem.
long long crtCoprime(const vector<long long>& r, const vector<long long>& m) {
    long long M = 1;
    for (long long mi : m) {
        M *= mi;  // Total modulus
    }
    long long x = 0;
    for (int i = 0; i < (int)r.size(); i++) {
        long long Mi = M / m[i];  // Product of all moduli except m[i]
        long long xi, yi;
        exgcd(Mi, m[i], xi, yi);  // Mi * xi ≡ 1 (mod m[i])
        xi = (xi % m[i] + m[i]) % m[i];
        x = (x + (__int128)r[i] * Mi % M * xi) % M;
    }
    return x;
}
```
使用 `__int128` 計算中間乘積，防止 `r[i] * Mi` 溢位。若模數乘積 M 本身超過 `long long`，需改用 `__int128` 存 M 及 x。

```cpp
// Merge x ≡ r1 (mod m1) and x ≡ r2 (mod m2).
// Returns {r, lcm(m1, m2)} or {-1, -1} if incompatible.
// r1: right index of the first interval/string segment.
// m1: first middle point in ternary search.
// r2: right index of the second interval/string segment.
// m2: second middle point in ternary search.
pair<long long, long long> crtMerge(long long r1, long long m1, long long r2, long long m2) {
    long long x, y;
    long long g = exgcd(m1, m2, x, y);  // m1*x + m2*y = g
    if ((r2 - r1) % g != 0) {
        return {-1, -1};          // Incompatible
    }
    long long lcm = m1 / g * m2;  // Divide first to reduce overflow
    // t = (r2 - r1) / g * x  mod (m2/g)
    long long t = (__int128)(r2 - r1) / g * x % (m2 / g);
    long long r = (r1 + (__int128)m1 * t % lcm + lcm) % lcm;
    return {r, lcm};
}

// Solve a system of congruences (moduli need not be coprime)
// r: right boundary, row, or endpoint.
// m: number of edges, columns, or elements depending on the problem.
pair<long long, long long> crtSystem(const vector<long long>& r, const vector<long long>& m) {
    long long cr = r[0], cm = m[0];
    for (int i = 1; i < (int)r.size(); i++) {
        auto [nr, nm] = crtMerge(cr, cm, r[i], m[i]);
        if (nr == -1) {
            return {-1, -1};  // No solution
        }
        cr = nr;
        cm = nm;
    }
    return {cr, cm};  // x ≡ cr (mod cm)
}
```
`(__int128)m1 * t % lcm` 避免 m1 與 t 相乘時溢位；`+ lcm` 確保結果非負後再取模。

```cpp
// Dsu with path compression and union by rank
struct Dsu {
    vector<int> parent, rnk;
    // n: number of nodes or elements.
    Dsu(int n) : parent(n), rnk(n, 0) {
        iota(parent.begin(), parent.end(), 0);
    }
    // x: value or node being processed.
    int findRoot(int x) {
        if (parent[x] != x) {
            parent[x] = findRoot(parent[x]);  // Path compression
        }
        return parent[x];
    }
    // a: input array or sequence.
    // b: second numeric input value.
    bool unite(int a, int b) {
        a = findRoot(a);
        b = findRoot(b);
        if (a == b) {
            return false;  // Already in same component
        }
        if (rnk[a] < rnk[b]) {
            swap(a, b);
        }
        parent[b] = a;
        if (rnk[a] == rnk[b]) {
            rnk[a]++;  // Union by rank
        }
        return true;
    }
};

// Kruskal: edges = vector of {weight, u, v}
// n: number of nodes or elements.
// edges: edge list used by the algorithm.
long long kruskal(int n, vector<tuple<int, int, int>>& edges) {
    sort(edges.begin(), edges.end());  // Sort by weight ascending
    Dsu dsu(n);
    long long total = 0;
    int cnt = 0;
    for (auto [w, u, v] : edges) {
        if (dsu.unite(u, v)) {
            total += w;
            if (++cnt == n - 1) {
                break;  // MST complete: n-1 edges chosen
            }
        }
    }
    return cnt == n - 1 ? total : -1;  // -1 if graph is disconnected
}
```

`dsu.unite(u, v)` 返回 `true` 代表 u、v 原本不同分量，此邊被加入 MST；返回 `false` 代表已同分量，加入會成環，跳過。提前退出（`cnt == n-1`）可節省不必要的迭代。

```cpp
// Kruskal returning the actual MST edges (needed for second-MST, etc.)
// Also records which edges are in the MST via in_mst flags
// n: number of nodes or elements.
// edges: edge list used by the algorithm.
// in_mst: input or working vector used by the algorithm.
long long kruskalWithEdges(int n, vector<tuple<int, int, int>>& edges,
                           vector<bool>& in_mst) {  // in_mst[i] = true if edge i is in MST
    sort(edges.begin(), edges.end());
    in_mst.assign(edges.size(), false);
    Dsu dsu(n);
    long long total = 0;
    int cnt = 0;
    for (int i = 0; i < (int)edges.size(); i++) {
        auto [w, u, v] = edges[i];
        if (dsu.unite(u, v)) {
            in_mst[i] = true;  // Mark this edge as part of MST
            total += w;
            if (++cnt == n - 1) {
                break;
            }
        }
    }
    return cnt == n - 1 ? total : -1;
}
```

記錄 MST 邊集合在**次小生成樹**、**瓶頸生成樹**等進階問題中非常重要。選出的 n-1 條邊組成 MST，其餘邊稱為**非樹邊（non-tree edge）**，次小生成樹的構造正是基於枚舉非樹邊。

```cpp
// Prim's MST with priority_queue (heap-optimized, for sparse graphs)
// src: source node index.
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
long long prim(int src, int n, const vector<vector<pair<int, int>>>& g) {
    const long long kInf = 1e18;
    vector<long long> key(n, kInf);  // Min edge weight to connect v to current MST
    vector<bool> in_mst(n, false);
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    key[src] = 0;
    pq.push({0, src});
    long long total = 0;
    int cnt = 0;
    while (!pq.empty()) {
        auto [k, u] = pq.top();
        pq.pop();
        if (in_mst[u]) {
            continue;  // Lazy deletion: already added to MST
        }
        in_mst[u] = true;
        total += k;  // Add this edge's weight to MST total
        cnt++;
        for (auto [v, w] : g[u]) {
            if (!in_mst[v] && w < key[v]) {
                // cumulative: accumulated value so far.
                key[v] = w;  // Update min connection cost (NOT cumulative)
                pq.push({key[v], v});
            }
        }
    }
    return cnt == n ? total : -1;  // -1 if graph is disconnected
}
```

**關鍵差異**：Dijkstra 推入堆的是 `dist[u] + w`（累積路徑長），Prim 推入的是 `w`（單條邊邊權 `key[v]`）。`inMST[]` 的作用等同於 Dijkstra 的懶惰刪除——已入樹的節點不再更新。

```cpp
// O(V^2) Prim for dense graphs using adjacency matrix
// adj[i][j] = edge weight, kInf if no direct edge
// n: number of nodes or elements.
// adj: input or working vector used by the algorithm.
long long primDense(int n, const vector<vector<long long>>& adj) {
    const long long kInf = 1e18;
    vector<long long> key(n, kInf);
    vector<bool> in_mst(n, false);
    key[0] = 0;  // Start from node 0
    long long total = 0;
    for (int iter = 0; iter < n; iter++) {
        // Find minimum key vertex not yet in MST (linear scan)
        int u = -1;
        for (int v = 0; v < n; v++) {
            if (!in_mst[v] && (u == -1 || key[v] < key[u])) {
                u = v;
            }
        }
        if (key[u] == kInf) {
            return -1;  // Graph is disconnected
        }
        in_mst[u] = true;
        total += key[u];
        // Update keys for all neighbors of u
        for (int v = 0; v < n; v++) {
            if (!in_mst[v] && adj[u][v] < key[v]) {
                key[v] = adj[u][v];
            }
        }
    }
    return total;
}
```

稠密圖（E ≈ V²）時，O(V²) 的矩陣版 Prim 常數小，實際上比 O(E log V) 的堆版更快。每輪用線性掃描找 key 最小節點，省去堆的 log 因子。V ≤ 3000 時為競賽首選。

```cpp
// After building MST as a rooted tree, precompute LCA + max edge on path
const int kLog = 18;
int par[100005][kLog];    // par[v][k] = 2^k-th ancestor of v
int max_e[100005][kLog];  // max_e[v][k] = max edge weight in v's path going up 2^k steps
int dep[100005];

// u: current node or left endpoint.
// p: parent node or previous node.
// d: current depth or distance value.
// mst_graph: adjacency list or 2D table used by the algorithm.
void dfs(int u, int p, int d, const vector<vector<pair<int, int>>>& mst_graph) {
    par[u][0] = p;
    dep[u] = d;
    for (int k = 1; k < kLog; k++) {
        par[u][k] = par[par[u][k - 1]][k - 1];
        max_e[u][k] = max(max_e[u][k - 1], max_e[par[u][k - 1]][k - 1]);  // Combine two halves
    }
    for (auto [v, w] : mst_graph[u]) {
        if (v == p) {
            continue;
        }
        max_e[v][0] = w;  // Edge weight from v to its parent
        dfs(v, u, d + 1, mst_graph);
    }
}

// Query max edge weight on MST path from u to v
// u: current node or left endpoint.
// v: neighbor node or right endpoint.
int queryMaxEdge(int u, int v) {
    int res = 0;
    if (dep[u] < dep[v]) {
        swap(u, v);
    }
    int diff = dep[u] - dep[v];
    for (int k = 0; k < kLog; k++) {  // Lift u to same depth as v
        if ((diff >> k) & 1) {
            res = max(res, max_e[u][k]);
            u = par[u][k];
        }
    }
    if (u == v) {
        return res;  // v is ancestor of u
    }
    for (int k = kLog - 1; k >= 0; k--) {
        if (par[u][k] != par[v][k]) {
            res = max({res, max_e[u][k], max_e[v][k]});
            u = par[u][k];
            v = par[v][k];
        }
    }
    return max({res, max_e[u][0], max_e[v][0]});  // Final step to LCA
}
```

`maxE[v][0]` 初始化為 v 到其父節點的邊權；倍增合併：`maxE[u][k] = max(maxE[u][k-1], maxE[par[u][k-1]][k-1])`，將兩段 2^(k-1) 長度的路徑最大值合併。查詢時在提升深度的過程中同步維護 max，包含最後一步到 LCA 的兩條邊不能遺漏。

```cpp
// Find strict second MST weight
// Requires: mst_weight, in_mst flags from Kruskal, and queryMaxEdge precomputed
// mst_weight: total weight of the minimum spanning tree.
// edges: edge list used by the algorithm.
// w: edge weight or node weight.
// u: current node or left endpoint.
// in_mst: input or working vector used by the algorithm.
long long secondMST(long long mst_weight,
                    const vector<tuple<int, int, int>>& edges,  // All edges sorted: {w, u, v}
                    const vector<bool>& in_mst) {  // in_mst[i] = true if edge i is in MST
    long long ans = LLONG_MAX;
    for (int i = 0; i < (int)edges.size(); i++) {
        if (in_mst[i]) {
            continue;  // Skip MST edges
        }
        auto [w, u, v] = edges[i];
        int mx = queryMaxEdge(u, v);  // Max edge on MST path from u to v
        if (w == mx) {
            continue;  // Would not change total weight (strict 2nd MST)
        }
        ans = min(ans, mst_weight - mx + w);
    }
    return ans;  // LLONG_MAX if no valid second MST exists
}

// Main driver: Kruskal -> DFS -> queryMaxEdge -> secondMST
// 1. kruskalWithEdges(n, edges, in_mst) -> mst_weight, builds in_mst flags
// 2. Build mst_graph (adjacency list from MST edges)
// 3. dfs(root=0, par=-1, dep=0, mst_graph); max_e[root][0] = 0;
// 4. secondMST(mst_weight, edges, in_mst)
```

對每條非樹邊 e=(u,v,w')，加入後 MST 上 u→v 路徑形成環；刪去路徑上最大邊打破環，新生成樹總重為 `mstWeight - mx + w'`。若 `w' == mx` 表示換入換出等重，新舊生成樹總重相同，不計為**嚴格**次小生成樹（依題意調整）。

```cpp
// a: input array or sequence.
vector<int> nextGreater(const vector<int>& a) {
    int n = (int)a.size();
    vector<int> nge(n, n);
    stack<int> st;  // Indices with decreasing values
    for (int i = 0; i < n; i++) {
        while (!st.empty() && a[i] > a[st.top()]) {
            nge[st.top()] = i;
            st.pop();
        }
        st.push(i);
    }
    return nge;
}

vector<int> prevGreater(const vector<int>& a) {
    int n = (int)a.size();
    vector<int> pge(n, -1);
    stack<int> st;  // Indices with decreasing values
    for (int i = 0; i < n; i++) {
        while (!st.empty() && a[st.top()] <= a[i]) {
            st.pop();
        }
        if (!st.empty()) {
            pge[i] = st.top();
        }
        st.push(i);
    }
    return pge;
}
```
`nextGreater` 用的是**遞減 stack**：當 `a[i]` 比 stack top 大時，被彈出的下標就在這一刻找到最近右側更大值。`prevGreater` 則是對稱寫法：先把所有 `<= a[i]` 的舊候選移除，留下的 stack top 就是最近左側更大值。若題目改成「下一個更大或相等值」，只要把 `a[i] > a[st.top()]` 改成 `a[i] >= a[st.top()]`；嚴格與非嚴格比較的差異，決定了相等元素究竟要現在結算，還是保留給更後面的代表。

```cpp
const int kMod = 1'000'000'007;

// a: input array or sequence.
long long sumSubarrayMins(const vector<int>& a) {
    int n = (int)a.size();
    vector<long long> left(n), right(n);
    stack<int> st;

    for (int i = 0; i < n; i++) {
        while (!st.empty() && a[st.top()] >= a[i]) {
            st.pop();
        }
        int prev = st.empty() ? -1 : st.top();
        left[i] = i - prev;
        st.push(i);
    }

    while (!st.empty()) {
        st.pop();
    }

    for (int i = n - 1; i >= 0; i--) {
        while (!st.empty() && a[st.top()] > a[i]) {
            st.pop();
        }
        int next = st.empty() ? n : st.top();
        right[i] = next - i;
        st.push(i);
    }

    long long ans = 0;
    for (int i = 0; i < n; i++) {
        long long contrib = 1LL * a[i] * left[i] % kMod * right[i] % kMod;
        ans = (ans + contrib) % kMod;
    }
    return ans;
}
```
這裡的 `left[i]` 與 `right[i]` 不是邊界下標，而是「可以往左／往右延伸的選擇數」。左邊找**嚴格更小**、右邊找**小於等於**，會把含有多個相同最小值的子陣列唯一地分配給其中一個位置，避免重複計數。把每個 `a[i]` 的貢獻 `a[i] * left[i] * right[i]` 相加，就等價於把所有子陣列都數過一遍，但只需要兩次單調堆疊掃描。

```cpp
// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
vector<int> slidingMax(const vector<int>& a, int k) {
    int n = (int)a.size();
    if (k <= 0 || k > n) {
        return {};
    }

    deque<int> dq;  // Indices with decreasing values
    vector<int> ans;
    for (int i = 0; i < n; i++) {
        while (!dq.empty() && dq.front() <= i - k) {
            dq.pop_front();
        }
        while (!dq.empty() && a[dq.back()] <= a[i]) {
            dq.pop_back();
        }
        dq.push_back(i);
        if (i >= k - 1) {
            ans.push_back(a[dq.front()]);
        }
    }
    return ans;
}
```
兩個 `while` 各自處理不同邏輯：前者刪掉**過期**下標，後者刪掉被新元素**支配**的候選。當 `i >= k-1` 時，視窗才第一次完整，此後每次答案都直接是 `a[dq.front()]`。因為 deque 裡只保留可能成為未來答案的下標，所以不需要重新掃描整個視窗。

```cpp
// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
vector<int> slidingMin(const vector<int>& a, int k) {
    int n = (int)a.size();
    if (k <= 0 || k > n) {
        return {};
    }

    deque<int> dq;  // Indices with increasing values
    vector<int> ans;
    for (int i = 0; i < n; i++) {
        while (!dq.empty() && dq.front() <= i - k) {
            dq.pop_front();
        }
        while (!dq.empty() && a[dq.back()] >= a[i]) {
            dq.pop_back();
        }
        dq.push_back(i);
        if (i >= k - 1) {
            ans.push_back(a[dq.front()]);
        }
    }
    return ans;
}

// a: input array or sequence.
// limit: maximum allowed limit for the window condition.
int longestStableSubarray(const vector<int>& a, int limit) {
    deque<int> maxdq, mindq;
    int ans = 0, left = 0;
    for (int right = 0; right < (int)a.size(); right++) {
        while (!maxdq.empty() && a[maxdq.back()] <= a[right]) {
            maxdq.pop_back();
        }
        while (!mindq.empty() && a[mindq.back()] >= a[right]) {
            mindq.pop_back();
        }
        maxdq.push_back(right);
        mindq.push_back(right);

        while (!maxdq.empty() && !mindq.empty() &&
               1LL * a[maxdq.front()] - a[mindq.front()] > limit) {
            if (maxdq.front() == left) {
                maxdq.pop_front();
            }
            if (mindq.front() == left) {
                mindq.pop_front();
            }
            left++;
        }
        ans = max(ans, right - left + 1);
    }
    return ans;
}
```
`slidingMin` 只是把最大值版本的不等號全部反過來。進一步地，若同時維護一個最大值 deque 與一個最小值 deque，就能在雙指標移動時即時知道目前區間的 `max` 與 `min`；只要 `max - min` 超過限制，就把左端點右移直到重新合法。這是把「固定長度視窗」延伸到「可伸縮合法區間」的經典用法。

```cpp
// cost: current accumulated cost.
// k: limit, count, or window size used by the algorithm.
vector<long long> windowDP(const vector<int>& cost, int k) {
    int n = (int)cost.size();
    const long long kInf = (1LL << 60);
    vector<long long> dp(n, kInf);
    if (n == 0) {
        return dp;
    }

    dp[0] = 0;
    if (k <= 0) {
        return dp;
    }

    deque<int> dq;
    dq.push_back(0);
    for (int i = 1; i < n; i++) {
        while (!dq.empty() && dq.front() < i - k) {
            dq.pop_front();
        }

        if (!dq.empty()) {
            dp[i] = dp[dq.front()] + cost[i];
        }

        while (!dq.empty() && dp[dq.back()] >= dp[i]) {
            dq.pop_back();
        }
        if (dp[i] < kInf) {
            dq.push_back(i);
        }
    }
    return dp;
}
```
deque 內的下標依 `dp` 值遞增，所以 queue front 永遠是當前視窗最小 `dp[j]`。注意順序必須是：先刪過期、再**讀 queue front 算 `dp[i]`**、最後才把 `i` 放進 deque；這樣才能保證 `dp[i]` 只來自舊狀態，而不會誤用自己。若某個位置不可達，讓它維持 `INF` 並且不要入 deque 即可。

```cpp
struct Item {
    int weight, value, count;
};

// cap: capacity limit.
// items: items considered by the algorithm.
vector<long long> multipleKnapsack(int cap, const vector<Item>& items) {
    const long long kNeg = -(1LL << 60);
    vector<long long> dp(cap + 1, kNeg);
    dp[0] = 0;

    for (const Item& item : items) {
        vector<long long> old = dp;
        for (int r = 0; r < item.weight && r <= cap; r++) {
            deque<pair<int, long long>> dq;  // (t, adjusted value)
            for (int t = 0, j = r; j <= cap; t++, j += item.weight) {
                while (!dq.empty() && dq.front().first < t - item.count) {
                    dq.pop_front();
                }

                if (old[j] != kNeg) {
                    long long adjusted = old[j] - 1LL * t * item.value;
                    while (!dq.empty() && dq.back().second <= adjusted) {
                        dq.pop_back();
                    }
                    dq.push_back({t, adjusted});
                }

                dp[j] = dq.empty() ? kNeg : dq.front().second + 1LL * t * item.value;
            }
        }
    }
    return dp;
}
```
對固定餘數 `r = j mod w` 而言，所有容量 `j = r + t*w` 會形成一條一維序列。把轉移改寫成 `old[r+s*w] + (t-s)*value = (old[r+s*w] - s*value) + t*value` 之後，只要維護最近 `count+1` 個 `adjusted` 值的最大值即可，這正是一個滑動視窗最大值。這裡可以**先入 deque 再取答案**，因為放進去的是上一層快照 `old[j]`，不是本輪剛算出的 `dp[j]`，不會形成自我轉移。

```cpp
// h: input or working vector used by the algorithm.
int largestRectangle(const vector<int>& h) {
    int n = (int)h.size();
    stack<int> st;  // Indices with increasing heights
    long long ans = 0;

    for (int i = 0; i <= n; i++) {
        int cur = (i == n ? 0 : h[i]);
        while (!st.empty() && h[st.top()] > cur) {
            int idx = st.top();
            st.pop();
            int left = st.empty() ? -1 : st.top();
            long long width = i - left - 1;
            ans = max(ans, 1LL * h[idx] * width);
        }
        if (i < n) {
            st.push(i);
        }
    }
    return (int)ans;
}
```
這種寫法不需要先顯式求 `L[i]` 與 `R[i]`。當某根柱子被彈出時，`i` 就是它的右邊界，而**彈出後**的新 stack top 就是左邊界，所以可以立刻算寬度 `i-left-1`。尾端哨兵 `0` 只負責把 stack 清空，因此通常不需要真的把索引 `n` 放進 stack 裡。

```cpp
// h: input or working vector used by the algorithm.
int largestRectangle(const vector<int>& h) {
    int n = (int)h.size();
    stack<int> st;
    long long ans = 0;
    for (int i = 0; i <= n; i++) {
        int cur = (i == n ? 0 : h[i]);
        while (!st.empty() && h[st.top()] > cur) {
            int idx = st.top();
            st.pop();
            int left = st.empty() ? -1 : st.top();
            long long width = i - left - 1;
            ans = max(ans, 1LL * h[idx] * width);
        }
        if (i < n) {
            st.push(i);
        }
    }
    return (int)ans;
}

// matrix: adjacency list or 2D table used by the algorithm.
int maximalRectangle(const vector<vector<int>>& matrix) {
    if (matrix.empty() || matrix[0].empty()) {
        return 0;
    }

    int n = (int)matrix.size();
    int m = (int)matrix[0].size();
    vector<int> h(m, 0);
    int ans = 0;

    for (int r = 0; r < n; r++) {
        for (int c = 0; c < m; c++) {
            h[c] = (matrix[r][c] == 0 ? 0 : h[c] + 1);
        }
        ans = max(ans, largestRectangle(h));
    }
    return ans;
}
```
把每一列都視為「以當前列為底」的直方圖：若 `matrix[r][c] == 1`，高度就延續加一；若為 `0`，該欄高度立刻歸零。於是每掃完一列，就把這一列的高度陣列丟給直方圖最大矩形演算法。外層共有 `n` 列、內層每次 `O(m)`，總複雜度是 `O(nm)`。

```cpp
// x: value or node being processed.
int lowbit(int x) {
    return x & -x;
}

int n;
vector<long long> bit;

// idx: current recursion index.
// val: value being inserted, queried, or compared.
void update(int idx, long long val) {
    for (int i = idx; i <= n; i += lowbit(i)) {
        bit[i] += val;
    }
}

// idx: current recursion index.
long long query(int idx) {
    long long res = 0;
    for (int i = idx; i > 0; i -= lowbit(i)) {
        res += bit[i];
    }
    return res;
}

// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
long long rangeQuery(int l, int r) {
    return query(r) - query(l - 1);
}
```
`update` 會往上補到所有覆蓋 `idx` 的區塊；`query` 則把 `1..idx` 拆成若干個不重疊的責任區間後逐一累加。只要記住 `bit[i]` 代表 `[i - lowbit(i) + 1, i]`，就能理解為什麼更新向上跳、查詢向下拆。

```cpp
int n;
vector<long long> bit_diff;

// idx: current recursion index.
// delta: value added to the indexed position or range.
void diffUpdate(int idx, long long delta) {
    for (int i = idx; i <= n; i += i & -i) {
        bit_diff[i] += delta;
    }
}

// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
// val: value being inserted, queried, or compared.
void rangeAdd(int l, int r, long long val) {
    diffUpdate(l, val);
    if (r + 1 <= n) {
        diffUpdate(r + 1, -val);
    }
}

// idx: current recursion index.
long long pointQuery(int idx) {
    long long res = 0;
    for (int i = idx; i > 0; i -= i & -i) {
        res += bit_diff[i];
    }
    return res;
}
```
這裡 BIT 存的是差分陣列的前綴資訊，所以 `pointQuery(idx)` 其實是在還原原陣列第 `idx` 格的最終值。注意 `rangeAdd` 需要處理 `r + 1`，實作時通常會把 BIT 陣列多開一格，避免右端點卡在邊界。

```cpp
vector<long long> seg, a;

// node: segment tree node index.
void pushup(int node) {
    seg[node] = seg[node * 2] + seg[node * 2 + 1];
}

// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
void build(int node, int l, int r) {
    if (l == r) {
        seg[node] = a[l];
        return;
    }
    int mid = l + (r - l) / 2;
    build(node * 2, l, mid);
    build(node * 2 + 1, mid + 1, r);
    pushup(node);
}

// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
// ql: left boundary of the query range.
// qr: right boundary of the query range.
long long query(int node, int l, int r, int ql, int qr) {
    if (ql <= l && r <= qr) {
        return seg[node];
    }
    int mid = l + (r - l) / 2;
    long long ans = 0;
    if (ql <= mid) {
        ans += query(node * 2, l, mid, ql, qr);
    }
    if (qr > mid) {
        ans += query(node * 2 + 1, mid + 1, r, ql, qr);
    }
    return ans;
}
```
`build` 先把左右子區間建好，再由 `pushup` 合併，所以是典型的後序遞迴。查詢時只要遇到「完整包含」就立刻回傳，這正是線段樹能把大段區間直接剪掉的關鍵。

```cpp
// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
// pos: current position being constructed.
// val: value being inserted, queried, or compared.
void update(int node, int l, int r, int pos, long long val) {
    if (l == r) {
        seg[node] = val;
        return;
    }
    int mid = l + (r - l) / 2;
    if (pos <= mid) {
        update(node * 2, l, mid, pos, val);
    }
    else {
        update(node * 2 + 1, mid + 1, r, pos, val);
    }
    pushup(node);
}

// Example usage:
// update(1, 1, n, 5, 17); // Set a[5] = 17
```
因為只有一個位置被改動，所以遞迴時永遠只會走到其中一側子樹；真正重要的是回溯時一定要 `pushup`，把受影響的祖先區間答案全部重新合併回來。

```cpp
const long long kInf = (1LL << 62);
vector<long long> mn, b;

// node: segment tree node index.
void pushupMin(int node) {
    mn[node] = min(mn[node * 2], mn[node * 2 + 1]);
}

// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
void buildMin(int node, int l, int r) {
    if (l == r) {
        mn[node] = b[l];
        return;
    }
    int mid = l + (r - l) / 2;
    buildMin(node * 2, l, mid);
    buildMin(node * 2 + 1, mid + 1, r);
    pushupMin(node);
}

// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
// ql: left boundary of the query range.
// qr: right boundary of the query range.
long long queryMin(int node, int l, int r, int ql, int qr) {
    if (ql <= l && r <= qr) {
        return mn[node];
    }
    int mid = l + (r - l) / 2;
    long long res = kInf;
    if (ql <= mid) {
        res = min(res, queryMin(node * 2, l, mid, ql, qr));
    }
    if (qr > mid) {
        res = min(res, queryMin(node * 2 + 1, mid + 1, r, ql, qr));
    }
    return res;
}
```
把 `sum` 換成 `min` 後，整棵樹的骨架完全不變；這說明線段樹真正要求的是「左右答案能被穩定合併」。常見的 `sum/min/max/gcd` 都能直接套同一套遞迴框架。

```cpp
vector<long long> tree, lazy, a;

// node: segment tree node index.
void pushup(int node) {
    tree[node] = tree[node * 2] + tree[node * 2 + 1];
}

// node: segment tree node index.
// len: length of the segment represented by node.
// val: value being inserted, queried, or compared.
void applyLazy(int node, int len, long long val) {
    tree[node] += val * len;
    lazy[node] += val;
}

// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
void build(int node, int l, int r) {
    if (l == r) {
        tree[node] = a[l];
        return;
    }
    int mid = l + (r - l) / 2;
    build(node * 2, l, mid);
    build(node * 2 + 1, mid + 1, r);
    pushup(node);
}

// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
void pushdown(int node, int l, int r) {
    if (lazy[node] == 0 || l == r) {
        return;
    }
    int mid = l + (r - l) / 2;
    applyLazy(node * 2, mid - l + 1, lazy[node]);
    applyLazy(node * 2 + 1, r - mid, lazy[node]);
    lazy[node] = 0;
}

// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
// ql: left boundary of the query range.
// qr: right boundary of the query range.
// val: value being inserted, queried, or compared.
void rangeAdd(int node, int l, int r, int ql, int qr, long long val) {
    if (ql <= l && r <= qr) {
        applyLazy(node, r - l + 1, val);
        return;
    }
    pushdown(node, l, r);
    int mid = l + (r - l) / 2;
    if (ql <= mid) {
        rangeAdd(node * 2, l, mid, ql, qr, val);
    }
    if (qr > mid) {
        rangeAdd(node * 2 + 1, mid + 1, r, ql, qr, val);
    }
    pushup(node);
}

// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
// ql: left boundary of the query range.
// qr: right boundary of the query range.
long long rangeQuery(int node, int l, int r, int ql, int qr) {
    if (ql <= l && r <= qr) {
        return tree[node];
    }
    pushdown(node, l, r);
    int mid = l + (r - l) / 2;
    long long ans = 0;
    if (ql <= mid) {
        ans += rangeQuery(node * 2, l, mid, ql, qr);
    }
    if (qr > mid) {
        ans += rangeQuery(node * 2 + 1, mid + 1, r, ql, qr);
    }
    return ans;
}
```
`applyLazy` 必須同時更新目前節點的答案與待下推標記，這樣 `tree[node]` 才會永遠保持正確。真正的關鍵在 `pushdown`：任何要進子樹的操作，都要先把父節點欠下的修改補發給左右孩子。

```cpp
vector<long long> treeA, assign_lazy;
const long long kNoTag = LLONG_MIN;

// node: segment tree node index.
// len: length of the segment represented by node.
// val: value being inserted, queried, or compared.
void applyAssign(int node, int len, long long val) {
    treeA[node] = val * len;
    assign_lazy[node] = val;
}

// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
void pushdownA(int node, int l, int r) {
    if (assign_lazy[node] == kNoTag || l == r) {
        return;
    }
    int mid = l + (r - l) / 2;
    applyAssign(node * 2, mid - l + 1, assign_lazy[node]);
    applyAssign(node * 2 + 1, r - mid, assign_lazy[node]);
    assign_lazy[node] = kNoTag;
}

// node: segment tree node index.
// l: left boundary or endpoint.
// r: right boundary, row, or endpoint.
// ql: left boundary of the query range.
// qr: right boundary of the query range.
// val: value being inserted, queried, or compared.
void rangeAssign(int node, int l, int r, int ql, int qr, long long val) {
    if (ql <= l && r <= qr) {
        applyAssign(node, r - l + 1, val);
        return;
    }
    pushdownA(node, l, r);
    int mid = l + (r - l) / 2;
    if (ql <= mid) {
        rangeAssign(node * 2, l, mid, ql, qr, val);
    }
    if (qr > mid) {
        rangeAssign(node * 2 + 1, mid + 1, r, ql, qr, val);
    }
    treeA[node] = treeA[node * 2] + treeA[node * 2 + 1];
}
```
區間賦值不是「累加」而是「覆蓋」，所以不能再用 `0` 當作沒有標記的哨兵值。這種情況通常要額外維護 `NO_TAG` 或布林旗標，表示目前節點是否有待下推的賦值操作。

```cpp
// a: input array or sequence.
vector<int> compress(const vector<long long>& a) {
    vector<long long> vals = a;
    sort(vals.begin(), vals.end());
    vals.erase(unique(vals.begin(), vals.end()), vals.end());

    vector<int> rank(a.size());
    for (int i = 0; i < (int)a.size(); i++) {
        rank[i] = int(lower_bound(vals.begin(), vals.end(), a[i]) - vals.begin()) + 1;
    }
    return rank;
}
```
排序加去重可以保證相同值映到同一個 rank，而最後的 `+1` 是為了配合 BIT 的 1-based 下標。壓縮完後，不論原值是負數還是 `10^9`，都只會落在 `1..m` 的緊密範圍內。

```cpp
struct Fenwick {
    int n;
    vector<int> bit;

    // n: number of nodes or elements.
    Fenwick(int n) : n(n), bit(n + 1, 0) {}

    // idx: current recursion index.
    // delta: value added to the indexed position or range.
    void add(int idx, int delta = 1) {
        for (int i = idx; i <= n; i += i & -i) {
            bit[i] += delta;
        }
    }

    // idx: current recursion index.
    int query(int idx) const {
        int res = 0;
        for (int i = idx; i > 0; i -= i & -i) {
            res += bit[i];
        }
        return res;
    }
};

// a: input array or sequence.
long long countInversions(const vector<long long>& a) {
    vector<int> r = compress(a);
    int m = 0;
    for (int x : r) {
        m = max(m, x);
    }
    Fenwick fw(m);
    long long inv = 0;
    for (int i = 0; i < (int)a.size(); i++) {
        inv += i - fw.query(r[i]);  // Count previous elements > a[i]
        fw.add(r[i]);
    }
    return inv;
}
```
第 `i` 步以前，BIT 裡已經放了前面 `i` 個元素；其中 `fw.query(r[i])` 代表「小於等於目前值」的數量，所以兩者相減就是嚴格大於 `a[i]` 的個數。若改成從右往左掃描，也能等價地統計「右側比自己小」的元素數。

```cpp
// Single-source shortest path with priority_queue (lazy deletion)
// src: source node index.
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
vector<long long> dijkstra(int src, int n, const vector<vector<pair<int, int>>>& g) {
    const long long kInf = 1e18;
    vector<long long> dist(n, kInf);
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    dist[src] = 0;
    pq.push({0, src});
    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();
        if (d > dist[u]) {
            continue;  // Lazy deletion: skip outdated entry
        }
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});  // Push updated distance
            }
        }
    }
    return dist;
}
```

**懶惰刪除**是關鍵：`if (d > dist[u]) continue;` 這行讓已被更短路取代的堆項目直接被丟棄，不做多餘的鬆弛。邊權必須非負，否則已出堆的節點仍可能被更新，Dijkstra 不再正確。

```cpp
// Dijkstra with path reconstruction using parent array
// src: source node index.
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
pair<vector<long long>, vector<int>> dijkstraPath(int src, int n,
                                                  const vector<vector<pair<int, int>>>& g) {
    const long long kInf = 1e18;
    vector<long long> dist(n, kInf);
    vector<int> prev(n, -1);  // Parent in shortest path tree
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    dist[src] = 0;
    pq.push({0, src});
    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();
        if (d > dist[u]) {
            continue;
        }
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                prev[v] = u;  // Record parent
                pq.push({dist[v], v});
            }
        }
    }
    return {dist, prev};
}

// Reconstruct path from src to dst
// prev: input or working vector used by the algorithm.
// dst: destination node index.
vector<int> getPath(const vector<int>& prev, int dst) {
    vector<int> path;
    for (int cur = dst; cur != -1; cur = prev[cur]) {
        path.push_back(cur);
    }
    reverse(path.begin(), path.end());
    return path;
}
```

用 `prev[]` 陣列記錄每個節點在最短路樹中的父節點，從目的地往回追溯即可重建路徑。注意若 `dist[dst] == INF` 表示不可達，`prev[]` 追溯無意義。

```cpp
// Multi-source Dijkstra: find shortest distance from any source
// sources: input or working vector used by the algorithm.
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
vector<long long> multiSourceDijkstra(const vector<int>& sources, int n,
                                      const vector<vector<pair<int, int>>>& g) {
    const long long kInf = 1e18;
    vector<long long> dist(n, kInf);
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    for (int s : sources) {
        dist[s] = 0;
        pq.push({0, s});  // Initialize all sources with distance 0
    }
    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();
        if (d > dist[u]) {
            continue;
        }
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}
```

**多源 Dijkstra** 的做法是把所有源點同時以距離 0 放入堆，等價於建一個超級源點連接所有源點（邊權 0）後跑單源 Dijkstra。常用於「最近設施距離」類問題。

```cpp
// Floyd-Warshall all-pairs shortest path
// dist[i][j] must be initialized: 0 if i==j, edge weight if direct edge, kInf otherwise
const long long kInf = 1e18;
// dist: dynamic programming or distance array.
// n: number of nodes or elements.
void floydWarshall(vector<vector<long long>>& dist, int n) {
    for (int k = 0; k < n; k++) {  // Intermediate node (MUST be outermost)
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (dist[i][k] < kInf && dist[k][j] < kInf) {  // Avoid overflow
                    dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]);
                }
            }
        }
    }
}

// Negative cycle detection after Floyd-Warshall.
// If dist[i][i] < 0 for any i, a negative cycle exists.
// dist: 2D container or adjacency structure used by the algorithm.
// n: number of nodes or elements.
bool hasNegCycle(const vector<vector<long long>>& dist, int n) {
    for (int i = 0; i < n; i++) {
        if (dist[i][i] < 0) {
            return true;
        }
    }
    return false;
}
```

**負環偵測**：若跑完 Floyd-Warshall 後 `dist[i][i] < 0`，表示從 i 出發繞一圈回到 i 有負收益，即負環存在。`dist[i][k] < INF && dist[k][j] < INF` 的判斷可避免 INF 加上負數產生偽更新。

```cpp
// Path reconstruction using next-hop matrix
// dist: shortest-path distance matrix.
// nxt: next-hop matrix; nxt[i][j] stores the first node after i on the path to j.
// n: number of nodes.
void floydWithPath(vector<vector<long long>>& dist, vector<vector<int>>& nxt, int n) {
    // Initialize nxt[i][j] = j if direct edge, -1 otherwise
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            nxt[i][j] = (i != j && dist[i][j] < kInf) ? j : -1;
        }
    }

    for (int k = 0; k < n; k++) {
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (dist[i][k] < kInf && dist[k][j] < kInf &&
                    dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                    nxt[i][j] = nxt[i][k];  // First step toward j is same as toward k
                }
            }
        }
    }
}

// Retrieve actual path from src to dst
// nxt: next-hop matrix produced by floydWithPath.
// src: source node index.
// dst: destination node index.
vector<int> getPath(const vector<vector<int>>& nxt, int src, int dst) {
    if (nxt[src][dst] == -1) {
        return {};  // No path
    }
    vector<int> path = {src};
    while (src != dst) {
        src = nxt[src][dst];
        path.push_back(src);
    }
    return path;
}
```

`nxt[i][j]` 記錄「從 i 到 j 的最短路，下一步走哪個節點」。每次 i→j 的路徑更新為經過 k 時，`nxt[i][j]` 繼承 `nxt[i][k]`——因為 i 先朝 k 方向走。重建時沿 nxt 跳到終點即可，複雜度 O(路徑長度)。

```cpp
// Transitive closure: reach[i][j] = true if j is reachable from i
// reach: input or working vector used by the algorithm.
// n: number of nodes or elements.
void transitiveClosure(vector<bitset<500>>& reach, int n) {
    for (int k = 0; k < n; k++) {
        for (int i = 0; i < n; i++) {
            if (reach[i][k]) {
                reach[i] |= reach[k];  // Bitset OR: O(n/64) per inner step
            }
        }
    }
}
```

用 `bitset` 取代 `bool reach[n][n]`，Floyd 的內層操作改為 `reach[i] |= reach[k]`，一次位元運算處理 64 個 j，整體複雜度降至 **O(V³/64)**。當 V ≤ 10000 且只需求可達性時非常高效。

```cpp
// 0-1 BFS: edge weights must be exactly 0 or 1
// src: source node index.
// n: number of nodes or elements.
// g: grid or adjacency structure used by the algorithm.
vector<int> bfs01(int src, int n, const vector<vector<pair<int, int>>>& g) {
    const int kInf = 1e9;
    vector<int> dist(n, kInf);
    deque<int> dq;
    dist[src] = 0;
    dq.push_back(src);
    while (!dq.empty()) {
        int u = dq.front();
        dq.pop_front();
        for (auto [v, w] : g[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                if (w == 0) {
                    dq.push_front(v);  // 0-cost: same layer, process first
                }
                else {
                    dq.push_back(v);  // 1-cost: next layer, process later
                }
            }
        }
    }
    return dist;
}
```

與普通 BFS 的唯一差異：依邊權決定推入 deque 的前端或後端。權 0 的邊不增加距離，新節點應優先處理（推前端）；權 1 的邊類似普通 BFS 的下一層（推後端）。不需要 `visited[]` 陣列——`dist[u] + w < dist[v]` 作為更新條件，已達最優的節點不會再被更新。

```cpp
// Grid shortest path: moving to '#' costs 1, '.' costs 0
// grid: input or working vector used by the algorithm.
// src: source node index.
// dst: destination node index.
int gridMin01Bfs(vector<string>& grid, pair<int, int> src, pair<int, int> dst) {
    int rowCount = grid.size(), col_count = grid[0].size();
    vector<vector<int>> dist(rowCount, vector<int>(col_count, INT_MAX));
    deque<pair<int, int>> dq;
    dist[src.first][src.second] = 0;
    dq.push_back(src);
    const int dx[] = {0, 0, 1, -1}, dy[] = {1, -1, 0, 0};
    while (!dq.empty()) {
        auto [x, y] = dq.front();
        dq.pop_front();
        for (int d = 0; d < 4; d++) {
            int nx = x + dx[d], ny = y + dy[d];
            if (nx < 0 || nx >= rowCount || ny < 0 || ny >= col_count) {
                continue;
            }
            int cost = (grid[nx][ny] == '#') ? 1 : 0;  // Obstacle costs 1
            if (dist[x][y] + cost < dist[nx][ny]) {
                dist[nx][ny] = dist[x][y] + cost;
                if (cost == 0) {
                    dq.push_front({nx, ny});
                }
                else {
                    dq.push_back({nx, ny});
                }
            }
        }
    }
    return dist[dst.first][dst.second];
}
```

0-1 BFS 最常見的應用場景：**網格最短路**。當「穿越某種格子」、「換方向」或「使用特殊移動」有 0/1 費用差異時，直接套用。解題關鍵在於識別「哪些操作費用為 0，哪些為 1」，然後建圖跑 0-1 BFS。

```cpp
// dp[v][0] = max value in subtree of v, NOT selecting v
// dp[v][1] = max value in subtree of v, selecting v
vector<int> val;
vector<vector<int>> adj;
vector<array<int, 2>> dp;

// v: neighbor node or right endpoint.
// par: parent node.
void dfs(int v, int par) {
    dp[v][0] = 0;
    dp[v][1] = val[v];
    for (int c : adj[v]) {
        if (c == par) {
            continue;
        }
        dfs(c, v);
        dp[v][1] += dp[c][0];                 // Select v: children must not be selected
        dp[v][0] += max(dp[c][0], dp[c][1]);  // Unselect v: each child is free
    }
}

// root: root node.
int solve(int root) {
    dfs(root, -1);
    return max(dp[root][0], dp[root][1]);
}
```

此為「洛谷 P1352 沒有上司的舞會」的標準解法。`val[v]` 為員工的快樂值（可以為負），樹根任取。每個節點只被訪問一次，合併每個子節點為 O(1)，整棵樹的時間複雜度為 O(n)。

```cpp
// Unweighted max independent set; min vertex cover = n - max_independent_set
vector<vector<int>> adj;
vector<array<int, 2>> dp;

// v: neighbor node or right endpoint.
// par: parent node.
void dfs(int v, int par) {
    dp[v][0] = 0;
    dp[v][1] = 1;  // Count node v itself
    for (int c : adj[v]) {
        if (c == par) {
            continue;
        }
        dfs(c, v);
        dp[v][1] += dp[c][0];                 // Select v: children unselected
        dp[v][0] += max(dp[c][0], dp[c][1]);  // Unselect v: children are free
    }
}

// Minimum vertex cover = n - max independent set size
// root: root node.
// n: number of nodes or elements.
int minVertexCover(int root, int n) {
    dp.assign(n + 1, {0, 0});
    dfs(root, -1);
    return n - max(dp[root][0], dp[root][1]);
}
```

**最小頂點覆蓋**（每條邊至少有一端被選）與最大獨立集互補：在樹上，最小頂點覆蓋大小 = n − 最大獨立集大小。可直接利用上述 DP 結果計算，無需重新建模。

```cpp
// For each node v, compute the farthest distance from v to any other node
vector<vector<pair<int, int>>> adj;  // adj[v] = {(neighbor, weight)}
vector<long long> down, ans;

// First DFS: down[v] = max distance from v downward into its subtree
// v: neighbor node or right endpoint.
// par: parent node.
void dfs1(int v, int par) {
    down[v] = 0;
    for (auto [c, w] : adj[v]) {
        if (c == par) {
            continue;
        }
        dfs1(c, v);
        down[v] = max(down[v], down[c] + (long long)w);
    }
}

// Second DFS: propagate up_val = best distance reachable via parent direction
// v: neighbor node or right endpoint.
// par: parent node.
// up_val: best value propagated from the parent side.
void dfs2(int v, int par, long long up_val) {
    ans[v] = max(down[v], up_val);
    // Gather max1/max2 over children (and up_val) to exclude each child in turn
    long long max1 = up_val, max2 = up_val;
    int src1 = -1;  // Which child achieves max1 among children
    for (auto [c, w] : adj[v]) {
        if (c == par) {
            continue;
        }
        long long val = down[c] + w;
        if (val >= max1) {
            max2 = max1;
            max1 = val;
            src1 = c;
        } else if (val > max2) {
            max2 = val;
        }
    }
    for (auto [c, w] : adj[v]) {
        if (c == par) {
            continue;
        }
        long long best = (c == src1) ? max2 : max1;  // Exclude c's contribution
        dfs2(c, v, best + w);
    }
}

// n: number of nodes or elements.
void rerooting(int n) {
    down.assign(n, 0);
    ans.assign(n, 0);
    dfs1(0, -1);
    dfs2(0, -1, 0);
}
```

`dfs2` 中，若子節點 c 正是使父節點 `down` 達到最大的來源，則傳給 c 的 `best` 改用次大值 `max2`，防止 c 透過自身子樹反饋造成循環。`max1/max2` 以 `upVal` 為初始值，表示父方向永遠是備選路線。

```cpp
// For each node v as root, compute sum of distances to all other nodes
vector<vector<int>> adj;
vector<long long> dist_sum;  // dist_sum[v] = sum dist(v, u) for all u != v
vector<int> sz;              // sz[v] = subtree size rooted at 0
int n;

// v: neighbor node or right endpoint.
// par: parent node.
void dfs1(int v, int par) {
    sz[v] = 1;
    dist_sum[v] = 0;
    for (int c : adj[v]) {
        if (c == par) {
            continue;
        }
        dfs1(c, v);
        sz[v] += sz[c];
        dist_sum[v] += dist_sum[c] + sz[c];  // Each node in c's subtree is 1 farther
    }
}

// v: neighbor node or right endpoint.
// par: parent node.
void dfs2(int v, int par) {
    for (int c : adj[v]) {
        if (c == par) {
            continue;  // Re-root v -> c: sz[c] nodes 1 closer, (n - sz[c]) nodes 1 farther
        }
        dist_sum[c] = dist_sum[v] - sz[c] + (n - sz[c]);
        int saved_size = sz[c];
        sz[c] = n - saved_size;  // c's subtree from c's root = rest of tree
        dfs2(c, v);
        sz[c] = saved_size;  // Restore for siblings
    }
}

// _n: number of nodes or elements.
void allDistSums(int _n) {
    n = _n;
    sz.assign(n, 0);
    dist_sum.assign(n, 0);
    dfs1(0, -1);
    dfs2(0, -1);
}
```

換根後，子節點 c 的距離總和可從父節點 O(1) 推出：子樹中 `sz[c]` 個節點各縮短 1，樹中其餘 `n − sz[c]` 個節點各增加 1，因此 `distSum[c] = distSum[v] + n − 2*sz[c]`。此公式是換根 DP 最常見的範例，對應 LeetCode 834「樹中距離之和」。

```cpp
// Two-DFS method: correct only for non-negative edge weights
vector<vector<pair<int, int>>> adj;  // adj[v] = {(neighbor, weight)}

// v: neighbor node or right endpoint.
// par: parent node.
// dist: current distance value or distance table.
// max_dist: current best/farthest distance.
// farthest: node achieving the current best distance.
void dfs(int v, int par, long long dist, long long& max_dist, int& farthest) {
    if (dist > max_dist) {
        max_dist = dist;
        farthest = v;
    }
    for (auto [c, w] : adj[v]) {
        if (c == par) {
            continue;
        }
        dfs(c, v, dist + w, max_dist, farthest);
    }
}

long long treeDiameterTwoDFS() {
    long long max_dist = 0;
    int u = 0;
    dfs(0, -1, 0, max_dist, u);  // First DFS: find endpoint u
    max_dist = 0;
    int v = 0;
    dfs(u, -1, 0, max_dist, v);  // Second DFS: find other endpoint v
    return max_dist;             // u-v distance = diameter
}
```

正確性依賴一個引理：**無負邊樹中，從任意節點出發最遠的節點必然是某條最長路徑的端點。**注意此方法在**有負邊**時不正確——負邊可能縮短從某節點到遠端的路徑，第一次 DFS 找到的 u 可能並非直徑端點。

```cpp
// Tree DP method: correct for all edge weights including negative
vector<vector<pair<int, int>>> adj;
vector<long long> down;
long long diameter;

// v: neighbor node or right endpoint.
// par: parent node.
void dfs(int v, int par) {
    down[v] = 0;
    for (auto [c, w] : adj[v]) {
        if (c == par) {
            continue;
        }
        dfs(c, v);  // Must update diameter BEFORE updating down[v] to avoid double-counting
        diameter = max(diameter, down[v] + down[c] + (long long)w);
        down[v] = max(down[v], down[c] + (long long)w);
    }
}

// n: number of nodes or elements.
long long treeDiameterDP(int n) {
    down.assign(n, 0);
    diameter = 0;  // 0 = empty path (single node)
    dfs(0, -1);
    return diameter;
}
```

合併過程中，`down[v]` 始終代表「已處理的子節點中最長的下行鏈」，每新加入一個子節點 c 就嘗試把「舊的最長鏈 + c 方向的鏈」合併為直徑候選。初始 `diameter = 0` 表示允許直徑為單一節點（長度 0）；若所有邊權為負且需要找嚴格最長路，應改初始值為 `LLONG_MIN` 並在計算後加判斷。

```cpp
// dp[v][j] = max value selecting exactly j nodes from subtree of v
// j = 0: select nothing; j >= 1: must include v itself in the count
vector<int> val;
vector<vector<int>> adj;
vector<vector<int>> dp;
vector<int> sz;
int cap;  // knapsack capacity

// v: neighbor node or right endpoint.
// par: parent node.
void dfs(int v, int par) {
    sz[v] = 1;
    dp[v].assign(cap + 1, 0);
    dp[v][1] = val[v];  // Select only node v
    for (int c : adj[v]) {
        if (c == par) {
            continue;
        }
        dfs(c, v);  // Merge child c into v; iterate j in reverse to stay in-place
        for (int j = min(sz[v], cap); j >= 0; j--) {
            for (int k = 1; k <= min(sz[c], cap - j); k++) {
                dp[v][j + k] = max(dp[v][j + k], dp[v][j] + dp[c][k]);
            }
        }
        sz[v] += sz[c];  // Update subtree size AFTER merging
    }
}

// root: root node.
// n: number of nodes or elements.
// _K: requested selection limit.
int treeKnapsack(int root, int n, int _K) {
    cap = _K;
    dp.assign(n + 1, {});
    sz.assign(n + 1, 0);
    dfs(root, -1);
    int ans = 0;
    for (int j = 0; j <= cap; j++) {
        ans = max(ans, dp[root][j]);
    }
    return ans;
}
```

**j 的上界必須使用 `sz[v]`**（合併 c 之前的子樹大小），而非 K。這是保證 O(nK) 複雜度的關鍵：合併時 `sz[v] × sz[c]` 的工作量，在整棵樹上加總等於所有節點對在各自 LCA 的貢獻次數，總計 O(n²)。當 K < n 時，`min(sz[v], K)` 進一步把複雜度限制在 O(nK)。

```cpp
// Course selection: selecting course c requires selecting its prerequisite parent
// Build a virtual root connected to all roots of prerequisite trees
// dp[v][j] = max value taking j courses from subtree of v (v must be taken if j>=1)
vector<int> val;
vector<vector<int>> adj;  // prerequisite tree + virtual root 0
vector<vector<int>> dp;
vector<int> sz;
int K;

// v: neighbor node or right endpoint.
// par: parent node.
void dfs(int v, int par) {
    sz[v] = 1;
    dp[v].assign(K + 2, 0);
    if (v != 0) {
        dp[v][1] = val[v];  // Must select v to take any child
    }
    for (int c : adj[v]) {
        if (c == par) {
            continue;
        }
        dfs(c, v);
        for (int j = min(sz[v], K + 1); j >= (v != 0 ? 1 : 0); j--) {
            for (int k = 1; k <= min(sz[c], K + 1 - j); k++) {
                dp[v][j + k] = max(dp[v][j + k], dp[v][j] + dp[c][k]);
            }
        }
        sz[v] += sz[c];
    }
}

// n: number of nodes or elements.
// _K: requested selection limit.
int courseSelection(int n, int _K) {
    K = _K;  // Select at most K non-root courses
    dp.assign(n + 1, {});
    sz.assign(n + 1, 0);
    dfs(0, -1);           // Virtual root 0
    return dp[0][K + 1];  // +1 accounts for the virtual root not counted
}
```

「洛谷 P2014 選課」問題要求：選某門課前必須先選其先修課（樹狀依賴）。做法是建立虛擬根節點 0，所有無先修課的課程連到 0，利用「選 j 個子樹節點時 v 必須被選（j≥1）」的約束直接套用樹上背包框架。

以**兩數之和（有序版）**為例，`left` 指向最小值，`right` 指向最大值，根據當前和調整指針方向；**三數之和**先排序，外層固定最小元素，內層對其右側用對撞指針：

```cpp
// Two-sum on sorted array: returns 0-indexed pair
// a: input array or sequence.
// target: target value or remaining target to satisfy.
pair<int, int> twoSumSorted(const vector<int>& a, int target) {
    int l = 0, r = (int)a.size() - 1;
    while (l < r) {
        int s = a[l] + a[r];
        if (s == target) {
            return {l, r};
        }
        else if (s < target) {
            l++;  // Sum too small, advance left
        }
        else {
            r--;  // Sum too large, retreat right
        }
    }
    return {-1, -1};
}

// 3Sum: all unique triplets summing to 0
// a: input array or sequence.
vector<array<int, 3>> threeSum(vector<int> a) {
    sort(a.begin(), a.end());
    vector<array<int, 3>> res;
    int n = a.size();
    for (int i = 0; i < n - 2; i++) {
        if (i > 0 && a[i] == a[i - 1]) {
            continue;  // Skip duplicate pivot
        }
        int l = i + 1, r = n - 1;
        while (l < r) {
            int s = a[i] + a[l] + a[r];
            if (s == 0) {
                res.push_back({a[i], a[l], a[r]});
                while (l < r && a[l] == a[l + 1]) {
                    l++;  // Skip duplicates before advancing
                }
                while (l < r && a[r] == a[r - 1]) {
                    r--;
                }
                l++;
                r--;
            } else if (s < 0) {
                l++;
            }
            else {
                r--;
            }
        }
    }
    return res;
}
```

三數之和去重有兩個層級：外層跳過相同的 `a[i]`（`i > 0 && a[i] == a[i-1]`），內層在找到答案後跳過 `l`、`r` 的連續重複值，確保結果集無重複三元組。

兩題都是對撞指針，但維護的信息不同：**盛最多水**每次移動矮端；**接雨水**需要維護左右兩側的歷史最大高度。

```cpp
// Container with most water (LeetCode 11)
// h: input or working vector used by the algorithm.
int maxWater(const vector<int>& h) {
    int l = 0, r = (int)h.size() - 1, ans = 0;
    while (l < r) {
        ans = max(ans, min(h[l], h[r]) * (r - l));
        if (h[l] < h[r]) {
            l++;  // Move the shorter side inward
        }
        else {
            r--;
        }
    }
    return ans;
}

// Trapping rain water (LeetCode 42)
// h: hash helper used for substring comparisons.
int trap(const vector<int>& h) {
    int l = 0, r = (int)h.size() - 1;
    int left_max = 0, right_max = 0, ans = 0;
    while (l < r) {
        if (h[l] < h[r]) {
            left_max = max(left_max, h[l]);
            ans += left_max - h[l];  // Water level at l determined by left_max
            l++;
        } else {
            right_max = max(right_max, h[r]);
            ans += right_max - h[r];  // Water level at r determined by right_max
            r--;
        }
    }
    return ans;
}
```

接雨水的正確性：處理 `l` 時，因為 `h[l] < h[r]`，可知 `rightMax >= h[r] > h[l]`，故瓶頸一定在左側 `leftMax`，水量計算不依賴尚未掃到的右半邊。

以**最長無重複字元子字串**（LeetCode 3）示範「最長」模板，以**最短覆蓋子字串**（LeetCode 76）示範「最短」模板：

```cpp
// Longest substring without repeating characters (LeetCode 3)
// s: input string.
int lengthOfLongestSubstring(const string& s) {
    int n = s.size(), ans = 0, left = 0;
    unordered_map<char, int> freq;
    for (int right = 0; right < n; right++) {
        freq[s[right]]++;
        while (freq[s[right]] > 1) {  // Window invalid: duplicate exists
            if (--freq[s[left]] == 0) {
                freq.erase(s[left]);
            }
            left++;
        }
        ans = max(ans, right - left + 1);  // Update after shrinking
    }
    return ans;
}

// Minimum window substring (LeetCode 76)
// s: input string.
// t: target/end value.
string minWindow(const string& s, const string& t) {
    unordered_map<char, int> need, have;
    for (char c : t) {
        need[c]++;
    }
    int formed = 0, required = (int)need.size();
    int left = 0, min_len = INT_MAX, min_start = 0;
    for (int right = 0; right < (int)s.size(); right++) {
        have[s[right]]++;
        // Check if this character type is now fully covered
        if (need.count(s[right]) && have[s[right]] == need[s[right]]) {
            formed++;
        }
        while (formed == required) {  // Window valid: try shrinking
            if (right - left + 1 < min_len) {
                min_len = right - left + 1;
                min_start = left;
            }
            if (need.count(s[left]) && --have[s[left]] < need[s[left]]) {
                formed--;
            }
            else {
                have[s[left]]--;
            }
            left++;
        }
    }
    return min_len == INT_MAX ? "" : s.substr(min_start, min_len);
}
```

**最長**：先擴張 `right`，不合法時縮左，合法後更新答案（答案在循環末尾更新）。**最短**：擴張直到合法，然後在 while 內持續縮左並更新答案，離開 while 後視窗恢復不合法狀態。

`atMost(k)` 統計每個 `right` 對應的合法起點數量（即以 `right` 結尾、以 `[left..right]` 內任一點為起點的合法子陣列數 `right - left + 1`），累加即得所有「最多 K 個不同值」的子陣列數。`atMost(K) - atMost(K-1)` 容斥得「恰好 K 個」：

```cpp
// Count subarrays with at most k distinct integers
// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
int atMost(const vector<int>& a, int k) {
    if (k < 0) {
        return 0;  // Guard for atMost(-1) call
    }
    int n = a.size(), left = 0, ans = 0;
    unordered_map<int, int> freq;
    for (int right = 0; right < n; right++) {
        freq[a[right]]++;
        while ((int)freq.size() > k) {  // Too many distinct values
            if (--freq[a[left]] == 0) {
                freq.erase(a[left]);
            }
            left++;
        }
        ans += right - left + 1;  // All subarrays ending at right are valid
    }
    return ans;
}

// Count subarrays with exactly k distinct integers (LeetCode 992)
// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
int exactlyK(const vector<int>& a, int k) {
    return atMost(a, k) - atMost(a, k - 1);
}
```

此技巧適用於所有「恰好 K 次滿足某條件」且可轉化為「最多」計數的問題，例如「恰好 K 個奇數的子陣列」、「恰好翻轉 K 次的子字串」等。

```cpp
struct ListNode {
    int val;
    ListNode* next;
};

// Returns the meeting node inside the cycle, or nullptr if no cycle
// head: head node of the linked list.
ListNode* detectCycleMeet(ListNode* head) {
    ListNode* slow = head;
    ListNode* fast = head;
    while (fast && fast->next) {  // Must check both before advancing
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast) {
            return slow;  // Meeting point found inside cycle
        }
    }
    return nullptr;  // No cycle: fast reached the end
}

// head: head node of the linked list.
bool hasCycle(ListNode* head) {
    return detectCycleMeet(head) != nullptr;
}
```

`while` 條件必須同時檢查 `fast != nullptr` 與 `fast->next != nullptr`，確保 `fast->next->next` 的存取安全。相遇點在環內某處，**不是**環入口，不可直接回傳為答案。

相遇後，令一個指針從 `head` 出發、另一個留在相遇點，兩者都以速度 1 前進，再次相遇處即為環入口：

```cpp
// Find the entry (start) node of the cycle; returns nullptr if no cycle
// head: head node of the linked list.
ListNode* findCycleEntry(ListNode* head) {
    ListNode* meet = detectCycleMeet(head);
    if (!meet) {
        return nullptr;
    }

    ListNode* p1 = head;  // Reset to head
    ListNode* p2 = meet;  // Stay at meeting point
    while (p1 != p2) {
        p1 = p1->next;  // Both move at speed 1
        p2 = p2->next;
    }
    return p1;  // Cycle entry node
}
```

數學保證：`a = kc - b`。`p1` 從 `head` 走 `a` 步到達入口；`p2` 從相遇點（入口後 `b` 步）走 `a = kc - b` 步，位置為 `b + kc - b = kc ≡ 0`（模 c），恰好回到入口。兩者同時到達，第一次相遇即為環入口。

奇偶長度下「中點」定義不同，需依是否要左中點選擇 `fast` 的起始位置：

```cpp
// Right-middle for even length (fast starts at head)
// head: head node of the linked list.
ListNode* findMiddle(ListNode* head) {
    ListNode *slow = head, *fast = head;
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
    }
    return slow;
}

// Left-middle for even length (fast starts one step ahead)
// head: head node of the linked list.
ListNode* findLeftMiddle(ListNode* head) {
    ListNode *slow = head, *fast = head->next;
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
    }
    return slow;
}

// Merge two sorted lists
// l1: left index of the first interval/string segment.
// l2: left index of the second interval/string segment.
ListNode* merge(ListNode* l1, ListNode* l2) {
    ListNode dummy(0);
    ListNode* cur = &dummy;
    while (l1 && l2) {
        if (l1->val <= l2->val) {
            cur->next = l1;
            l1 = l1->next;
        } else {
            cur->next = l2;
            l2 = l2->next;
        }
        cur = cur->next;
    }
    cur->next = l1 ? l1 : l2;
    return dummy.next;
}

// Merge sort on linked list using fast-slow split
// head: head node of the linked list.
ListNode* mergeSort(ListNode* head) {
    if (!head || !head->next) {
        return head;
    }
    ListNode* mid = findLeftMiddle(head);
    ListNode* right = mid->next;
    mid->next = nullptr;  // Split into two halves
    return merge(mergeSort(head), mergeSort(right));
}
```

歸併排序必須使用**左中點**（`fast` 從 `head->next` 出發），使長度為 2 的串列分割為 `[head]` 和 `[head->next]` 各一個，避免右中點時分割後左半仍是 `[head, head->next]`、右半為空而無限遞迴。

以「長度 k 的子陣列最大和」為例，視窗和 `sum` 隨指針滑動增量維護：

```cpp
// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
long long maxSumFixed(const vector<int>& a, int k) {
    long long sum = 0, best = LLONG_MIN;
    for (int i = 0; i < (int)a.size(); i++) {
        sum += a[i];  // 1) enter a[i]
        if (i < k - 1) {
            continue;           // window not full yet
        }
        best = max(best, sum);  // 2) update with a full window
        sum -= a[i - k + 1];    // 3) leave the leftmost element
    }
    return best;
}
```

三步驟的順序不能亂：必須等視窗湊滿 `k` 個元素才更新答案，否則會把長度不足的前綴也算進去。

當統計量不是單純的和，而是「不同字母數」「某條件元素的個數」時，用一個計數器或頻次表搭配相同骨架。例如求每個長度 k 視窗內的母音數：

```cpp
// s: input string.
// k: limit, count, or window size used by the algorithm.
vector<int> vowelsInWindows(const string& s, int k) {
    auto is_vowel = [](char c) { return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u'; };
    vector<int> res;
    int cnt = 0;
    for (int i = 0; i < (int)s.size(); i++) {
        cnt += is_vowel(s[i]);  // enter
        if (i < k - 1) {
            continue;
        }
        res.push_back(cnt);             // record
        cnt -= is_vowel(s[i - k + 1]);  // leave
    }
    return res;
}
```

只要「入」與「出」是對稱的可逆操作（加一/減一、insert/erase），這個模板就成立。

最基礎的歸併：誰小先放誰，某側走完後把另一側剩餘全部接上。

```cpp
// a: input array or sequence.
// b: input or working vector used by the algorithm.
vector<int> mergeSorted(const vector<int>& a, const vector<int>& b) {
    vector<int> res;
    res.reserve(a.size() + b.size());
    int i = 0, j = 0;
    while (i < (int)a.size() && j < (int)b.size()) {
        if (a[i] <= b[j]) {
            res.push_back(a[i++]);
        }
        else {
            res.push_back(b[j++]);
        }
    }
    while (i < (int)a.size()) {
        res.push_back(a[i++]);
    }
    while (j < (int)b.size()) {
        res.push_back(b[j++]);
    }
    return res;
}
```

`a[i] <= b[j]` 用 `<=` 而非 `<` 可保持穩定性（相等時先取 a），在需要穩定歸併時很重要。

求兩有序陣列交集時，相等才同時記錄並雙雙前進；否則推進較小側：

```cpp
// a: input array or sequence.
// b: input or working vector used by the algorithm.
vector<int> intersect(const vector<int>& a, const vector<int>& b) {
    vector<int> res;
    int i = 0, j = 0;
    while (i < (int)a.size() && j < (int)b.size()) {
        if (a[i] == b[j]) {
            res.push_back(a[i]);
            i++;
            j++;
        } else if (a[i] < b[j]) {
            i++;
        }
        else {
            j++;
        }
    }
    return res;
}
```

判斷 `s` 是否為 `t` 的子序列也是雙序列指針：`j` 掃 `t`，若 `t[j]==s[i]` 就 `i++`，最後看 `i` 是否走完 `s`。差別只在「不要求 t 有序，只要求順序匹配」。

以「最長連續相同字元段長度」為例：

```cpp
// s: input string.
int longestRun(const string& s) {
    int n = s.size(), ans = 0, i = 0;
    while (i < n) {
        int j = i;
        while (j < n && s[j] == s[i]) {
            j++;                // extend the current group
        }
        ans = max(ans, j - i);  // group is [i, j)
        i = j;                  // jump to next group's start
    }
    return ans;
}
```

不論段的定義是什麼（相同、遞增、奇偶交替……），都只要替換內層 while 的條件，外層永遠是 `i = j` 跳段，保證每個元素只被掃一次。

當「是否屬於同一段」取決於相鄰兩元素關係（如嚴格遞增、交替奇偶），內層條件比較 `s[j]` 與 `s[j-1]`：

```cpp
// a: input array or sequence.
int longestAlternating(const vector<int>& a) {
    int n = a.size(), ans = 0, i = 0;
    while (i < n) {
        int j = i + 1;
        // same group while parity keeps alternating
        while (j < n && (a[j] % 2) != (a[j - 1] % 2)) {
            j++;
        }
        ans = max(ans, j - i);
        i = j;  // next group starts where this broke
    }
    return ans;
}
```

注意內層從 `i+1` 開始（單一元素自成一段），跳出後 `i = j` 讓**斷點**成為下一段起點，而不是 `i = j+1`，否則會漏掉斷點元素。

`m×n` 乘法表第 K 小：`cnt(x) = Σ min(x / i, n)`（第 i 列有幾個 `i·j <= x`）。對答案二分：

```cpp
// m: number of edges, columns, or elements depending on the problem.
// n: number of nodes or elements.
// k: limit, count, or window size used by the algorithm.
int findKthNumber(int m, int n, int k) {
    auto count_less_equal = [m, n](long long x) {
        long long c = 0;
        for (int i = 1; i <= m; i++) {
            c += min(x / i, (long long)n);
        }
        return c;
    };
    int lo = 1, hi = m * n;
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        if (count_less_equal(mid) >= k) {
            hi = mid;  // enough numbers <= mid, shrink
        }
        else {
            lo = mid + 1;
        }
    }
    return lo;  // smallest x with count_less_equal(x) >= k
}
```

迴圈結束時 `lo` 即第 K 小。即使 `mid` 不在乘法表內，因 `cnt` 在真實值處才「跳級」，最終收斂到的 `lo` 必為表內真實值。

求所有數對絕對差中的第 K 小：排序後，`cnt(x)=` 差 `<= x` 的對數，用雙指針 O(n) 求得：

```cpp
// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
int smallestDistancePair(vector<int>& a, int k) {
    sort(a.begin(), a.end());
    int n = a.size();
    auto count_pairs = [&a, n](int x) {
        int c = 0, l = 0;
        for (int r = 0; r < n; r++) {
            while (a[r] - a[l] > x) {
                l++;     // keep diff within x
            }
            c += r - l;  // pairs ending at r
        }
        return c;
    };
    int lo = 0, hi = a[n - 1] - a[0];
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        if (count_pairs(mid) >= k) {
            hi = mid;
        }
        else {
            lo = mid + 1;
        }
    }
    return lo;
}
```

這裡 `cnt` 本身是一個不定長滑動視窗：外層值域二分 × 內層雙指針，是「二分套計數」的經典組合。

「把陣列分成 m 段使各段和的最大值最小」：`check(x)=` 以「段和不超過 x」貪心切，所需段數 `<= m` 即可行。可行性對 `x` 單調遞增，找最小可行 `x`：

```cpp
// a: input array or sequence.
// m: number of edges, columns, or elements depending on the problem.
int splitArray(vector<int>& a, int m) {
    auto check = [&a, m](long long x) {
        int parts = 1;
        long long cur = 0;
        for (int v : a) {
            if (v > x) {
                return false;  // a single element exceeds x
            }
            if (cur + v > x) {
                parts++;
                cur = 0;
            }
            cur += v;
        }
        return parts <= m;  // feasible with <= m segments
    };
    long long lo = *max_element(a.begin(), a.end());
    long long hi = accumulate(a.begin(), a.end(), 0LL);
    while (lo < hi) {
        long long mid = lo + (hi - lo) / 2;
        if (check(mid)) {
            hi = mid;  // feasible -> try smaller max
        }
        else {
            lo = mid + 1;
        }
    }
    return lo;
}
```

`lo` 取單一元素最大值（任何段至少裝得下最大元素），`hi` 取總和（全放一段）。

「在 n 個位置放 k 頭牛使任兩頭最近距離最大」：`check(x)=` 貪心從最左開始、每超過 `x` 才放一頭，能放 `>= k` 即可行。可行性對 `x` 單調遞減，找**最大**可行 `x`：

```cpp
// pos: current position being constructed.
// k: limit, count, or window size used by the algorithm.
int maxMinDistance(vector<int>& pos, int k) {
    sort(pos.begin(), pos.end());
    auto check = [&pos, k](int x) {
        int cnt = 1, last = pos[0];
        for (int p : pos) {
            if (p - last >= x) {
                cnt++;
                last = p;
            }
        }
        return cnt >= k;
    };
    int lo = 1, hi = pos.back() - pos.front(), ans = 0;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (check(mid)) {
            ans = mid;
            lo = mid + 1;
        }  // feasible -> try larger
        else {
            hi = mid - 1;
        }
    }
    return ans;
}
```

注意方向相反：最大化最小值時，可行就往**大**走（`lo = mid + 1`），用 `ans` 記錄最後一個可行解。

經典：含負數時不能用滑窗，改用前綴和 + 雜湊。

```cpp
// a: input array or sequence.
// k: limit, count, or window size used by the algorithm.
int subarraySum(vector<int>& a, int k) {
    unordered_map<long long, int> seen{{0, 1}};  // empty prefix
    long long pre = 0;
    int cnt = 0;
    for (int v : a) {
        pre += v;
        cnt += seen.count(pre - k) ? seen[pre - k] : 0;  // need pre[l] = pre - k
        seen[pre]++;
    }
    return cnt;
}
```

初始放入 `{0:1}` 代表「空前綴」，否則會漏掉從頭開始就等於 k 的子陣列。

`S[i][j]` 為左上角到 `(i-1,j-1)` 的矩形和，建表與查詢都用容斥：

```cpp
// build: prefix has size (n+1) x (m+1), zero-padded
for (int i = 1; i <= n; i++) {
    for (int j = 1; j <= m; j++) {
        prefix[i][j] = a[i - 1][j - 1] + prefix[i - 1][j] + prefix[i][j - 1] - prefix[i - 1][j - 1];
    }
}

// query rectangle [r1..r2] x [c1..c2] (0-indexed, inclusive):
auto rect_sum = [&prefix](int r1, int c1, int r2, int c2) {
    return prefix[r2 + 1][c2 + 1] - prefix[r1][c2 + 1] - prefix[r2 + 1][c1] + prefix[r1][c1];
};
```

建表的 `- S[i-1][j-1]` 與查詢的 `+ S[r1][c1]` 都是「多減一塊要補回」的容斥；padding 一圈 0 可免邊界特判。

以「和為 k 的子陣列個數」為例。

```cpp
int subarraySum(vector<int>& a, int k){
    unordered_map<long long,int> cnt; cnt[0]=1; // 空前綴
    long long pre=0; int ans=0;
    for(int x : a){
        pre += x;
        ans += cnt[pre - k];   // 需要左前綴 = pre-k
        cnt[pre]++;            // 把當前前綴存入供右側查詢
    }
    return ans;
}
```

先查後存，保證每個左端點都在右端點之前被計入。求「最長」改存每個前綴最早出現的下標。

用單調堆疊求每個元素左右第一個更小者，左邊嚴格、右邊非嚴格避免重複：

```cpp
const long long kMod = 1e9 + 7;
// a: input array or sequence.
int sumSubarrayMins(vector<int>& a) {
    int n = a.size();
    vector<int> L(n), R(n);  // boundaries where a[i] is the strict min
    stack<int> st;
    for (int i = 0; i < n; i++) {  // left: first index with a[left] < a[i]
        while (!st.empty() && a[st.top()] >= a[i]) {
            st.pop();
        }
        L[i] = st.empty() ? -1 : st.top();
        st.push(i);
    }
    while (!st.empty()) {
        st.pop();
    }
    for (int i = n - 1; i >= 0; i--) {  // right: first index with a[right] < a[i]
        while (!st.empty() && a[st.top()] > a[i]) {
            st.pop();
        }
        R[i] = st.empty() ? n : st.top();
        st.push(i);
    }
    long long ans = 0;
    for (int i = 0; i < n; i++) {
        ans = (ans + 1LL * a[i] * (i - L[i]) % kMod * (R[i] - i)) % kMod;
    }
    return ans;
}
```

左用 `>=`（嚴格更小才停）、右用 `>`（遇相等不停），保證每個子陣列的最小值唯一歸給最左邊那個，避免重算。

「所有子陣列 (max − min) 之和」可拆成兩個獨立貢獻問題：

```cpp
// sum of maxima - sum of minima over all subarrays
// a: input array or sequence.
long long subArrayRanges(vector<int>& a) {
    auto solve = [&a](bool want_max) {
        int n = a.size();
        long long s = 0;
        vector<int> left(n), right(n);
        stack<int> st;
        for (int i = 0; i < n; i++) {
            while (!st.empty() && (want_max ? a[st.top()] <= a[i] : a[st.top()] >= a[i])) {
                st.pop();
            }
            left[i] = st.empty() ? -1 : st.top();
            st.push(i);
        }
        st = {};
        for (int i = n - 1; i >= 0; i--) {
            while (!st.empty() && (want_max ? a[st.top()] < a[i] : a[st.top()] > a[i])) {
                st.pop();
            }
            right[i] = st.empty() ? n : st.top();
            st.push(i);
        }
        for (int i = 0; i < n; i++) {
            s += 1LL * a[i] * (i - left[i]) * (right[i] - i);
        }
        return s;
    };
    return solve(true) - solve(false);
}
```

「極差」「逆序貢獻」「最大值×長度」等都能用同一框架：先確定每元素的管轄區間，再乘上對應權重累加。

維護遞增 stack，stack top 比當前大且還能刪就彈：

```cpp
// num: input string.
// k: limit, count, or window size used by the algorithm.
string removeKdigits(string num, int k) {
    string st;
    for (char c : num) {
        while (!st.empty() && k > 0 && st.back() > c) {
            st.pop_back();
            k--;
        }
        st.push_back(c);
    }
    while (k > 0) {
        st.pop_back();
        k--;
    }  // still must remove from the tail
    int i = 0;
    while (i < (int)st.size() && st[i] == '0') {
        i++;  // strip leading zeros
    }
    string res = st.substr(i);
    return res.empty() ? "0" : res;
}
```

若掃完還有刪除額度（整體遞增的情況），從尾端補刪；最後去前導零。

每個字元恰留一個，要求字典序最小。多了兩個約束：當前字元已在 stack 中就跳過；pop 前要確認被彈字元**後面還會再出現**。

```cpp
// s: input string.
string smallestSubsequence(string s) {
    int cnt[26] = {0};
    bool in_stack[26] = {false};
    for (char c : s) {
        cnt[c - 'a']++;
    }
    string st;
    for (char c : s) {
        cnt[c - 'a']--;  // one fewer remaining
        if (in_stack[c - 'a']) {
            continue;  // keep only one of each
        }
        while (!st.empty() && st.back() > c && cnt[st.back() - 'a'] > 0) {
            in_stack[st.back() - 'a'] = false;  // safe to pop: appears later
            st.pop_back();
        }
        st.push_back(c);
        in_stack[c - 'a'] = true;
    }
    return st;
}
```

pop 條件 `cnt[st.back()] > 0` 保證被刪字元之後還能補回，否則會丟失必須保留的字元。

方向陣列 + 就地標記（把走過的陸地改成水）避免額外 visited：

```cpp
int dr[] = {-1, 1, 0, 0}, dc[] = {0, 0, -1, 1};
// g: grid or adjacency structure used by the algorithm.
// r: right boundary, row, or endpoint.
// c: candidate character or capacity value.
int dfs(vector<vector<char>>& g, int r, int c) {
    int rowCount = g.size(), col_count = g[0].size();
    if (r < 0 || r >= rowCount || c < 0 || c >= col_count || g[r][c] != '1') {
        return 0;
    }
    g[r][c] = '0';  // mark visited in place
    int area = 1;
    for (int k = 0; k < 4; k++) {
        area += dfs(g, r + dr[k], c + dc[k]);
    }
    return area;
}
// g: grid or adjacency structure used by the algorithm.
int numIslands(vector<vector<char>>& g) {
    int cnt = 0;
    for (int r = 0; r < (int)g.size(); r++) {
        for (int c = 0; c < (int)g[0].size(); c++) {
            if (g[r][c] == '1') {
                dfs(g, r, c);
                cnt++;
            }
        }
    }
    return cnt;
}
```

大網格用遞迴 DFS 可能 stack overflow，改用顯式 stack 或 BFS 較安全。

所有源點同時 enqueue，按層擴散，第一次到達即最短：

```cpp
// g: grid or adjacency structure used by the algorithm.
int orangesRotting(vector<vector<int>>& g) {
    int rowCount = g.size(), col_count = g[0].size(), fresh = 0;
    queue<pair<int, int>> q;
    for (int r = 0; r < rowCount; r++) {
        for (int c = 0; c < col_count; c++) {
            if (g[r][c] == 2) {
                q.push({r, c});  // all sources enqueued first
            }
            else if (g[r][c] == 1) {
                fresh++;
            }
        }
    }
    int dr[] = {-1, 1, 0, 0}, dc[] = {0, 0, -1, 1}, minutes = 0;
    while (!q.empty() && fresh) {
        int sz = q.size();
        while (sz--) {
            auto [r, c] = q.front();
            q.pop();
            for (int k = 0; k < 4; k++) {
                int nr = r + dr[k], nc = c + dc[k];
                if (nr < 0 || nr >= rowCount || nc < 0 || nc >= col_count || g[nr][nc] != 1) {
                    continue;
                }
                g[nr][nc] = 2;
                fresh--;
                q.push({nr, nc});
            }
        }
        minutes++;  // one layer = one minute
    }
    return fresh ? -1 : minutes;
}
```

每處理完一整層 `minutes++`，這就是 BFS「按邊數分層」的特性；多源只是初始把所有起點放進同一層。

統計每點入度，反覆移除入度 0 的點；最後 `onCycle` 為真者即在某個環上：

```cpp
// next: input or working vector used by the algorithm.
vector<char> findCycleNodes(const vector<int>& next) {  // next[i] = i's out-edge
    int n = next.size();
    vector<int> indeg(n, 0);
    for (int i = 0; i < n; i++) {
        indeg[next[i]]++;
    }
    queue<int> q;
    for (int i = 0; i < n; i++) {
        if (indeg[i] == 0) {
            q.push(i);
        }
    }
    vector<char> on_cycle(n, 1);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        on_cycle[u] = 0;  // peeled off -> a tree node
        if (--indeg[next[u]] == 0) {
            q.push(next[u]);
        }
    }
    return on_cycle;  // remaining 1's lie on cycles
}
```

剝葉後仍留有入度的節點全部在環上；這比 DFS 找環更不易出錯，也方便接著做環上計算。

從某點出發，快指針一次兩步、慢指針一步，相遇後再繞一圈量環長：

```cpp
// next: input or working vector used by the algorithm.
// start: starting index or node for the search.
int cycleLength(const vector<int>& next, int start) {
    int slow = start, fast = start;
    do {
        slow = next[slow];
        fast = next[next[fast]];
    } while (slow != fast);  // meet inside the cycle
    int len = 0;
    do {
        fast = next[fast];
        len++;
    } while (fast != slow);
    return len;
}
```

函數圖一定有環，所以快慢指針必相遇；這常用於「能否回到自己／最大環長」這類題。

對每一位獨立統計有幾個數該位為 1，AND 的貢獻來自「兩數該位都是 1 的對數」：

```cpp
// sum over all pairs (i<j) of (a[i] & a[j])
// a: input array or sequence.
long long pairAndSum(const vector<int>& a) {
    long long total = 0;
    for (int b = 0; b < 30; b++) {
        long long ones = 0;
        for (int x : a) {
            if (x >> b & 1) {
                ones++;
            }
        }
        total += (ones * (ones - 1) / 2) << b;  // comb(ones, 2) pairs contribute 2^b
    }
    return total;
}
```

XOR 之和則改成 `ones * (n - ones)`（一 0 一 1 的對才貢獻）。逐位獨立讓 O(n²) 變 O(n·30)。

常見的位元小工具：

```cpp
// x: value or node being processed.
int popcount(unsigned x) {  // count set bits
    int c = 0;
    while (x) {
        x &= x - 1;
        c++;
    }  // drop the lowest set bit each step
    return c;
}
// x: value, node, or output coefficient used by the function.
int lowbit(int x) {
    return x & -x;
}  // isolate the lowest set bit
// x: value, node, or output coefficient used by the function.
bool isPow2(unsigned x) {
    return x && !(x & (x - 1));
}
// enumerate all submasks of m (descending):
// for (int s = m; s; s = (s - 1) & m) { /* use s */ }
```

C++20 可直接用 `std::popcount`、`std::countr_zero`；競賽常用 GCC 內建 `__builtin_popcount` / `__builtin_ctz`。

插入每個數的二進位（高位在上），查詢時貪心走相反位：

```cpp
struct XorTrie {
    static const int B = 30;
    vector<array<int, 2>> ch{{{0, 0}}};  // node 0 is the root
    // x: value or node being processed.
    void insert(int x) {
        int u = 0;
        for (int b = B; b >= 0; b--) {
            int d = x >> b & 1;
            if (!ch[u][d]) {
                ch.push_back({0, 0});
                ch[u][d] = ch.size() - 1;
            }
            u = ch[u][d];
        }
    }
    // x: value, node, or output coefficient used by the function.
    int queryMax(int x) {  // max (x ^ y) over inserted y
        int u = 0, res = 0;
        for (int b = B; b >= 0; b--) {
            int d = x >> b & 1;
            if (ch[u][d ^ 1]) {
                res |= 1 << b;
                u = ch[u][d ^ 1];
            }  // go opposite
            else {
                u = ch[u][d];
            }
        }
        return res;
    }
};
```

每一位優先走「與 x 相反」的子（讓該位異或為 1），走不通才同向；高位優先保證結果最大。

若只需最大異或對，可用集合逐位試填，無需顯式 Trie：

```cpp
// a: input array or sequence.
int findMaximumXOR(vector<int>& a) {
    int ans = 0, mask = 0;
    for (int b = 30; b >= 0; b--) {
        mask |= 1 << b;  // consider prefixes up to bit b
        unordered_set<int> pref;
        for (int x : a) {
            pref.insert(x & mask);
        }
        int want = ans | (1 << b);  // can we make this bit a 1?
        for (int p : pref) {
            if (pref.count(want ^ p)) {
                ans = want;
                break;
            }  // two prefixes xor to 'want'
        }
    }
    return ans;
}
```

每位假設答案該位能是 1（`want`），若存在兩前綴異或得到 `want` 就鎖定；這是「試填 + 雜湊」的代表。

用費馬小定理求逆元，遞推 `inv_fact` 避免每次快速冪：

```cpp
const long long kMod = 1e9 + 7;
const int N = 1e6 + 5;
long long fact[N], inv_fact[N];
// a: input array or sequence.
// b: second numeric input value.
// m: number of edges, columns, or elements depending on the problem.
long long power(long long a, long long b, long long m) {
    long long r = 1;
    a %= m;
    for (; b; b >>= 1, a = a * a % m) {
        if (b & 1) {
            r = r * a % m;
        }
    }
    return r;
}
void initComb() {
    fact[0] = 1;
    for (int i = 1; i < N; i++) {
        fact[i] = fact[i - 1] * i % kMod;
    }
    inv_fact[N - 1] = power(fact[N - 1], kMod - 2, kMod);
    for (int i = N - 1; i > 0; i--) {
        inv_fact[i - 1] = inv_fact[i] * i % kMod;
    }
}
// n: number of nodes or elements.
// r: right boundary, row, or endpoint.
long long comb(int n, int r) {
    if (r < 0 || r > n) {
        return 0;
    }
    return fact[n] * inv_fact[r] % kMod * inv_fact[n - r] % kMod;
}
```

`inv_fact` 從大到小遞推（`inv_fact[i-1] = inv_fact[i]·i`）只需一次快速冪，整體 O(n)。

錯位排列（沒有元素在原位）用容斥：

```cpp
// D(n): permutations with no fixed point, via inclusion-exclusion
// n: number of nodes or elements.
long long derangement(int n) {
    long long res = 0;
    for (int k = 0; k <= n; k++) {
        long long term = comb(n, k) * fact[n - k] % kMod;  // fix k positions
        res = (k & 1) ? (res - term + kMod) % kMod : (res + term) % kMod;
    }
    return res;  // = sum (-1)^k comb(n, k)(n-k)!
}
```

「至少 k 個滿足」的計數常先算「指定某 k 個都滿足、其餘任意」再容斥成「恰好」；符號隨容斥層數正負交替。

預處理階乘與其逆元，O(1) 查任意 C(n,k) mod p。

```cpp
const int MOD=1e9+7; vector<long long> fac, inv;
long long power(long long a,long long b){ long long r=1; for(;b;b>>=1,a=a*a%MOD) if(b&1) r=r*a%MOD; return r; }
void init(int n){
    fac.assign(n+1,1);
    for(int i=1;i<=n;i++) fac[i]=fac[i-1]*i%MOD;
    inv.assign(n+1,1); inv[n]=power(fac[n],MOD-2);
    for(int i=n;i>0;i--) inv[i-1]=inv[i]*i%MOD;
}
long long C(int n,int k){ if(k<0||k>n) return 0; return fac[n]*inv[k]%MOD*inv[n-k]%MOD; }
```

隔板法：把 n 個相同物分給 k 人（每人 ≥0）方案數 = C(n+k-1, k-1)；乘法原理把多步獨立選擇相乘即可。

Nim 結論只需一行異或：

```cpp
// piles: input or working vector used by the algorithm.
bool firstPlayerWinsNim(const vector<int>& piles) {
    int x = 0;
    for (int p : piles) {
        x ^= p;     // Nim-sum
    }
    return x != 0;  // nonzero -> first player wins
}
```

直覺：異或非 0 時，先手總能取一步讓異或變 0（把對手丟進必敗態），反之先手怎麼動都會破壞全 0。

對「每次可取 1..m 顆」之類的取石子遊戲求 SG：

```cpp
// SG for a game where from a pile of size i you may remove any value in moves[]
// n: number of nodes or elements.
// moves: input or working vector used by the algorithm.
vector<int> computeSG(int n, const vector<int>& moves) {
    vector<int> sg(n + 1, 0);
    for (int i = 1; i <= n; i++) {
        set<int> reachable;
        for (int m : moves) {
            if (i - m >= 0) {
                reachable.insert(sg[i - m]);
            }
        }
        int mex = 0;
        while (reachable.count(mex)) {
            mex++;  // smallest excluded value
        }
        sg[i] = mex;
    }
    return sg;
}
// Combine independent games: overall losing iff XOR of their SG values == 0.
```

把局面拆成互不干擾的子遊戲，各自查 SG 後全部異或；結果為 0 即先手必敗。這就是 SG 定理的威力。

插入分隔符後對每個中心求半徑，利用對稱複用：

```cpp
// s: input string.
vector<int> manacher(const string& s) {
    string t = "^";
    for (char c : s) {
        t += '#';
        t += c;
    }
    t += "#$";  // sentinels avoid bounds checks
    int n = t.size();
    vector<int> p(n, 0);
    int center = 0, right = 0;
    for (int i = 1; i < n - 1; i++) {
        if (i < right) {
            p[i] = min(right - i, p[2 * center - i]);  // mirror reuse
        }
        while (t[i + p[i] + 1] == t[i - p[i] - 1]) {
            p[i]++;  // expand
        }
        if (i + p[i] > right) {
            center = i;
            right = i + p[i];
        }  // extend window
    }
    return p;  // p[i] = palindrome radius in t
}
```

`p[i]` 正好等於原串中以該位置為中心的最長回文**長度**（分隔符的巧妙之處）。

找最大的 `p[i]`，由 `t` 的下標換回原串區間：

```cpp
// s: input string.
string longestPalindrome(const string& s) {
    if (s.empty()) {
        return "";
    }
    vector<int> p = manacher(s);
    int best_len = 0, best_center = 0;
    for (int i = 1; i + 1 < (int)p.size(); i++) {
        if (p[i] > best_len) {
            best_len = p[i];
            best_center = i;
        }
    }
    int start = (best_center - best_len) / 2;  // map back to original index
    return s.substr(start, best_len);
}
```

原串起點 `= (center - radius) / 2`，長度即 `radius`；推導來自插入 `#` 後每個原字元下標翻倍的關係。

把轉移補全為自動機，使匹配時無需顯式跳 fail：

```cpp
struct AhoCorasick {
    static const int K = 26;
    vector<array<int, K>> go{{}};  // node 0 = root, transitions
    vector<int> fail{0}, cnt{0};   // fail link, #patterns ending here
    // s: input string.
    void insert(const string& s) {
        int u = 0;
        for (char c : s) {
            int d = c - 'a';
            if (!go[u][d]) {
                go.push_back({});
                fail.push_back(0);
                cnt.push_back(0);
                go[u][d] = go.size() - 1;
            }
            u = go[u][d];
        }
        cnt[u]++;
    }
    void build() {
        queue<int> q;
        for (int c = 0; c < K; c++) {
            if (go[0][c]) {
                q.push(go[0][c]);
            }
        }
        while (!q.empty()) {
            int u = q.front();
            q.pop();
            for (int c = 0; c < K; c++) {
                int v = go[u][c];
                if (v) {
                    fail[v] = go[fail[u]][c];
                    q.push(v);
                } else {
                    go[u][c] = go[fail[u]][c];  // path-compress transition
                }
            }
        }
    }
};
```

`else go[u][c] = go[fail[u]][c]` 是關鍵：不存在的邊直接指向 fail 的轉移，匹配時每步 O(1)、無需迴圈跳 fail。

沿自動機走，累計每個前綴節點沿 fail 鏈的命中數（可用拓撲序優化）：

```cpp
// ac: Aho-Corasick automaton instance.
// text: input string.
long long countMatches(AhoCorasick& ac, const string& text) {
    long long total = 0;
    int u = 0;
    for (char c : text) {
        u = ac.go[u][c - 'a'];              // O(1) transition
        for (int v = u; v; v = ac.fail[v]) {  // walk fail chain (or precompute)
            total += ac.cnt[v];
        }
    }
    return total;
}
```

若命中很密集，沿 fail 鏈逐節點累加可能退化；可按 fail 樹的拓撲序把 `cnt` 累加到 fail 父節點，查詢變 O(1)。

從右往左遞推 `nxt`，查詢時沿表跳：

```cpp
struct SubseqAutomaton {
    vector<array<int, 26>> nxt;  // nxt[i][c] = first index >= i with char c, or n
    int n;
    // s: input string.
    SubseqAutomaton(const string& s) : n(s.size()) {
        nxt.assign(n + 1, {});
        for (int c = 0; c < 26; c++) {
            nxt[n][c] = n;  // n = "not found"
        }
        for (int i = n - 1; i >= 0; i--) {
            nxt[i] = nxt[i + 1];
            nxt[i][s[i] - 'a'] = i;  // s[i] available from i itself
        }
    }
    // t: target/end value.
    bool isSubsequence(const string& t) const {
        int pos = 0;
        for (char c : t) {
            pos = nxt[pos][c - 'a'];
            if (pos == n) {
                return false;  // char not found afterwards
            }
            pos++;             // consume it, move past
        }
        return true;
    }
};
```

查詢時 `pos = nxt[pos][c]` 找到該字元位置後 `pos++` 往後推進；`pos == n` 代表後面再也沒有此字元，匹配失敗。

子序列自動機讓「不同子序列數」DP 一目了然：`f[i]` = 從位置 i 出發的不同子序列數，沿每個字元的首次出現轉移避免重複：

```cpp
// number of distinct non-empty subsequences (mod p), using first-occurrence
// s: input string.
long long distinctSubseq(const string& s) {
    const long long kMod = 1e9 + 7;
    int n = s.size();
    SubseqAutomaton sa(s);
    vector<long long> f(n + 1, 0);
    f[n] = 1;  // empty subsequence (counted once)
    for (int i = n - 1; i >= 0; i--) {
        f[i] = 0;
        for (int c = 0; c < 26; c++) {
            if (sa.nxt[i][c] < n) {
                f[i] = (f[i] + f[sa.nxt[i][c] + 1]) % kMod;
            }
        }
        f[i] = (f[i] + 1) % kMod;  // the subsequence ending choices
    }
    return (f[0] - 1 + kMod) % kMod;  // exclude the empty one
}
```

只從「每個字元的首次出現」轉移，天然去重——這正是子序列自動機去除重複子序列的核心。

比較兩候選起點 i、j，依差異整批跳過較大者。

```cpp
int minRotation(const string& s){
    int n=s.size(), i=0, j=1, k=0;
    while(i<n && j<n && k<n){
        char a=s[(i+k)%n], b=s[(j+k)%n];
        if(a==b){ k++; continue; }
        if(a>b) i+=k+1; else j+=k+1;  // 較大起點整段作廢
        if(i==j) j++;
        k=0;
    }
    return min(i,j); // 最小表示法的起始下標
}
```

兩字串循環同構 ⟺ 它們的最小表示相同（或等長且互為子串：`(s+s).find(t)!=npos`）。

`f[i]` = 前 i 字元的最少劃分次數，枚舉最後一段 `[j, i)`：

```cpp
// s: source node in the flow network.
int minCut(const string& s) {
    int n = s.size();
    // pal[j][i] = whether s[j..i-1] is a palindrome (precomputed)
    vector<vector<char>> pal(n, vector<char>(n + 1, 0));
    for (int j = n - 1; j >= 0; j--) {
        for (int i = j + 1; i <= n; i++) {
            pal[j][i] = (s[j] == s[i - 1]) && (i - j < 3 || pal[j + 1][i - 1]);
        }
    }
    vector<int> f(n + 1, INT_MAX);
    f[0] = 0;
    for (int i = 1; i <= n; i++) {
        for (int j = 0; j < i; j++) {
            if (pal[j][i] && f[j] != INT_MAX) {
                f[i] = min(f[i], f[j] + 1);
            }
        }
    }
    return f[n] - 1;  // cuts = segments - 1
}
```

「最後一段必須合法（回文）」是轉移的前提；先預處理合法性表，轉移就乾淨。

把陣列分成恰 k 段使各段和平方差等代價最小，`f[i][t]` = 前 i 個分成 t 段：

```cpp
// minimize total cost splitting a[0..n) into exactly k segments
// pre: input or working vector used by the algorithm.
// n: number of nodes or elements.
// k: limit, count, or window size used by the algorithm.
// cost: current accumulated cost.
long long partitionK(const vector<long long>& pre, int n, int k,
                     function<long long(int, int)> cost) {  // cost(j, i)=segment [j, i)
    const long long kInf = 1e18;
    vector<vector<long long>> f(n + 1, vector<long long>(k + 1, kInf));
    f[0][0] = 0;
    for (int i = 1; i <= n; i++) {
        for (int t = 1; t <= min(i, k); t++) {
            for (int j = t - 1; j < i; j++) {
                if (f[j][t - 1] < kInf) {
                    f[i][t] = min(f[i][t], f[j][t - 1] + cost(j, i));  // last seg [j, i)
                }
            }
        }
    }
    return f[n][k];
}
```

`cost(j, i)` 多半能用前綴和 O(1) 求得；若代價滿足四邊形不等式，可用決策單調性把這層 O(n) 降到 O(log n) 或更低。

狀態：`hold`（持股）、`sold`（剛賣出，次日冷凍）、`rest`（空倉可買）：

```cpp
// p: stock prices by day.
int maxProfitCooldown(vector<int>& p) {
    int n = p.size();
    if (!n) {
        return 0;
    }
    int hold = -p[0], sold = 0, rest = 0;  // day 0
    for (int i = 1; i < n; i++) {
        int nhold = max(hold, rest - p[i]);  // keep, or buy from rest
        int nsold = hold + p[i];             // sell today
        int nrest = max(rest, sold);         // stay rest, or recover from sold
        hold = nhold;
        sold = nsold;
        rest = nrest;
    }
    return max(sold, rest);  // not holding at the end
}
```

每個轉移直接對應狀態圖的一條邊：買（rest→hold）、賣（hold→sold）、冷卻（sold→rest）、休息（自環）。

把「已用幾次交易」放進狀態，`buy[j]`/`sell[j]` 表示第 j 筆交易的持股／已賣最優：

```cpp
// k: limit, count, or window size used by the algorithm.
// p: stock prices by day.
int maxProfitK(int k, vector<int>& p) {
    if (p.empty() || k == 0) {
        return 0;
    }
    vector<int> buy(k + 1, INT_MIN), sell(k + 1, 0);
    for (int price : p) {
        for (int j = 1; j <= k; j++) {
            buy[j] = max(buy[j], sell[j - 1] - price);  // open j-th position
            sell[j] = max(sell[j], buy[j] + price);     // close j-th position
        }
    }
    return sell[k];
}
```

交易次數本身就是狀態的一維；內層從 1 到 k 的遞推等價於 k 台狀態機串接。

以「統計 [0, n] 中數位不含 4 的數」為例：

```cpp
string digits;
int dp[12][2];  // dp[pos][started]; valid only when !tight
// pos: current position being constructed.
// tight: state marker or boolean-like flag.
// started: state marker or boolean-like flag.
int dfs(int pos, bool tight, bool started) {
    if (pos == (int)digits.size()) {
        return started ? 1 : 1;  // count this number
    }
    if (!tight && dp[pos][started] != -1) {
        return dp[pos][started];
    }
    int hi = tight ? digits[pos] - '0' : 9;
    int res = 0;
    for (int d = 0; d <= hi; d++) {
        if (d == 4) {
            continue;  // the digit constraint
        }
        res += dfs(pos + 1, tight && (d == hi), started || d > 0);
    }
    if (!tight) {
        dp[pos][started] = res;
    }
    return res;
}
// n: number of nodes or elements.
int countNoFour(int n) {
    digits = to_string(n);
    memset(dp, -1, sizeof dp);
    return dfs(0, true, false);
}
```

只有 `tight=false` 時才記憶化（此時剩餘位的答案與上界無關）；`tight=true` 的分支唯一、無需快取。

若條件涉及相鄰位（如相鄰數字差 ≥ 2），把上一位放進狀態，區間用差分：

```cpp
// answer for [L, R] = solve(R) - solve(L - 1)
// dp state adds 'prev' (last placed digit) when the rule couples adjacent digits:
//   dfs(pos, prev, tight, started)
// transition: for d in [0..hi], require started==false || abs(d - prev) >= 2
// memoize on dp[pos][prev] only when !tight && started.
// L: left boundary of the query range.
// R: right boundary of the query range.
// solve: callback predicate used by the algorithm.
long long countRange(long long L, long long R, function<long long(long long)> solve) {
    return solve(R) - solve(L - 1);  // classic prefix differencing
}
```

把「與相鄰位的約束」「目前數位和」「是否已出現某模式」等都放進狀態，是數位 DP 的擴展方向；前導零狀態 `started` 決定約束何時開始生效。

`f[l][r]` = 當前玩家在 `[l, r]` 的最大淨得分（自己減對手）：

```cpp
// a: input array or sequence.
bool firstWins(vector<int>& a) {
    int n = a.size();
    vector<vector<int>> f(n, vector<int>(n, 0));
    for (int i = 0; i < n; i++) {
        f[i][i] = a[i];  // one pile: take it all
    }
    for (int len = 2; len <= n; len++) {
        for (int l = 0; l + len - 1 < n; l++) {
            int r = l + len - 1;
            f[l][r] = max(a[l] - f[l + 1][r],   // take left
                          a[r] - f[l][r - 1]);  // take right
        }
    }
    return f[0][n - 1] >= 0;  // first player not behind
}
```

「`a[l] - f[l+1][r]`」中減號的意義：剩下局面換對手當「當前玩家」，其淨得分要從我方視角扣除。

當只問勝負（非分數），用布林：存在一步讓對手必敗，則當前必勝：

```cpp
// can the current player force a win taking 1..3 stones, last taker wins?
unordered_map<int, int> memo;
// n: number of nodes or elements.
bool canWin(int n) {
    if (n <= 0) {
        return false;
    }
    auto it = memo.find(n);
    if (it != memo.end()) {
        return it->second;
    }
    bool win = false;
    for (int take = 1; take <= 3 && take <= n; take++) {
        if (!canWin(n - take)) {
            win = true;
            break;
        }  // opponent loses next
    }
    return memo[n] = win;
}
```

「存在一個後繼是對手必敗（`!canWin`）」⇒ 當前必勝；所有後繼皆對手必勝 ⇒ 當前必敗。這是必勝/必敗態 DP 的通用判據。

直線上每步以機率前進，求到終點期望步數，從終態倒推：

```cpp
// expected number of dice tosses to go from 0 to >= n, die is 1..6 uniform
// n: number of nodes or elements.
double expectedTosses(int n) {
    vector<double> expected(n + 7, 0.0);  // expected[i] = expected tosses from i
    for (int i = n - 1; i >= 0; i--) {
        double e = 1.0;  // this toss counts as 1
        for (int f = 1; f <= 6; f++) {
            e += (i + f >= n ? 0.0 : expected[i + f]) / 6.0;
        }
        expected[i] = e;
    }
    return expected[0];
}
```

終態 `E[>=n]=0`，每個狀態的期望 = 1（本次操作）+ 各後繼期望的加權平均；逆向遞推自然滿足依賴順序。

「抽卡集齊 n 種的期望次數」（贈券收集）用線性性直接加總各階段期望：

```cpp
// coupon collector: expected draws to collect all n distinct types
// n: number of nodes or elements.
double couponCollector(int n) {
    double exp = 0.0;
    for (int k = 1; k <= n; k++) {
        exp += (double)n / k;  // when k-1 owned, P(new)= (n-k+1)/n
    }
    return exp;                // sum of geometric expectations
}
```

把「集滿」拆成 n 個獨立階段，「已有 k−1 種、抽到第 k 種新卡」服從幾何分布，期望 `n/(n-k+1)`；線性性允許直接相加，無需處理聯合分布。

讓總等待時間最小，應按服務時間升序；交換論證可證相鄰逆序對交換會變差：

```cpp
// t: target/end value.
long long minTotalWait(vector<int>& t) {
    sort(t.begin(), t.end());  // shortest job first
    long long pre = 0, total = 0;
    for (int x : t) {
        total += pre;
        pre += x;
    }  // each later job waits for all earlier
    return total;
}
```

若存在相鄰兩人服務時間 `a > b` 卻 a 在前，交換他們會減少總等待——故最優解中必為升序，貪心正確。

把數字拼成最小，需自訂比較子 `a+b < b+a`（字串拼接比較）：

```cpp
// nums: input numbers.
string smallestConcat(vector<int>& nums) {
    vector<string> s;
    for (int x : nums) {
        s.push_back(to_string(x));
    }
    sort(s.begin(), s.end(), [](const string& a, const string& b) {
        return a + b < b + a;  // a should precede b
    });
    string res;
    for (auto& x : s) {
        res += x;
    }
    return res;
}
```

這個比較子滿足全序（可遞移），交換論證保證排序後拼接最優；最大數版本把 `<` 改成 `>`。

先排序，再從一端貪心地做不可逆決策。

```cpp
sort(a.begin(), a.end());
int i = 0, j = (int)a.size() - 1, ans = 0;
while (i <= j) {
    if (canPair(a[i], a[j])) { ans++; i++; j--; } // 最小配最大
    else j--;                                       // 否則放棄當前最大
}
```

「兩數和不超過上限的最多船/組數」「分發餅乾」都是此型：排序後雙端或同端推進，每步取當前最受限元素。

每個任務有截止期與利潤，每單位時間做一個，最大化總利潤：

```cpp
// jobs: jobs or tasks to schedule.
int maxProfitJobs(vector<pair<int, int>>& jobs) {         // {deadline, profit}
    sort(jobs.begin(), jobs.end());                       // by deadline ascending
    priority_queue<int, vector<int>, greater<int>> done;  // min-heap of chosen profits
    for (auto& [d, p] : jobs) {
        done.push(p);
        if ((int)done.size() > d) {
            done.pop();  // too many by this deadline: drop worst
        }
    }
    int total = 0;
    while (!done.empty()) {
        total += done.top();
        done.pop();
    }
    return total;
}
```

到截止 d 為止最多做 d 個任務；超額時彈出利潤最小者「反悔」，保證留下的永遠是利潤最大的可行子集。

路上經過加油站把可加油量存進堆，油不夠時回頭「加」之前最大的那桶：

```cpp
// target: target value or remaining target to satisfy.
// start_fuel: initial fuel amount.
// st: stack used by the algorithm.
int minRefuel(int target, int start_fuel, vector<vector<int>>& st) {
    priority_queue<int> pq;  // fuel available at passed stations
    int fuel = start_fuel, refuels = 0, i = 0, n = st.size();
    int pos = 0;
    while (fuel < target) {
        while (i < n && st[i][0] <= fuel) {
            pq.push(st[i++][1]);  // reachable stations
        }
        if (pq.empty()) {
            return -1;  // cannot reach target
        }
        fuel += pq.top();
        pq.pop();  // regret: take the biggest tank now
        refuels++;
    }
    return refuels;
}
```

不預先決定在哪加油，而是「先開到沒油，再回頭挑之前能加的最大一桶」，等價於最少加油次數。

在保留每種字元至少需求量下，貪心組出字典序最小結果（示意：從計數構造最小排列且滿足某約束）：

```cpp
// Build the lexicographically smallest string using counts cnt[26].
// Place the smallest usable char whose use still leaves a feasible suffix.
// cnt: counts or frequency table.
// total: total number of positions or elements to construct.
// feasible: predicate that checks whether the remaining state can still be completed.
string smallestFromCounts(int cnt[26], int total, function<bool(int, int*)> feasible) {
    string res;
    for (int pos = 0; pos < total; pos++) {
        for (int c = 0; c < 26; c++) {
            if (!cnt[c]) {
                continue;
            }
            cnt[c]--;
            if (feasible(pos + 1, cnt)) {
                res += char('a' + c);
                break;
            }          // keep choice
            cnt[c]++;  // revert, try next char
        }
    }
    return res;
}
```

每位從最小字元開始試，`feasible` 確認用掉它後剩餘仍可完成；不可行就還原計數換下一個字元。

「能刪就刪」型字典序最小（如移除 k 位）用單調堆疊最直接：

```cpp
// s: input string.
// k: limit, count, or window size used by the algorithm.
string smallestAfterRemoveK(const string& s, int k) {
    string st;
    for (char c : s) {
        while (!st.empty() && k > 0 && st.back() > c) {
            st.pop_back();
            k--;
        }
        st.push_back(c);  // greedily keep small prefix
    }
    st.resize(st.size() - k);  // remove leftover from tail
    return st;
}
```

當 stack top 比當前字元大且還能刪，就彈掉它讓高位變小——這正是「逐位取最小且保證可行」在 stack 上的實現。

把 `1..n` 重排，使相鄰差或首尾和符合要求，常用首尾配對：

```cpp
// arrange 1..n so adjacent pairs from both ends sum constantly (zigzag pairing)
// n: number of nodes or elements.
vector<int> pairConstruct(int n) {
    vector<int> res;
    int lo = 1, hi = n;
    while (lo <= hi) {
        res.push_back(lo++);
        if (lo <= hi) {
            res.push_back(hi--);  // interleave small and large
        }
    }
    return res;  // 1, n, 2, n-1, ...
}
```

「最小配最大」是構造題的常見招式，能讓和或差呈現規律；正確性由配對的對稱性直接保證。

許多構造先用不變量判定有無解，再給法則。例如把 `n` 拆成若干不同正整數之和的最大個數：

```cpp
// max count of distinct positive integers summing to n: greedily 1, 2, 3, ...
// n: number of nodes or elements.
vector<int> maxDistinctParts(int n) {
    vector<int> res;
    int cur = 1;
    while (n - cur >= cur + 1) {
        res.push_back(cur);
        n -= cur;
        cur++;
    }
    res.push_back(n);  // dump the remainder into the last term
    return res;
}
```

貪心地用 `1,2,3,...` 累加，最後把剩餘塞進最大一項——保證互不相同且個數最多；這是「先找單調規律再構造」的典型。

「依序刪點/刪邊後查連通」正向難做，倒序變成加邊，用並查集即可。

```cpp
// 倒序處理刪除：先刪到底，再倒著一個個加回
for (int i = q - 1; i >= 0; i--) {
    addBack(ops[i]);          // 把第 i 次刪除「加回」
    ans[i] = dsu.componentInfo();
}
// 最終 ans 即每次刪除後的狀態（順序對應原查詢）
```

從右往左掃描則用於「每個元素右邊第一個更大值」「後綴最大/和」等，維護後綴結構一趟完成。

以「依長度奇偶 + 是否含特定元素」分類為例。

```cpp
int solve(const vector<int>& a){
    int n = a.size();
    if (n == 0) return 0;             // 邊界類
    if (special(a)) return caseA(a);  // 特徵類 A
    return (n & 1) ? caseOdd(a) : caseEven(a); // 奇偶兩類
}
```

寫完務必回頭檢查：每個輸入恰好落入一類（互斥），且所有輸入都被覆蓋（窮盡）。遺漏邊界（空、單元素、全相同）是最常見錯誤。

範例思路：許多「能否經由若干操作達成」的題，答案由某個不變量決定。

```cpp
// 例：每次操作把相鄰兩數同時 +1，問能否全部相等
// 觀察：操作改變總和，但奇偶位置的差有某種守恆 → 化為同餘判斷
bool canEqualize(const vector<int>& a){
    long long odd = 0, even = 0;
    for (int i = 0; i < (int)a.size(); i++) (i & 1 ? odd : even) += a[i];
    return odd == even; // 視題目守恆量而定
}
```

核心不是程式，而是先證明「哪個量守恆」，程式只是把該量算出來比較。

每個遞迴節點本身就是一個合法子集：

```cpp
// start: starting index or node for the search.
// a: input array or sequence.
// path: current partial solution path.
// res: container used to store results.
void dfs(int start, vector<int>& a, vector<int>& path, vector<vector<int>>& res) {
    res.push_back(path);  // record current subset
    for (int i = start; i < (int)a.size(); i++) {
        path.push_back(a[i]);      // choose a[i]
        dfs(i + 1, a, path, res);  // only pick from i+1 onward
        path.pop_back();           // undo
    }
}
vector<vector<int>> subsets(vector<int>& a) {
    vector<vector<int>> res;
    vector<int> path;
    dfs(0, a, path, res);
    return res;
}
```

`i + 1` 確保元素按序、不回頭，自動去除排列順序造成的重複。

先排序，同一層跳過相同元素：

```cpp
// start: starting index or node for the search.
// a: input array or sequence.
// path: current partial solution path.
// res: container used to store results.
void dfsUnique(int start, vector<int>& a, vector<int>& path, vector<vector<int>>& res) {
    res.push_back(path);
    for (int i = start; i < (int)a.size(); i++) {
        if (i > start && a[i] == a[i - 1]) {
            continue;  // skip duplicate at this level
        }
        path.push_back(a[i]);
        dfsUnique(i + 1, a, path, res);
        path.pop_back();
    }
}
```

`i > start`（而非 `i > 0`）是關鍵：只跳過「同一層」的重複，仍允許同一元素值在不同深度被選入。

路徑滿即記錄，否則枚舉所有未用元素：

```cpp
// a: input array or sequence.
// used: marker array for already chosen elements.
// path: current partial solution path.
// res: container used to store results.
void dfs(vector<int>& a, vector<char>& used, vector<int>& path, vector<vector<int>>& res) {
    if (path.size() == a.size()) {
        res.push_back(path);
        return;
    }
    for (int i = 0; i < (int)a.size(); i++) {
        if (used[i]) {
            continue;
        }
        used[i] = 1;
        path.push_back(a[i]);     // choose
        dfs(a, used, path, res);  // recurse
        path.pop_back();
        used[i] = 0;  // undo
    }
}
```

每層從 0 開始掃，靠 `used` 跳過已選；這保證枚舉的是「順序」而非「組合」。

先排序，再用 `!used[i-1]` 同層去重：

```cpp
// a: input array or sequence.
// used: marker array for already chosen elements.
// path: current partial solution path.
// res: container used to store results.
void dfsUnique(vector<int>& a, vector<char>& used, vector<int>& path, vector<vector<int>>& res) {
    if (path.size() == a.size()) {
        res.push_back(path);
        return;
    }
    for (int i = 0; i < (int)a.size(); i++) {
        if (used[i]) {
            continue;
        }
        if (i > 0 && a[i] == a[i - 1] && !used[i - 1]) {
            continue;  // dup at same level
        }
        used[i] = 1;
        path.push_back(a[i]);
        dfsUnique(a, used, path, res);
        path.pop_back();
        used[i] = 0;
    }
}
```

`!used[i-1]`：前一個相同元素已回溯（本層用過），故此重複者跳過；若改成 `used[i-1]` 則會錯誤去重、漏掉合法排列。

選 k 個數，用「剩餘不足就回退」剪枝：

```cpp
// start: starting index or node for the search.
// n: number of nodes or elements.
// k: limit, count, or window size used by the algorithm.
// path: current partial solution path.
// res: container used to store results.
void dfs(int start, int n, int k, vector<int>& path, vector<vector<int>>& res) {
    if ((int)path.size() == k) {
        res.push_back(path);
        return;
    }
    int need = k - path.size();
    // prune: not enough numbers left in [start, n] to fill 'need'
    for (int i = start; i <= n - need + 1; i++) {
        path.push_back(i);
        dfs(i + 1, n, k, path, res);
        path.pop_back();
    }
}
```

迴圈上界 `n - need + 1` 就是數量剪枝：再往後起點會湊不滿 k 個，直接不進入。

同一元素可重複選時，遞迴傳 `i`（不是 `i+1`）；排序後用和剪枝：

```cpp
// start: starting index or node for the search.
// a: input array or sequence.
// target: target value or remaining target to satisfy.
// path: current partial solution path.
// res: container used to store results.
void dfs(int start, vector<int>& a, int target, vector<int>& path, vector<vector<int>>& res) {
    if (target == 0) {
        res.push_back(path);
        return;
    }
    for (int i = start; i < (int)a.size(); i++) {
        if (a[i] > target) {
            break;  // sorted: no larger one can fit either
        }
        path.push_back(a[i]);
        dfs(i, a, target - a[i], path, res);  // i (not i+1): reuse allowed
        path.pop_back();
    }
}
```

`dfs(i, ...)` 允許重複使用當前元素；先排序後 `a[i] > target` 即可 `break`，省去所有更大元素的分支。

用三個布林集合維護列與兩對角線的佔用，放置 O(1) 檢查：

```cpp
int total = 0, n;
vector<char> col, diag, anti;  // occupied columns / diagonals
// r: right boundary, row, or endpoint.
void place(int r) {
    if (r == n) {
        total++;
        return;
    }
    for (int c = 0; c < n; c++) {
        int d = r + c, a = r - c + n;  // diagonal indices
        if (col[c] || diag[d] || anti[a]) {
            continue;  // feasibility prune
        }
        col[c] = diag[d] = anti[a] = 1;
        place(r + 1);
        col[c] = diag[d] = anti[a] = 0;  // undo
    }
}
```

把「同列／同對角衝突」做成 O(1) 查表的可行性剪枝；還可只枚舉第一列的前半並利用左右對稱把答案 ×2。

在「最少分組／最小代價」型爆搜中，已超過當前最優就回退，並優先放難安置的元素：

```cpp
int best;
// assign items to groups, prune when used groups already >= best
// idx: current recursion index.
// groups_used: number of groups opened so far.
// group_load: current load of each opened group.
// items: items considered by the algorithm.
// cap: capacity limit.
void dfs(int idx, int groups_used, vector<int>& group_load, const vector<int>& items, int cap) {
    if (groups_used >= best) {
        return;  // optimality prune
    }
    if (idx == (int)items.size()) {
        best = min(best, groups_used);
        return;
    }
    for (int g = 0; g < groups_used; g++) {
        if (group_load[g] + items[idx] <= cap) {
            group_load[g] += items[idx];
            dfs(idx + 1, groups_used, group_load, items, cap);
            group_load[g] -= items[idx];
        }
    }
    group_load[groups_used] += items[idx];  // open a new group
    dfs(idx + 1, groups_used + 1, group_load, items, cap);
    group_load[groups_used] -= items[idx];
}
```

先把 `items` 由大到小排序（搜索順序優化）能更早撐爆容量、更快觸發剪枝；`groupsUsed >= best` 是最優性剪枝。

Dinic 主體：BFS 分層，DFS 沿層推流並更新反向邊：

```cpp
struct Dinic {
    struct Edge {
        int to, rev;
        long long cap;
    };
    vector<vector<Edge>> g;
    vector<int> level, it;
    // n: number of nodes or elements.
    Dinic(int n) : g(n), level(n), it(n) {}
    // u: current node or left endpoint.
    // v: neighbor node or right endpoint.
    // c: edge capacity.
    void addEdge(int u, int v, long long c) {
        g[u].push_back({v, (int)g[v].size(), c});
        g[v].push_back({u, (int)g[u].size() - 1, 0});  // reverse edge
    }
    // s: start/source value.
    // t: target/end value.
    bool bfs(int s, int t) {
        fill(level.begin(), level.end(), -1);
        queue<int> q;
        q.push(s);
        level[s] = 0;
        while (!q.empty()) {
            int u = q.front();
            q.pop();
            for (auto& e : g[u]) {
                if (e.cap > 0 && level[e.to] < 0) {
                    level[e.to] = level[u] + 1;
                    q.push(e.to);
                }
            }
        }
        return level[t] >= 0;
    }
    // u: current node or left endpoint.
    // t: target/end value.
    // f: amount of flow currently being pushed.
    long long dfs(int u, int t, long long f) {
        if (u == t) {
            return f;
        }
        for (int& i = it[u]; i < (int)g[u].size(); i++) {
            Edge& e = g[u][i];
            if (e.cap > 0 && level[e.to] == level[u] + 1) {
                long long d = dfs(e.to, t, min(f, e.cap));
                if (d > 0) {
                    e.cap -= d;
                    g[e.to][e.rev].cap += d;
                    return d;
                }
            }
        }
        return 0;
    }
    // s: source node in the flow network.
    // t: sink node in the flow network.
    long long maxflow(int s, int t) {
        long long flow = 0;
        while (bfs(s, t)) {
            fill(it.begin(), it.end(), 0);
            while (long long f = dfs(s, t, LLONG_MAX)) {
                flow += f;
            }
        }
        return flow;
    }
};
```

`for (int& i = it[u]; ...)` 用引用實現當前弧優化：已確定無用的邊不再重訪，是 Dinic 達標複雜度的核心。

反向邊讓算法能「反悔」先前推送的流，避免貪心走錯路卡死：

```cpp
// When we push d units along edge u->v:
//   e.cap     -= d;            // forward residual decreases
//   g[v][e.rev].cap += d;      // reverse residual increases, enabling cancellation
// A later augmenting path can traverse the reverse edge to redirect earlier flow.
```

沒有反向邊，一旦某條增廣選擇不是全域最優就無法修正，會得到偏小的流；反向邊把「重新分配」內建進殘量網路。

最大流後，殘量網路上從 s 可達的點集即 S 側，跨越到不可達點的滿流邊即割邊：

```cpp
// after din.maxflow(s, t), find the S-side of the min cut
// din: Dinic instance containing the flow network.
// s: source node in the flow network.
// n: number of nodes or elements.
vector<char> minCutSide(Dinic& din, int s, int n) {
    vector<char> side(n, 0);
    queue<int> q;
    q.push(s);
    side[s] = 1;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (auto& e : din.g[u]) {
            if (e.cap > 0 && !side[e.to]) {
                side[e.to] = 1;
                q.push(e.to);
            }
        }
    }
    return side;  // side[v]=1 -> v on S side
}
```

只沿「仍有殘量」的邊走；走不到的點屬 T 側。一條 `side[u]=1, side[v]=0` 的原始邊即割邊。

選一些點，選了某點就必須選其後繼，最大化點權和——轉成最小割：

```cpp
// Max-weight closure: source -> positive nodes (cap = weight).
// Negative nodes -> sink (cap = -weight), dependency u->v has cap kInf.
// Answer = (sum of positive weights) - maxflow(s, t).
// din: Dinic instance containing the flow network.
// s: source node in the flow network.
// t: sink node in the flow network.
// w: weights or node values.
// deps: dependency edges or constraints.
void buildClosure(Dinic& din, int s, int t, const vector<int>& w,
                  const vector<pair<int, int>>& deps) {
    long long kInf = 1e18;
    for (int i = 0; i < (int)w.size(); i++) {
        if (w[i] > 0) {
            din.addEdge(s, i, w[i]);
        }
        else if (w[i] < 0) {
            din.addEdge(i, t, -w[i]);
        }
    }
    for (auto& [u, v] : deps) {
        din.addEdge(u, v, kInf);  // must-take dependency
    }
}
```

依賴邊容量設 `INF` 表示「絕不切斷」，強制閉合性；答案 = 正權總和 − 最小割（= 最大流）。

對每個左點 DFS 找增廣路，`matchR[r]` 記右點當前匹配的左點：

```cpp
vector<vector<int>> adj;  // adj[u] = right nodes adjacent to left u
vector<int> match_r;      // match_r[r] = matched left node, or -1
vector<char> vis;
// u: current node or left endpoint.
bool augment(int u) {
    for (int v : adj[u]) {
        if (vis[v]) {
            continue;
        }
        vis[v] = 1;
        if (match_r[v] == -1 || augment(match_r[v])) {  // v free or its match can move
            match_r[v] = u;
            return true;
        }
    }
    return false;
}
// n_left: number of nodes on the left side of the bipartite graph.
// n_right: number of nodes on the right side of the bipartite graph.
int hungarian(int n_left, int n_right) {
    match_r.assign(n_right, -1);
    int res = 0;
    for (int u = 0; u < n_left; u++) {
        vis.assign(n_right, 0);
        if (augment(u)) {
            res++;  // found an augmenting path for u
        }
    }
    return res;
}
```

`augment(matchR[v])` 嘗試把佔用 v 的左點「讓位」到別處，這就是增廣路翻轉；每成功一次匹配數 +1。

最大匹配連結多個經典量，建模時直接套用：

```cpp
// Bipartite identities (no code needed, just the relations):
// max matching                = M
// minimum vertex cover        = M            (Konig's theorem)
// maximum independent set     = V - M
// DAG minimum path cover      = V - (max matching after node-splitting)
```

很多「最少選幾個覆蓋所有邊」「最多選互不衝突的點」「用最少鏈覆蓋 DAG」的題，本質都是先求最大匹配再套定理。

固定使用左閉右開 `[lo, hi)`，迴圈條件 `lo < hi`，每次取 `mid = lo + (hi - lo) / 2`，依 `check` 收縮其中一側。

```cpp
// 第一個使 check 為 true 的位置（check 單調：false...false,true...true）
int lower(int lo, int hi, auto check) {
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        if (check(mid)) hi = mid;   // mid 可行，答案在左半（含 mid）
        else lo = mid + 1;          // mid 不可行，答案在右半
    }
    return lo;                       // = hi，第一個可行位置
}
```

要找「最後一個可行位置」時，最穩的做法是找「第一個不可行位置」再 `-1`，避免另寫一套 `mid` 偏移邏輯。`mid` 用 `lo + (hi - lo) / 2` 而非 `(lo + hi) / 2`，可避免大數相加溢位。

當答案本身具單調性（例如「最少需要多少時間／容量」），把答案當搜尋變數，用一個 `feasible(x)` 判定「給定 x 能否完成」。

```cpp
long long lo = 1, hi = MAXV;
while (lo < hi) {
    long long mid = lo + (hi - lo) / 2;
    if (feasible(mid)) hi = mid;    // x 越大越容易可行 → 收左界
    else lo = mid + 1;
}
// lo 即最小可行答案
```

關鍵是證明單調性：若 x 可行，則所有 ≥ x（或 ≤ x）也可行。確定方向後，`feasible` 通常是一次 O(n) 的貪心模擬。這把「最小化最大值／最大化最小值」這類最優化問題轉成判定問題。

以「最小路徑和」為例，`dp[j]` 表示走到當前行第 j 格的最小成本。

```cpp
vector<int> dp(m, INT_MAX);
for (int i = 0; i < n; i++)
    for (int j = 0; j < m; j++) {
        if (i == 0 && j == 0) dp[j] = grid[0][0];
        else {
            int best = INT_MAX;
            if (i) best = min(best, dp[j]);       // 上方（上一行同列）
            if (j) best = min(best, dp[j-1]);     // 左方（本行前一列）
            dp[j] = best + grid[i][j];
        }
    }
// dp[m-1] 即答案
```

用一維 `dp[j]`：更新時 `dp[j]`（更新前）就是上方值、`dp[j-1]`（已更新）就是左方值，天然完成滾動。路徑計數把 `min(+grid)` 換成「累加方案數」即可。

兩個字串的對齊問題狀態是 `dp[i][j]` = `a[0..i)` 轉成 `b[0..j)` 的最小操作數。

```cpp
vector<vector<int>> dp(n+1, vector<int>(m+1));
for (int i = 0; i <= n; i++) dp[i][0] = i;
for (int j = 0; j <= m; j++) dp[0][j] = j;
for (int i = 1; i <= n; i++)
    for (int j = 1; j <= m; j++) {
        if (a[i-1] == b[j-1]) dp[i][j] = dp[i-1][j-1];
        else dp[i][j] = 1 + min({dp[i-1][j], dp[i][j-1], dp[i-1][j-1]});
    }
```

三個來源分別對應刪除、插入、替換。LCS、最長公共子陣列都是這個二維表的變體，差別只在轉移與初始化。

以 1×2 骨牌鋪滿網格計數為例，逐格決定「當前格如何被覆蓋」，更新輪廓線狀態。

```cpp
// dp[mask] = 處理到 (i,j)、輪廓線狀態為 mask 的方案數
vector<long long> dp(1<<m, 0), ndp;
dp[0] = 1;
for (int i = 0; i < n; i++)
    for (int j = 0; j < m; j++) {
        ndp.assign(1<<m, 0);
        for (int mask = 0; mask < (1<<m); mask++) if (dp[mask]) {
            int bit = 1 << j;
            if (mask & bit) ndp[mask ^ bit] += dp[mask];      // 此格已被上方覆蓋
            else {
                ndp[mask | bit] += dp[mask];                   // 用豎磚（向下伸出插頭）
                if (j+1<m && !(mask&(bit<<1)))                  // 用橫磚
                    ndp[mask | bit | (bit<<1)] += dp[mask];
            }
        }
        swap(dp, ndp);
    }
```

每處理完一格就把狀態推進到下一格；行末自然進位到下一行。輪廓線位元的「有/無覆蓋」對應骨牌往下或往右的選擇。

若 `dp[i] = sum(dp[j])`，其中 j 落在某段區間，維護 dp 的前綴和即可 O(1) 取區間和。

```cpp
// dp[i] = 從 i-k..i-1 任一步跳來的方案數
vector<long long> dp(n+1), pre(n+2);
dp[0] = 1; pre[1] = 1;
for (int i = 1; i <= n; i++) {
    int lo = max(0, i - k);
    dp[i] = (pre[i] - pre[lo] + MOD) % MOD; // 區間和 = 前綴差
    pre[i+1] = (pre[i] + dp[i]) % MOD;
}
```

關鍵是邊算 dp 邊維護其前綴和 `pre`，避免「先算完再求和」造成依賴循環。二維/帶權的情形同理擴展。

形如 `f[n] = a·f[n-1] + b·f[n-2]` 的遞推，可寫成狀態向量乘轉移矩陣，n 很大時用快速冪。

```cpp
using Mat = array<array<long long,2>,2>;
Mat mul(const Mat&A,const Mat&B){
    Mat C{};
    for(int i=0;i<2;i++)for(int k=0;k<2;k++)if(A[i][k])
        for(int j=0;j<2;j++) C[i][j]=(C[i][j]+A[i][k]*B[k][j])%MOD;
    return C;
}
Mat power(Mat a,long long n){ Mat r={{{1,0},{0,1}}}; for(;n;n>>=1,a=mul(a,a)) if(n&1) r=mul(r,a); return r; }
```

把遞推的係數填進 2×2（或 k×k）矩陣，`power(T, n)` 後乘上初始向量即得 `f[n]`，複雜度 O(k^3 log n)。

原問題：在「恰好選 k 個」下最大化 `f`。定義 `g(λ)` = 去掉個數限制、但每選一個扣 `λ` 後的最優值，並記錄此時的選擇個數 `cnt(λ)`。

```cpp
// 對 λ 二分，找出使 cnt(λ) == k 的 λ
long long lo = 0, hi = MAXLAMBDA, bestLambda = 0;
while (lo <= hi) {
    long long mid = (lo + hi) / 2;
    auto [val, cnt] = solveWithPenalty(mid); // 無約束 DP/貪心，回傳最優值與選擇數
    if (cnt >= k) { bestLambda = mid; lo = mid + 1; } // 選太多 → 加大懲罰
    else hi = mid - 1;
}
auto [val, cnt] = solveWithPenalty(bestLambda);
long long answer = val + bestLambda * k; // 把扣掉的 k·λ 補回來
```

最後別忘了把懲罰加回：因為子問題每選一個扣了 λ，恰好 k 個就共扣了 `k·λ`，要 `+ k·λ` 還原成原目標。

`dp[u][0/1/2]` 對應上面三種狀態的最小選點數。

```cpp
// 0: u 被選; 1: u 未選但被子覆蓋; 2: u 未選且未被覆蓋(等父覆蓋)
long long dp[N][3];
void dfs(int u,int p){
    dp[u][0]=1; dp[u][1]=0; dp[u][2]=0;
    bool hasChild=false; long long extra=LLONG_MAX; bool covered=false;
    for(int v: g[u]) if(v!=p){
        hasChild=true; dfs(v,u);
        dp[u][0]+=min({dp[v][0],dp[v][1],dp[v][2]}); // u 選了，兒子隨意
        dp[u][2]+=dp[v][1];                          // u 未被覆蓋 → 兒子須自覆蓋且不靠 u
        // 狀態1：兒子們取 min(0,1)，且至少一個取狀態0來覆蓋 u
        dp[u][1]+=min(dp[v][0],dp[v][1]);
        if(dp[v][0]<=dp[v][1]) covered=true;
        else extra=min(extra, dp[v][0]-dp[v][1]);
    }
    if(!covered) dp[u][1]+= (hasChild? extra : 0);  // 強制一個兒子被選來覆蓋 u
    if(!hasChild) dp[u][1]=LLONG_MAX/2;              // 葉子無法靠兒子覆蓋
}
// 答案 = min(dp[root][0], dp[root][1])
```

狀態 1 的細節在於「必須至少有一個兒子被選（狀態 0）來覆蓋 u」，若所有兒子都取狀態 1，要補上最小的額外代價 `extra`。

左括號壓入，右括號嘗試與 stack top 配對；最後 stack 空才合法。

```cpp
bool isValid(const string& s) {
    stack<char> st;
    unordered_map<char,char> pair = {{")","("[0]},{"]","["[0]},{"}","{"[0]}};
    for (char c : s) {
        if (c=="("[0] || c=="["[0] || c=="{"[0]) st.push(c);
        else {
            if (st.empty() || st.top()!=pair[c]) return false;
            st.pop();
        }
    }
    return st.empty();
}
```

變體「最少增刪使括號合法」只需在掃描中統計無法匹配的左右括號數量，stack 深的峰值與殘留即答案。

基本計算機用「數字 stack + 運算子 stack」或在掃描時依運算子優先級即時結算；後綴（逆波蘭）表達式則只需一個數字 stack。

```cpp
int evalRPN(vector<string>& tokens) {
    stack<long long> st;
    for (auto& t : tokens) {
        if (t=="+"||t=="-"||t=="*"||t=="/") {
            long long b=st.top();st.pop();
            long long a=st.top();st.pop();
            st.push(t=="+"?a+b:t=="-"?a-b:t=="*"?a*b:a/b);
        } else st.push(stoll(t));
    }
    return st.top();
}
```

鄰項消除（如消消樂、星號移除相鄰字元）同理：能與 stack top 抵銷就 `pop`，否則 `push`，stack 內元素即最終結果。

用固定陣列與 `head/tail` 指標取模循環，避免 dequeue 後搬移元素。

```cpp
struct CircularQueue {
    vector<int> a; int head=0, cnt=0, cap;
    CircularQueue(int k): a(k), cap(k) {}
    bool enqueue(int x){ if(cnt==cap) return false; a[(head+cnt)%cap]=x; cnt++; return true; }
    bool dequeue(){ if(!cnt) return false; head=(head+1)%cap; cnt--; return true; }
    int front(){ return cnt? a[head] : -1; }
};
```

用「容量 + 計數」判斷空滿，比單純比較頭尾指標更不易出錯。

`in` stack 負責 enqueue，`out` stack 負責 dequeue；`out` 空時把 `in` 整批倒過去。

```cpp
stack<int> in, out;
void push(int x){ in.push(x); }
int pop(){ peek(); int v=out.top(); out.pop(); return v; }
int peek(){ if(out.empty()) while(!in.empty()){ out.push(in.top()); in.pop(); } return out.top(); }
```

每個元素至多被搬移一次，因此每次操作攤還 O(1)。這也是「用 stack 維護 queue 最值」等進階題的雛形。

任務有截止時間 `d` 與耗時 `t`，按 `d` 排序後逐一加入；若當前總耗時超過 `d`，就反悔掉「耗時最大」的已選任務。

```cpp
sort(jobs.begin(), jobs.end()); // 按 deadline 升序
priority_queue<int> pq;          // max-heap，存已選任務耗時
long long cur = 0;
for (auto [d, t] : jobs) {
    cur += t; pq.push(t);
    if (cur > d) {               // 來不及 → 反悔最耗時的一個
        cur -= pq.top(); pq.pop();
    }
}
// pq.size() 即最多可完成任務數
```

關鍵：按截止時間排序保證「考慮到某任務時，之前的都可用」，而反悔最大耗時者一定不會讓可行解變差。

另一類是「最多選 k 個、可替換」：維護已選的 min-heap，新元素若大於堆頂則替換。

```cpp
priority_queue<int, vector<int>, greater<int>> pq; // min-heap
for (int x : vals) {
    if ((int)pq.size() < k) pq.push(x);
    else if (x > pq.top()) { pq.pop(); pq.push(x); }
}
```

更複雜的版本（如「IPO」「最大化路徑收益」）會把「解鎖條件」與「收益」分離：先用一個堆按條件釋放可選項，再用另一個堆挑最大收益，必要時反悔。

插入時逐位建點；查詢時每位貪心走相反方向。

```cpp
int ch[N*31][2], idx=0;
void insert(int x){
    int p=0;
    for(int i=30;i>=0;i--){ int b=x>>i&1; if(!ch[p][b]) ch[p][b]=++idx; p=ch[p][b]; }
}
int queryMax(int x){
    int p=0, res=0;
    for(int i=30;i>=0;i--){ int b=x>>i&1;
        if(ch[p][b^1]){ res|=1<<i; p=ch[p][b^1]; } // 走相反位 → 該位異或為 1
        else p=ch[p][b];
    }
    return res;
}
```

要支援刪除或「下標 ≤ r」的限制，給節點加 `cnt`：插入 +1、刪除 -1，走的時候只走 `cnt>0` 的分支。

節點用左右孩子下標（而非 2x/2x+1）動態分配，未訪問的子樹不佔空間。

```cpp
struct Node { int ls=0, rs=0; long long sum=0; };
vector<Node> t(1); int root=0;
void update(int& p, long long lo, long long hi, long long pos, long long v){
    if(!p){ p=t.size(); t.push_back({}); }
    t[p].sum += v;
    if(lo==hi) return;
    long long mid=(lo+hi)/2;
    if(pos<=mid) update(t[p].ls, lo, mid, pos, v);
    else update(t[p].rs, mid+1, hi, pos, v);
}
```

以引用參數 `int& p` 在遞迴中惰性建點。主席樹在此基礎上，update 時複製路徑上的節點並讓新版本根指向新鏈。

`f[i][j]` 表示從 i 起、長度 2^j 的區間最值；查詢時用兩個可重疊的 2^k 區間覆蓋。

```cpp
int f[N][LOG];
void build(vector<int>& a){
    int n=a.size();
    for(int i=0;i<n;i++) f[i][0]=a[i];
    for(int j=1;(1<<j)<=n;j++)
        for(int i=0;i+(1<<j)<=n;i++)
            f[i][j]=max(f[i][j-1], f[i+(1<<(j-1))][j-1]);
}
int query(int l,int r){ int k=__lg(r-l+1); return max(f[l][k], f[r-(1<<k)+1][k]); }
```

因為 max/min/gcd 是冪等的（重疊不影響結果），兩個 2^k 區間可以重疊覆蓋 `[l,r]`，所以查詢 O(1)。和需要區間更新的問題無緣——它只服務靜態查詢。

把查詢按「左端點所在塊」為第一關鍵字、右端點為第二關鍵字排序，使指標移動總量最小。

```cpp
int B; // 塊大小 ≈ sqrt(n)
struct Q { int l, r, id; };
sort(qs.begin(), qs.end(), [&](const Q&a, const Q&b){
    if (a.l/B != b.l/B) return a.l/B < b.l/B;
    return (a.l/B & 1) ? a.r > b.r : a.r < b.r; // 奇偶排序優化
});
int l=0, r=-1;
for (auto& q : qs) {
    while (r < q.r) add(++r);
    while (l > q.l) add(--l);
    while (r > q.r) del(r--);
    while (l < q.l) del(l++);
    ans[q.id] = curAns;
}
```

`add/del` 必須能 O(1) 或 O(log) 增量維護答案（例如用計數陣列維護「不同數個數」）。奇偶排序讓右指標來回掃描更省。

把陣列分塊，維護每塊的聚合值（和、最值、懶標記）。查詢/修改時，整塊走預處理、邊角塊暴力。

```cpp
// 區間加、區間求和的分塊：blockAdd 為整塊懶加
void rangeAdd(int L, int R, long long v) {
    for (int i = L; i <= R; ) {
        if (i % B == 0 && i + B - 1 <= R) {      // 整塊
            blockAdd[i/B] += v; i += B;
        } else { a[i] += v; sum[i/B] += v; i++; } // 邊角暴力
    }
}
```

分塊的好處是通用、好寫、易擴展到線段樹難處理的查詢；代價是 O(√n) 比 O(log n) 慢，適合 n、q 不過大或查詢特殊時。平衡樹（如 Treap）則用於需要動態維護有序序列且支援分裂合併的場景。

用 stack 模擬：能走就往前走並刪邊，走不動就把節點加入答案，最後反轉。

```cpp
vector<int> g[N]; int idx[N];   // idx：每點下一條未用邊的指標
vector<int> path;
void hierholzer(int s){
    stack<int> st; st.push(s);
    while(!st.empty()){
        int u=st.top();
        if(idx[u]<(int)g[u].size()){
            int v=g[u][idx[u]++];   // 取下一條未用邊
            st.push(v);
        } else { path.push_back(u); st.pop(); }
    }
    reverse(path.begin(), path.end());
}
```

用 `idx` 指標而非每次刪除邊，確保每條邊只處理一次，達到線性。有向圖直接用此版；無向圖需標記邊是否用過（成對的反向邊）。

單次 DFS 維護 dfn/low 與 stack，根節點 `dfn==low` 時收一個分量。

```cpp
int dfn[N], low[N], timer=0, scc[N], sccCnt=0;
bool inStk[N]; stack<int> st;
void tarjan(int u){
    dfn[u]=low[u]=++timer; st.push(u); inStk[u]=true;
    for(int v: g[u]){
        if(!dfn[v]){ tarjan(v); low[u]=min(low[u],low[v]); }
        else if(inStk[v]) low[u]=min(low[u],dfn[v]);
    }
    if(dfn[u]==low[u]){
        sccCnt++;
        while(true){ int x=st.top(); st.pop(); inStk[x]=false; scc[x]=sccCnt; if(x==u) break; }
    }
}
```

縮點後，把跨 SCC 的邊建成新圖（去重），即得 DAG，可在其上做拓撲 DP（如最長路、計數）。

試除到 √n，剩餘 >1 的部分本身是質因數。

```cpp
vector<pair<long long,int>> factorize(long long n){
    vector<pair<long long,int>> f;
    for(long long p=2; p*p<=n; p++) if(n%p==0){
        int c=0; while(n%p==0){ n/=p; c++; }
        f.push_back({p,c});
    }
    if(n>1) f.push_back({n,1});
    return f;
}
// 約數個數 = ∏(c_i+1)；約數和 = ∏(1+p+...+p^c_i)
```

枚舉所有因子時，迴圈到 √n，對每個整除的 i 同時收集 `i` 與 `n/i`（注意完全平方時去重）。

預處理 `spf[x]` = x 的最小質因子，之後反覆除以 spf 即可快速分解。

```cpp
int spf[N];
void sieve(){
    for(int i=2;i<N;i++) if(!spf[i])
        for(int j=i;j<N;j+=i) if(!spf[j]) spf[j]=i;
}
vector<int> fast(int x){ vector<int> r; while(x>1){ r.push_back(spf[x]); x/=spf[x]; } return r; }
```

當題目要對「大量數」分解時，這個 O(N) 預處理 + O(log n) 查詢遠勝逐個試除。

FWT 對陣列做「類傅立葉」變換，點乘後逆變換得到位運算卷積。

```cpp
void fwtXor(vector<long long>& a, bool inv){
    int n=a.size();
    for(int len=1; len<n; len<<=1)
        for(int i=0;i<n;i+=len<<1)
            for(int j=i;j<i+len;j++){
                long long x=a[j], y=a[j+len];
                a[j]=x+y; a[j+len]=x-y;          // 蝴蝶變換
            }
    if(inv) for(auto& v:a) v/=n;                  // 逆變換除以 n
}
// 異或卷積：fwtXor(A); fwtXor(B); 點乘; fwtXor(C, true)
```

AND/OR 卷積只是把蝴蝶變換換成對應的加減形式。這類技巧常用於「異或/子集和的方案計數」。

用 `cur` 走訪，注意不要動到 `head`，以免遺失串列起點。

```cpp
int length(ListNode* head){
    int n=0;
    for(ListNode* cur=head; cur; cur=cur->next) n++;
    return n;
}
```

求「倒數第 k 個」可先算長度再走 `len-k` 步，或用快慢指標一趟完成（見前後指標一節）。

以刪除所有值為 val 的節點為例。

```cpp
ListNode* removeElements(ListNode* head, int val){
    ListNode dummy(0, head), *prev=&dummy;
    while(prev->next){
        if(prev->next->val==val) prev->next=prev->next->next; // 繞過
        else prev=prev->next;                                 // 否則前進
    }
    return dummy.next;
}
```

刪除時不要移動 `prev`，這樣才能處理連續多個待刪節點。刪重複節點（保留/不保留）只是換掉判斷條件。

找到第一個大於等於新值的位置之前驅，插入。

```cpp
ListNode* insertSorted(ListNode* head, int val){
    ListNode dummy(0, head), *prev=&dummy;
    while(prev->next && prev->next->val < val) prev=prev->next;
    ListNode* node=new ListNode(val);
    node->next=prev->next;   // 先接後繼
    prev->next=node;         // 再接前驅
    return dummy.next;
}
```

顛倒這兩行會先讓 `prev->next` 指向新節點，導致原本的後繼遺失。

整體反轉回傳新頭 `prev`；區間反轉先用 dummy 框住區段。

```cpp
ListNode* reverse(ListNode* head){
    ListNode *prev=nullptr, *cur=head;
    while(cur){ ListNode* nxt=cur->next; cur->next=prev; prev=cur; cur=nxt; }
    return prev;
}
```

區間反轉：定位 `left` 前驅，反轉 `[left,right]` 後，把前驅接到新頭、原 `left` 節點接到 `right` 後繼。每 k 個一組則先檢查剩餘是否足 k 再反轉。

fast 先行 k 步，配合 dummy 讓 slow 停在待刪節點的前驅。

```cpp
ListNode* removeNthFromEnd(ListNode* head, int k){
    ListNode dummy(0, head), *fast=&dummy, *slow=&dummy;
    while(k--) fast=fast->next;        // fast 先走 k 步
    while(fast->next){ fast=fast->next; slow=slow->next; }
    slow->next=slow->next->next;       // slow 在待刪前驅
    return dummy.next;
}
```

用 dummy 當起點可確保「刪除頭節點」也落在統一邏輯內。

相遇後重置一指標到頭，同速走再相遇即入口。

```cpp
ListNode* detectCycle(ListNode* head){
    ListNode *slow=head, *fast=head;
    while(fast && fast->next){
        slow=slow->next; fast=fast->next->next;
        if(slow==fast){
            ListNode* p=head;
            while(p!=slow){ p=p->next; slow=slow->next; }
            return p;
        }
    }
    return nullptr;
}
```

入口結論來自距離等式：頭到入口的距離等於相遇點繞行回入口的距離。

啞節點接尾，較小者接入後該鏈前進。

```cpp
ListNode* merge(ListNode* a, ListNode* b){
    ListNode dummy(0), *tail=&dummy;
    while(a && b){
        if(a->val<=b->val){ tail->next=a; a=a->next; }
        else { tail->next=b; b=b->next; }
        tail=tail->next;
    }
    tail->next = a ? a : b;   // 接上剩餘
    return dummy.next;
}
```

k 個合併用 priority queue 存各鏈當前頭，每次彈最小、推進該鏈；或分治兩兩合併達 O(N log k)。

快慢指標找中點並斷開，遞迴排序兩半後合併。

```cpp
ListNode* sortList(ListNode* head){
    if(!head || !head->next) return head;
    ListNode *slow=head, *fast=head->next;
    while(fast && fast->next){ slow=slow->next; fast=fast->next->next; }
    ListNode* mid=slow->next; slow->next=nullptr;  // 斷成兩半
    return merge(sortList(head), sortList(mid));    // merge 見「合併」一節
}
```

`fast=head->next` 的起點讓中點切分對偶數長度更均衡，避免無窮遞迴。

三步組合：找中點、反轉後半、交錯合併。

```cpp
void reorderList(ListNode* head){
    if(!head || !head->next) return;
    ListNode *slow=head, *fast=head;
    while(fast->next && fast->next->next){ slow=slow->next; fast=fast->next->next; }
    ListNode* second=reverse(slow->next); slow->next=nullptr; // 反轉後半
    ListNode* first=head;
    while(second){ // 交錯合併
        ListNode* f=first->next; ListNode* s=second->next;
        first->next=second; second->next=f;
        first=f; second=s;
    }
}
```

兩數相加則邊走兩鏈邊處理進位；複製帶隨機指標可用「節點後插複製節點」或雜湊表映射。

三序只是 visit 位置不同；迭代中序用 stack。

```cpp
vector<int> inorder(TreeNode* root){
    vector<int> res; stack<TreeNode*> st; TreeNode* cur=root;
    while(cur || !st.empty()){
        while(cur){ st.push(cur); cur=cur->left; }   // 一路向左
        cur=st.top(); st.pop();
        res.push_back(cur->val);                      // 中序 visit
        cur=cur->right;
    }
    return res;
}
```

前序在 push 時 visit、後序可用「反轉的前序（根右左）」再反轉得到。

以「路徑總和是否等於 target」為例，把剩餘目標往下帶。

```cpp
bool hasPathSum(TreeNode* node, int target){
    if(!node) return false;
    target -= node->val;
    if(!node->left && !node->right) return target==0; // 葉子判斷
    return hasPathSum(node->left, target) || hasPathSum(node->right, target);
}
```

求「好節點數」「路徑上最大值」等，都是把祖先資訊（最大值、計數）當參數向下傳，在葉子或每個節點更新答案。

回傳以節點為端點的最大下伸量，全域更新跨節點路徑。

```cpp
int best=0;
int depth(TreeNode* node){
    if(!node) return 0;
    int l=depth(node->left), r=depth(node->right);
    best=max(best, l+r);          // 跨過 node 的路徑（邊數）
    return max(l, r) + 1;         // 只能單邊往上接
}
// 直徑 = best（呼叫 depth(root) 後）
```

最大路徑和把高度換成「最大鏈和、負則取 0」，平衡判定則回傳高度同時用一個標記或 -1 表示已失衡。

用 (min,max) 範圍遞迴驗證，或用中序遞增性。

```cpp
bool valid(TreeNode* n, long long lo, long long hi){
    if(!n) return true;
    if(n->val<=lo || n->val>=hi) return false;
    return valid(n->left, lo, n->val) && valid(n->right, n->val, hi);
}
```

第 k 小用中序遍歷計數，數到第 k 個即答案；找最接近值則一路比較往左/右走並更新候選。

前序首元素是根，在中序中找到它切出左右子樹大小。

```cpp
unordered_map<int,int> pos; // 中序值→下標
int pre=0;
TreeNode* build(vector<int>& preorder, int inL, int inR){
    if(inL>inR) return nullptr;
    int rootVal=preorder[pre++];
    TreeNode* root=new TreeNode(rootVal);
    int k=pos[rootVal];
    root->left = build(preorder, inL, k-1);   // 先建左，與前序順序一致
    root->right= build(preorder, k+1, inR);
    return root;
}
```

必須「先建左子樹」才能與前序的消費順序一致。由排序陣列建平衡 BST 則每次取中點當根，遞迴左右半。

每輪固定本層大小，逐層收集。

```cpp
vector<vector<int>> levelOrder(TreeNode* root){
    vector<vector<int>> res; if(!root) return res;
    queue<TreeNode*> q; q.push(root);
    while(!q.empty()){
        int sz=q.size(); vector<int> level;
        while(sz--){
            TreeNode* x=q.front(); q.pop();
            level.push_back(x->val);
            if(x->left) q.push(x->left);
            if(x->right) q.push(x->right);
        }
        res.push_back(level);
    }
    return res;
}
```

右視圖取每層最後一個；之字形按層號決定正序/反序插入；最短到葉用層數計數。

遞迴對每個孩子取最優再合併。

```cpp
int maxDepth(Node* root){
    if(!root) return 0;
    int best=0;
    for(Node* c: root->children) best=max(best, maxDepth(c));
    return best+1;
}
```

前序/後序只是把 visit 放在迴圈孩子之前/之後；層序 BFS 則在 dequeue 時把所有孩子 enqueue。

後序遞迴：若左右子樹各找到一個目標，當前節點即 LCA。

```cpp
TreeNode* lca(TreeNode* root, TreeNode* p, TreeNode* q){
    if(!root || root==p || root==q) return root;
    TreeNode* l=lca(root->left, p, q);
    TreeNode* r=lca(root->right, p, q);
    if(l && r) return root;     // 兩側各一 → 當前是 LCA
    return l ? l : r;           // 否則回傳找到的那側
}
```

序列化用前序帶 null 標記，反序列化按同序消費；判斷相同樹/對稱樹則同步遞迴比較兩棵（子）樹。

一次 DFS 給每個節點進入/離開時間，子樹恰為 `[in[u], out[u]]`。

```cpp
int in[N], out[N], timer=0;
void dfs(int u,int p){
    in[u]=++timer;
    for(int v: g[u]) if(v!=p) dfs(v,u);
    out[u]=timer;
}
// 「u 子樹加值」「查 u 子樹和」→ 對區間 [in[u], out[u]] 用 BIT/線段樹
```

這把樹上子樹操作完全轉成序列上的區間操作，是處理「子樹修改/查詢」的標準前置步驟。

每層找重心，統計「經過重心」的路徑，扣除同子樹內的重複，再對各子樹遞迴。

```cpp
// 骨架：findCentroid → calc(經過 root 的路徑) → 對每個子樹 calc 去重 → 遞迴
void solve(int u){
    int c = centroid(u);
    countPathsThrough(c);            // 統計過 c 的合法路徑
    used[c] = true;
    for(int v: g[c]) if(!used[v]) solve(v);
}
```

選重心保證每次子問題規模減半，故遞迴深度 O(log n)，每層 O(n)，總 O(n log n)。常用於「距離為 k 的點對數」「路徑和滿足條件」等。

列舉當前段的結尾，合法（回文）才往下分。

```cpp
vector<vector<string>> res; vector<string> path;
void dfs(const string& s, int start){
    if(start==(int)s.size()){ res.push_back(path); return; }
    for(int end=start; end<(int)s.size(); end++){
        if(isPalin(s,start,end)){           // 段合法才遞迴
            path.push_back(s.substr(start,end-start+1));
            dfs(s, end+1);
            path.pop_back();                 // 回溯
        }
    }
}
```

可先用 `pal[i][j]` 預處理回文判斷把段檢查降到 O(1)。復原 IP、分割成 k 段等變體只是換掉合法性條件與終止判斷。

左右各枚舉一半的子集和，右半排序後二分互補值。

```cpp
vector<long long> gen(const vector<int>& v){      // 枚舉所有子集和
    vector<long long> s;
    int n=v.size();
    for(int m=0;m<(1<<n);m++){
        long long sum=0;
        for(int i=0;i<n;i++) if(m>>i&1) sum+=v[i];
        s.push_back(sum);
    }
    return s;
}
long long closest(vector<int>& a, long long target){
    int h=a.size()/2;
    auto L=gen({a.begin(),a.begin()+h});
    auto R=gen({a.begin()+h,a.end()});
    sort(R.begin(),R.end());
    long long best=LLONG_MAX;
    for(long long x:L){
        long long need=target-x;
        auto it=lower_bound(R.begin(),R.end(),need);
        if(it!=R.end()) best=min(best, llabs(x+*it-target));
        if(it!=R.begin()) best=min(best, llabs(x+*prev(it)-target));
    }
    return best;
}
```

計數型把「二分找一個」換成「二分找區間長度」；恰好等於目標則用雜湊表計次。

插入時從高位往低位嘗試消去；查詢最大值時貪心地讓答案盡量大。

```cpp
long long basis[63];
bool insert(long long x){
    for(int i=62;i>=0;i--) if(x>>i&1){
        if(!basis[i]){ basis[i]=x; return true; } // 找到空位，成為新基底
        x^=basis[i];                               // 否則消去這一位
    }
    return false; // x 已能被現有基底表示
}
long long maxXor(){
    long long res=0;
    for(int i=62;i>=0;i--) res=max(res,res^basis[i]);
    return res;
}
```

插入回傳 false 代表 x 落在已張成空間內（線性相關），這同時用於「判斷能否異或出 x」。

統計次數 → 前綴和得到每個值的結束位置 → 從後往前填，保證穩定。

```cpp
vector<int> countingSort(const vector<int>& a, int k) { // 值域 [0, k]
    vector<int> cnt(k + 1, 0), out(a.size());
    for (int x : a) cnt[x]++;
    for (int v = 1; v <= k; v++) cnt[v] += cnt[v - 1]; // 前綴和
    for (int i = (int)a.size() - 1; i >= 0; i--)        // 從後往前 → 穩定
        out[--cnt[a[i]]] = a[i];
    return out;
}
```

從後往前填入是穩定性的關鍵：相同值的元素保持原相對順序，這在基數排序中是必要條件。

把每個數視為 base 進位制，從最低位開始，對每一位做一次穩定計數排序。

```cpp
void radixSort(vector<unsigned>& a) {
    const int BASE = 256;
    vector<unsigned> buf(a.size());
    for (int shift = 0; shift < 32; shift += 8) {
        int cnt[BASE + 1] = {0};
        for (unsigned x : a) cnt[(x >> shift) & 0xFF]++;
        for (int i = 1; i <= BASE; i++) cnt[i] += cnt[i - 1];
        for (int i = (int)a.size() - 1; i >= 0; i--)
            buf[--cnt[(a[i] >> shift) & 0xFF]] = a[i];
        swap(a, buf);
    }
}
```

每一輪必須用「穩定」的計數排序，否則高位排好的順序會被低位打亂。位數 d 與基數 b 的選擇影響 `O(d·(n + b))` 的常數。
